-- Poems batch 417
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-922','恋绣衾','陆游','宋','宋词','song-ci','恋绣衾','[]','无方能驻脸上红。',68,'宋词/ci.song.9000.json','["无方能驻脸上红。", "笑浮生、扰扰梦中。", "平地是、冲霄路，又何劳、千日用功。", "飘然再过莲峰下，乱云深、吹下暮锺。", "访旧隐、依然在，但鹤巢、时有堕松。"]'),
('song-ci-923','风入松','陆游','宋','宋词','song-ci','风入松','[]','十年裘马锦江滨。',88,'宋词/ci.song.9000.json','["十年裘马锦江滨。", "酒隐红尘。", "万金选胜莺花海，倚疏狂、驱使青春。", "吹笛鱼龙尽出，题诗风月俱新。", "自怜华发满纱巾。", "犹是官身。", "凤楼常记当年语，问浮名、何似身亲。", "欲寄吴笺说与，这回真个闲人。"]'),
('song-ci-924','真珠帘','陆游','宋','宋词','song-ci','真珠帘','[]','灯前月下嬉游处。',123,'宋词/ci.song.9000.json','["灯前月下嬉游处。", "向笙歌、锦绣丛中相遇。", "彼此知名，才见便论心素。", "浅黛娇蝉风调别，最动人、时时偷顾。", "归去。", "想闲窗深院，调弦促柱。", "乐府初翻新谱。", "漫裁红点翠，闲题金缕。", "燕子入帘时，又一番春暮。", "侧帽燕脂坡下过，料也记、前年崔护。", "休诉。", "待从今须与，好花为主。"]'),
('song-ci-925','风流子','陆游','宋','宋词','song-ci','风流子','[]','佳人多命薄，初心慕、德耀嫁梁鸿。',135,'宋词/ci.song.9000.json','["佳人多命薄，初心慕、德耀嫁梁鸿。", "记绿窗睡起，静吟闲咏，句翻离合，格变玲珑。", "更乘兴，素纨留戏墨，纤玉抚孤桐。", "蟾滴夜寒，水浮微冻，凤笺春丽，花砑轻红。", "人生谁能料，堪悲处、身落柳陌花丛。", "空羡画堂鹦鹉，深闭金笼。", "向宝镜鸾钗，临妆常晚，绣茵牙版，催舞还慵。", "肠断市桥月笛，灯院霜锺。"]'),
('song-ci-926','双头莲','陆游','宋','宋词','song-ci','双头莲','[]','风卷征尘，堪叹处、青骢正摇金辔。',122,'宋词/ci.song.9000.json','["风卷征尘，堪叹处、青骢正摇金辔。", "客襟贮泪。", "漫万点如血，凭谁持寄。", "伫想艳态幽情，压江南佳丽。", "春正媚。", "怎忍长亭，匆匆顿分连理。", "目断淡日平芜，望烟浓树远，微茫如荠。", "悲欢梦里。", "奈倦客、又是关河千里。", "最苦唱彻骊歌，重迟留无计。", "何限事。", "待与丁宁，行时已醉。"]'),
('song-ci-927','鹧鸪天','陆游','宋','宋词','song-ci','鹧鸪天','[]','杖屦寻春苦未迟。',64,'宋词/ci.song.9000.json','["杖屦寻春苦未迟。", "洛城樱笋正当时。", "三千界外归初到，五百年前事总知。", "吹玉笛，渡清伊。", "相逢休问姓名谁。", "小车处士深衣叟，曾是天津共赋诗。"]'),
('song-ci-928','蝶恋花','陆游','宋','宋词','song-ci','蝶恋花','[]','禹庙兰亭今古路。',70,'宋词/ci.song.9000.json','["禹庙兰亭今古路。", "一夜清霜，染尽湖边树。", "鹦鹉杯深君莫诉。", "他时相遇知何处。", "冉冉年华留不住。", "镜里朱颜，毕竟消磨去。", "一句丁宁君记取。", "神仙须是闲人做。"]'),
('song-ci-929','渔父・渔歌子','陆游','宋','宋词','song-ci','渔父・渔歌子','[]','石帆山下雨空濛。',32,'宋词/ci.song.9000.json','["石帆山下雨空濛。", "三扇香新翠箬篷。", "苹叶绿，蓼花红。", "回首功名一梦中。"]'),
('song-ci-930','渔父・渔歌子','陆游','宋','宋词','song-ci','渔父・渔歌子','[]','晴山滴翠水挼蓝。',32,'宋词/ci.song.9000.json','["晴山滴翠水挼蓝。", "聚散渔舟两复三。", "横埭北，断桥南。", "侧起船篷便作帆。"]'),
('song-ci-931','渔父・渔歌子','陆游','宋','宋词','song-ci','渔父・渔歌子','[]','镜湖俯仰两青天。',32,'宋词/ci.song.9000.json','["镜湖俯仰两青天。", "万顷玻璃一叶船。", "拈棹舞，拥蓑眠。", "不作天仙作水仙。"]'),
('song-ci-932','渔父・渔歌子','陆游','宋','宋词','song-ci','渔父・渔歌子','[]','湘湖烟雨长莼丝。',32,'宋词/ci.song.9000.json','["湘湖烟雨长莼丝。", "菰米新炊滑上匙。", "云散后，月斜时。", "潮落舟横醉不知。"]'),
('song-ci-933','渔父・渔歌子','陆游','宋','宋词','song-ci','渔父・渔歌子','[]','长安拜免几公卿。',32,'宋词/ci.song.9000.json','["长安拜免几公卿。", "渔父横眠醉未醒。", "烟艇小，钓车腥。", "遥指梅山一点青。"]'),
('song-ci-934','恋绣衾','陆游','宋','宋词','song-ci','恋绣衾','[]','雨断西山晚照明。',68,'宋词/ci.song.9000.json','["雨断西山晚照明。", "悄无人、幽梦自惊。", "说道去、多时也，到如今、真个是行。", "远山已是无心画，小楼空、斜掩绣屏。", "你嚎早、收心呵，趁刘郎、双鬓未星。"]'),
('song-ci-935','采桑子','陆游','宋','宋词','song-ci','采桑子','[]','三山山下闲居士，巾履萧然。',26,'宋词/ci.song.9000.json','["三山山下闲居士，巾履萧然。", "小醉闲眠。", "风引飞花落钓船。"]'),
('song-ci-936','水龙吟','陆游','宋','宋词','song-ci','水龙吟','[]','摩诃池上追游路，红绿参差春晚。',126,'宋词/ci.song.9000.json','["摩诃池上追游路，红绿参差春晚。", "韶光妍媚，海棠如醉，桃花欲暖。", "挑菜初闲，禁烟将近，一城丝管。", "看金鞍争道，香车飞盖，争先占、新亭馆。", "惆怅年华暗换。", "黯销魂、雨收云散。", "镜奁掩月，钗梁拆凤，秦筝斜雁。", "身在天涯，乱山孤垒，危楼飞观。", "叹春来只有，杨花和恨、向东风满。"]'),
('song-ci-937','月照梨花・河传','陆游','宋','宋词','song-ci','月照梨花・河传','[]','霁景风软，烟江春涨。',66,'宋词/ci.song.9000.json','["霁景风软，烟江春涨。", "小阁无人，绣帘半上。", "花外姊妹相呼。", "约樗蒲。", "修蛾忘了章台样。", "细思一饷。", "感事添惆怅。", "胸酥臂玉消减，拟觅双鱼。", "倩传书。"]'),
('song-ci-938','月照梨花・河传','陆游','宋','宋词','song-ci','月照梨花・河传','[]','闷已萦损。',66,'宋词/ci.song.9000.json','["闷已萦损。", "那堪多病。", "几曲屏山，伴人昼静。", "梁燕催起犹慵。", "换熏龙。", "新愁旧恨何时尽。", "渐凋绿鬓。", "小雨知花信。", "芳笺寄与何处，绣阁珠栊。", "柳阴中。"]'),
('song-ci-939','夜游宫','陆游','宋','宋词','song-ci','夜游宫','[]','宴罢珠帘半卷。',71,'宋词/ci.song.9000.json','["宴罢珠帘半卷。", "画檐外、蜡香人散。", "翠雾霏霏漏声断。", "倚香肩，看中庭，花影乱。", "宛是高唐馆。", "宝奁炷、麝烟初暖。", "璧月何妨夜夜满。", "拥芳柔，恨今年，寒尚浅。"]'),
('song-ci-940','如梦令','陆游','宋','宋词','song-ci','如梦令','[]','独倚博山峰小。',40,'宋词/ci.song.9000.json','["独倚博山峰小。", "翠雾满身飞绕。", "只恐学行云，去作阳台春晓。", "春晓。", "春晓。", "满院绿阳芳草。"]'),
('song-ci-941','失调名','陆游','宋','宋词','song-ci','失调名','[]','飞上锦裀红皱。',7,'宋词/ci.song.9000.json','["飞上锦裀红皱。"]'),
('song-ci-942','解连环','陆游','宋','宋词','song-ci','解连环','[]','泪淹妆薄。',132,'宋词/ci.song.9000.json','["泪淹妆薄。", "背东风伫立，柳绵池阁。", "漫细字、书满芳笺，恨钗燕筝鸿，总难凭托。", "风雨无情，又颠倒、绿苔红萼。", "仗香醪破闷，怎禁夜阑，酒酲萧索。", "刘郎已望故约。", "奈重门静院，光景如昨。", "尽做它、别有留心，便不念当时，雨意初著。", "京兆眉残，怎忍为、新人梳掠。", "尽今生、拼了为伊，任人道错。"]'),
('song-ci-943','大圣乐','陆游','宋','宋词','song-ci','大圣乐','[]','电转雷惊，自叹浮生，四十二年。',117,'宋词/ci.song.9000.json','["电转雷惊，自叹浮生，四十二年。", "试思量往事，虚无似梦，悲欢万状，合散如烟。", "苦海无边，爱河无底，流浪看成百漏船。", "何人解，问无常火里，铁打身坚。", "须臾便是华颠。", "好收拾形体归自然。", "又何通，是非荣辱，此事由来都在天。", "从今去，任东西南北，作个飞仙。"]'),
('song-ci-944','钗头凤・撷芳词','唐婉','宋','宋词','song-ci','钗头凤・撷芳词','[]','世情薄。',76,'宋词/ci.song.9000.json','["世情薄。", "人情恶。", "雨送黄昏花易落。", "晓风乾。", "泪痕残。", "欲笺心事，独语斜阑。", "难难难。", "人成各。", "今非昨。", "病魂尝似秋千索。", "角声寒。", "夜阑珊。", "怕人寻问，咽泪装欢。", "瞒瞒瞒。"]'),
('song-ci-945','生查子','陆游妾某氏','宋','宋词','song-ci','生查子','[]','只知愁上眉，不识愁来路。',48,'宋词/ci.song.9000.json','["只知愁上眉，不识愁来路。", "窗外有芭蕉，阵阵黄昏雨。", "逗晓理残妆，整顿教愁去。", "不合画春山，依旧留连住。"]'),
('song-ci-946','祝英台近','王','宋','宋词','song-ci','祝英台近','[]','柳烟浓，花露重，合是醉时候。',95,'宋词/ci.song.9000.json','["柳烟浓，花露重，合是醉时候。", "楼倚花梢，长记小垂手。", "谁教钗燕轻分，镜鸾慵舞，是孤负、几番春昼。", "自别后。", "闻道花底花前，多是两眉皱。", "又说新来，比似旧时瘦。", "须知两意长存，相逢终有。", "莫谩被、春光僝僽。"]'),
('song-ci-947','夜行船','王','宋','宋词','song-ci','夜行船','[]','曲水溅裙三月二。',68,'宋词/ci.song.9000.json','["曲水溅裙三月二。", "马如龙、钿车如水。", "风扬游丝，日烘晴昼，人共海棠俱醉。", "客里光阴难可意。", "扫芳尘、旧游谁记。", "午梦醒来，小窗人静，春在卖花声里。"]'),
('song-ci-948','朝中措','贾逸祖','宋','宋词','song-ci','朝中措','[]','青山隐隐水斜斜。',60,'宋词/ci.song.9000.json','["青山隐隐水斜斜。", "修竹两三家。", "又是水寒山瘦，依然行客遍天涯。", "天教流落，东西南北，不恨年华。", "只恨夜来风雨，投明月、老却梅花。"]'),
('song-ci-949','鹊桥仙','蜀妓','宋','宋词','song-ci','鹊桥仙','[]','说盟说誓。',68,'宋词/ci.song.9000.json','["说盟说誓。", "说情说意。", "动便春愁满纸。", "多应念得脱空经，是那个、先生教底。", "不茶不饭，不言不语，一味供他憔悴。", "相思已是不曾闲，又那得、功夫咒你。"]'),
('song-ci-950','画堂春','姜特立','宋','宋词','song-ci','画堂春','[]','故园二月正芳菲。',53,'宋词/ci.song.9000.json','["故园二月正芳菲。", "红紫团枝。", "一番草绿谢郎池。", "人醉如泥。", "底事江乡风物，年年独殿芳时。", "无情燕子背人飞。", "似愧春迟。"]'),
('song-ci-951','浣溪沙','姜特立','宋','宋词','song-ci','浣溪沙','[]','节序回环已献裘。',48,'宋词/ci.song.9000.json','["节序回环已献裘。", "不堪风叶夜鸣秋。", "寒螀吟露月阶幽。", "蜗角虚名真误我，蝇头细字不禁愁。", "班超何日定封候。"]'),
('song-ci-952','菩萨蛮','姜特立','宋','宋词','song-ci','菩萨蛮','[]','日长庭院无人到。',52,'宋词/ci.song.9000.json','["日长庭院无人到。", "琅玕翠影摇寒瓮。", "困卧北窗凉。", "好风吹梦长。", "壁月升东岭。", "冷浸扶疏影。", "苗叶万珠明。", "露华圆更清。"]'),
('song-ci-953','菩萨蛮','姜特立','宋','宋词','song-ci','菩萨蛮','[]','蓬山学士文章伯。',52,'宋词/ci.song.9000.json','["蓬山学士文章伯。", "尊前风味谁能敌。", "新觅似花人。", "添成小院春。", "玉纤呵翠袖。", "满劝金杯酒。", "寿酒莫辞斟。", "酒深人意深。"]'),
('song-ci-954','菩萨蛮','姜特立','宋','宋词','song-ci','菩萨蛮','[]','镜天良月皆佳节。',52,'宋词/ci.song.9000.json','["镜天良月皆佳节。", "休恨今宵妨皎洁。", "玉锁闷蟾宫。", "姮娥意自通。", "终有开时节。", "莫放笙歌歇。", "来夕尚婵娟。", "何妨把酒看。"]'),
('song-ci-955','霜天晓角','姜特立','宋','宋词','song-ci','霜天晓角','["\u897f\u6e56"]','欢娱电掣。',54,'宋词/ci.song.9000.json','["欢娱电掣。", "何况轻离别。", "料得两情无奈，思量尽、总难说。", "酒热。", "凄兴发。", "共寻波底月。", "长结西湖心愿，水有尽、情无歇。"]'),
('song-ci-956','阮郎归','姜特立','宋','宋词','song-ci','阮郎归','[]','绿阴庭院记年时。',56,'宋词/ci.song.9000.json','["绿阴庭院记年时。", "家人捧寿卮。", "乐声催拍送腰支。", "香风匝地衣。", "清梦断，彩云飞。", "刘郎今鬓丝。", "强将杯酒破愁眉。", "如今触事非。"]'),
('song-ci-957','浪淘沙','姜特立','宋','宋词','song-ci','浪淘沙','[]','春事有来期。',64,'宋词/ci.song.9000.json','["春事有来期。", "且喜春归。", "问春何似去年时。", "报道今年春意好，随分开眉。", "往事莫伤悲。", "光景如飞。", "十分潘鬓已成丝。", "幸是风流犹未减，且醉芳菲。"]'),
('song-ci-958','朝中措','姜特立','宋','宋词','song-ci','朝中措','[]','芳林曲径锦玲珑。',57,'宋词/ci.song.9000.json','["芳林曲径锦玲珑。", "腻白借微红。", "元是海棠标格，司花点化东风。", "端相浑似，玉真未醉，春思先慵。", "留取浅颦低笑，夜深翠幄轻笼。"]'),
('song-ci-959','朝中措','姜特立','宋','宋词','song-ci','朝中措','[]','十分天赋好精神。',57,'宋词/ci.song.9000.json','["十分天赋好精神。", "宫样小腰身。", "迷却阳城下蔡，未饶宋玉东邻。", "不堪回首，高堂去梦，楚峡归云。", "从此好寻夫婿，有书频寄鸿鳞。"]'),
('song-ci-960','朝中措','姜特立','宋','宋词','song-ci','朝中措','[]','如山堂上翠横空。',57,'宋词/ci.song.9000.json','["如山堂上翠横空。", "山影浪花中。", "夜夜林间明月，时时柳外清风。", "如今到此，け然万事，无处情锺。", "唯有尊前一笑，分明好个山翁。"]'),
('song-ci-961','蝶恋花','姜特立','宋','宋词','song-ci','蝶恋花','[]','飘粉吹香三月暮。',70,'宋词/ci.song.9000.json','["飘粉吹香三月暮。", "病酒情怀，愁绪浑无数。", "有个人人来又去。", "归期有恨难留驻。", "明日尊前无觅处。", "咿轧篮舆，只向双溪路。", "我辈情锺君谩与。", "为云为雨应难据。"]'),
('song-ci-962','声声慢','姜特立','宋','宋词','song-ci','声声慢','[]','云迷越岫，枫冷吴江，天香忽到人寰。',119,'宋词/ci.song.9000.json','["云迷越岫，枫冷吴江，天香忽到人寰。", "满额涂黄，别更一种施丹。", "天教素秋独步，笑同时、霜菊秋兰。", "最好处，向水阶月地，把酒相看。", "应有骚人雅韵，将胆瓶筠管，簇向屏山。", "野店云房，争待结屋中间。", "无奈猖狂老子，架巢卧、风露清闲。", "待早晚，约姮娥、同住广寒。"]'),
('song-ci-963','卜算子','姜特立','宋','宋词','song-ci','卜算子','[]','丹桂一枝芳，陡觉秋容静。',52,'宋词/ci.song.9000.json','["丹桂一枝芳，陡觉秋容静。", "月里人间总一般，共此扶疏影。", "枕畔忽闻香，夜半还思省。", "争奈姮娥不嫁人，寂寞孤衾冷。"]'),
('song-ci-964','西江月','姜特立','宋','宋词','song-ci','西江月','[]','富贵从来自有，人生最羡长年。',58,'宋词/ci.song.9000.json','["富贵从来自有，人生最羡长年。", "骎骎八秩未华颠。", "更喜此身强健。", "金印新来如斗，丝纶御墨犹鲜。", "枣如瓜大藕如船。", "莫惜尊前满劝。"]'),
('song-ci-965','满江红','姜特立','宋','宋词','song-ci','满江红','[]','听说梅山，一邱内、深藏曲折。',112,'宋词/ci.song.9000.json','["听说梅山，一邱内、深藏曲折。", "过醒心桥下，水光清彻。", "迤逦跻攀登翠岭，沈沈烟壑千峰列。", "更小亭、风露逼华堂，荷香发。", "歌声动，云横阕。", "舞腰转，风回雪。", "正良辰美景，众宾欢悦。", "老子中间聊笑傲，酒行莫放觥筹歇。", "愿此生、长似钓璜公，添华发。"]'),
('song-ci-966','念奴娇','姜特立','宋','宋词','song-ci','念奴娇','[]','宦途巇险，问急流勇退，几人闻早。',120,'宋词/ci.song.9000.json','["宦途巇险，问急流勇退，几人闻早。", "自别修门今正是，一纪生朝还到。", "绿野风光，平泉草木，争似梅山好。", "园林如画，芰荷香泛芳沼。", "早晚玉节来临，君恩踵至，金印应如斗。", "好是华堂开宴处，歌舞管弦声奏。", "海上蟠桃，山中仙杏，共劝长生酒。", "莫辞沈醉，年年此会依旧。"]'),
('song-ci-967','满江红','姜特立','宋','宋词','song-ci','满江红','[]','小小华堂，朱阑外、乱山如簇。',112,'宋词/ci.song.9000.json','["小小华堂，朱阑外、乱山如簇。", "更云中仙掌，一峰高矗。", "南极老人呈瑞处，丙丁躔次光相烛。", "又谁知、堂上有闲人，无拘束。", "宾朋至，须歌曲。", "风月好，纷丝竹，都不管、世间是非荣辱。", "屈指如今侪辈少，几人老后能知足。", "问此身、何地寄生涯，唯松菊。"]'),
('song-ci-968','临江仙','姜特立','宋','宋词','song-ci','临江仙','[]','桃李飞花春渐老，海棠次第芬芳。',70,'宋词/ci.song.9000.json','["桃李飞花春渐老，海棠次第芬芳。", "庭前红叶已成行。", "酴醿开未到，犹更有花王。", "从此便须排日醉，莫将闲事相妨。", "老来不是太疏狂。", "尊前君看取，潘宾已成霜。"]'),
('song-ci-969','感皇恩','姜特立','宋','宋词','song-ci','感皇恩','[]','儿女沸欢声，生朝来到。',81,'宋词/ci.song.9000.json','["儿女沸欢声，生朝来到。", "帘幕中间喷香兽。", "京祠新任，好事日边还又。", "清闲无个事，君恩厚。", "赢得乞食，歌姬一笑。", "旧衲云山伴红袖。", "蓬莱弱水，试问神仙何有。", "近来饶落托，贪杯酒。"]'),
('song-ci-970','朝中措','周必大','宋','宋词','song-ci','朝中措','[]','乘成台上晓书云。',57,'宋词/ci.song.9000.json','["乘成台上晓书云。", "黄色映天庭。", "已谢浮名浮利，也知来应长生。", "边亭卧鼓，馀粮栖亩，朝野欢声。", "从此四时八节，弟兄常醉金觥。"]'),
('song-ci-971','满庭芳','周必大','宋','宋词','song-ci','满庭芳','[]','天壤茫茫，人心殊观，未免因欠思馀。',118,'宋词/ci.song.9000.json','["天壤茫茫，人心殊观，未免因欠思馀。", "太山邱垤，同载一方舆。", "那更长沙下湿，祝融峰、才比吾庐。", "秋风冷，攀缘汗浃，应叹苦区区。", "登高，聊尔耳，何须蜡屐，谁暇膏车。", "默存处，清都宛在须臾。", "笑约乘鸾羽客，窥倒景、拊掌崎岖。", "归来把，萸囊菊盏，一为洗泥涂。"]'),
('song-ci-972','谒金门','周必大','宋','宋词','song-ci','谒金门','[]','梅乍吐。',55,'宋词/ci.song.9000.json','["梅乍吐。", "趁寿席、香风度。", "人与此花俱独步。", "风流天付与。", "好在青云歧路。", "愿共作、和羹侣。", "归访赤松辞万户。", "莺花犹是主。"]'),
('song-ci-973','点绛唇','周必大','宋','宋词','song-ci','点绛唇','[]','报答风光，满倾琼液休思睡。',50,'宋词/ci.song.9000.json','["报答风光，满倾琼液休思睡。", "乱莺声碎。", "来往甘棠底。", "闻道中和，深简君王意。", "归舟起。", "到时应是。", "玉殿槐交翠。"]'),
('song-ci-974','点绛唇','周必大','宋','宋词','song-ci','点绛唇','[]','醉上兰舟，羡他沙暖鸳鸯睡。',50,'宋词/ci.song.9000.json','["醉上兰舟，羡他沙暖鸳鸯睡。", "月波金碎。", "愁海深无底。", "太守新词，解释无穷意。", "高歌起。", "浮云闲事。", "浑付烟中翠。"]'),
('song-ci-975','点绛唇','周必大','宋','宋词','song-ci','点绛唇','[]','踏白江梅，大都玉斫酥凝就。',50,'宋词/ci.song.9000.json','["踏白江梅，大都玉斫酥凝就。", "雨肥霜逗。", "痴了闺房秀。", "莫待冬深，雪压风欺后。", "君知否。", "却嫌伊瘦。", "仍怕伊僝僽。"]'),
('song-ci-976','点绛唇','周必大','宋','宋词','song-ci','点绛唇','[]','秋夜乘槎，客星容到天孙渚。',50,'宋词/ci.song.9000.json','["秋夜乘槎，客星容到天孙渚。", "眼波微注。", "将谓牵牛渡。", "见了还非，重理霓裳舞。", "都无误。", "几年一遇。", "莫讶周郎顾。"]'),
('song-ci-977','朝中措','周必大','宋','宋词','song-ci','朝中措','[]','月眉新画露珠圆。',57,'宋词/ci.song.9000.json','["月眉新画露珠圆。", "今夕正相鲜。", "欲导唐家诞节，先生汉相韦贤。", "悬知此去，莺迁春谷，鹗在秋天。", "班首算来旬岁，状头看取明年。"]'),
('song-ci-978','朝中措','周必大','宋','宋词','song-ci','朝中措','[]','九重深念朔庭空。',57,'宋词/ci.song.9000.json','["九重深念朔庭空。", "良弼梦时中。", "擢第难遵常制，筑岩直继高风。", "明年东府，金钗珠履，列鼎鸣钟。", "良酝傥分焦革，早禾休浸曹公。"]'),
('song-ci-979','醉落魄・一斛珠','周必大','宋','宋词','song-ci','醉落魄・一斛珠','[]','山川迥别。',67,'宋词/ci.song.9000.json','["山川迥别。", "赤城自古雄东越。", "锺英储秀簪绅列。", "何事黄扉，殊未相黄发。", "如今衮职那容缺。", "人心恰与天时合。", "看看孚号彤庭发。", "初破天荒，留与后来说。"]'),
('song-ci-980','醉落魄・一斛珠','周必大','宋','宋词','song-ci','醉落魄・一斛珠','[]','才高句杰。',67,'宋词/ci.song.9000.json','["才高句杰。", "飞黄却应鸾和节。", "新词聊卷波澜阔。", "泉玉淙铮，犹不比清切。", "相逢未稳愁相别。", "南园烟草南楼月。", "阳关西出重吹彻。", "垂柳新栽，宁忍便攀折。"]'),
('song-ci-981','西江月','周必大','宋','宋词','song-ci','西江月','[]','三月群贤毕集，二天五马生光。',58,'宋词/ci.song.9000.json','["三月群贤毕集，二天五马生光。", "传觞击鼓底匆忙。", "画鹢将飞江上。", "鲁国方虚两社，齐人要复侵疆。", "延英引对上东廊。", "应念幽人相望。"]'),
('song-ci-982','西江月','周必大','宋','宋词','song-ci','西江月','[]','藉甚新除刺史，岿然鲁殿灵光。',58,'宋词/ci.song.9000.json','["藉甚新除刺史，岿然鲁殿灵光。", "诏书催发棹讴忙。", "沙路从今稳上。", "有喜刊除戎索，无劳远抚闽疆。", "日高龙影转槐廊。", "想见清光注望。"]'),
('song-ci-983','导引','周必大','宋','宋词','song-ci','导引','[]','重华真主，晨夕奉庭闱。',59,'宋词/ci.song.9000.json','["重华真主，晨夕奉庭闱。", "禋祀庆成时。", "乾元坤载同归美，宝册两光辉。", "斑衣何似赭黄衣。", "此事古今稀。", "都人欢乐嵩呼震，圣寿总天齐。"]'),
('song-ci-984','导引','周必大','宋','宋词','song-ci','导引','[]','新阳初应，乐事起彤庭。',59,'宋词/ci.song.9000.json','["新阳初应，乐事起彤庭。", "和气满吴京。", "帝家来庆东皇寿，西母共长生。", "金书玉篆灿龙文。", "前导沸欢声。", "修龄无极名无尽，一岁一回增。"]'),
('song-ci-985','导引','周必大','宋','宋词','song-ci','导引','[]','合宫亲飨，青女肃长空。',59,'宋词/ci.song.9000.json','["合宫亲飨，青女肃长空。", "精意与天通。", "后皇临顾谁为侑，文祖暨神功。", "亟蒙祉福岁长丰。", "声教被华戎。", "两宫眉寿同荣乐，戬谷永来崇。"]'),
('song-ci-986','合宫歌','周必大','宋','宋词','song-ci','合宫歌','[]','圣明朝，旷典乘秋举。',161,'宋词/ci.song.9000.json','["圣明朝，旷典乘秋举。", "大飨本仁祖。", "九室八牖四户。", "敕躬齐戒格堪舆。", "盛牲实俎。", "并侑总稽古。", "玉露乍肃天宇。", "冰轮下照金铺。", "燎烟嘘呼。", "郁尊香，云门舞。", "仿佛翔坐，灵心咸嘉娱。", "众星俞美，光属照熉珠。", "清晓御丹凤，湛恩遍浃率溥。", "欢声雷动岳镇呼。", "徐命法驾，万骑花盈路。", "献胙慈极，寿同箕翼，事超唐虞。", "看平燕云，从此兴文偃武。", "待重会诸侯，依旧东都。"]'),
('song-ci-987','失调名','周辉','宋','宋词','song-ci','失调名','[]','卷帘试约东君，问花信风来第几番。',16,'宋词/ci.song.9000.json','["卷帘试约东君，问花信风来第几番。"]'),
('song-ci-988','失调名','周辉','宋','宋词','song-ci','失调名','[]','生怕冻损蜂房，胆瓶汤浸，且与温存著。',18,'宋词/ci.song.9000.json','["生怕冻损蜂房，胆瓶汤浸，且与温存著。"]'),
('song-ci-989','满江红','范成大','宋','宋词','song-ci','满江红','[]','寒谷春生，熏叶气、玉筒吹谷。',115,'宋词/ci.song.9000.json','["寒谷春生，熏叶气、玉筒吹谷。", "新阳后、便占新岁，吉云清穆。", "休把心情关乐裹，但逢节序添诗轴。", "笑强颜、风物岂非痴，终非俗。", "清昼永，佳眠熟。", "门外事，何时足。", "且团栾同社，笑歌相属。", "著意调停云露酿，从头检举梅花曲。", "纵不能、将醉作生涯，休拘束。"]'),
('song-ci-990','满江红','范成大','宋','宋词','song-ci','满江红','[]','竹里行厨，来问讯、诸侯宾老。',115,'宋词/ci.song.9000.json','["竹里行厨，来问讯、诸侯宾老。", "春满座、弹丝未遍，挥豪先了。", "云避仁风收雨脚，日随和气薰林表。", "向尊前、来访白髯公，衰何早。", "志千里，功名兆。", "光万丈，文章耀。", "洗水壶胸次，月秋霜晓。", "应念一堂尘网暗，故将百和香云绕。", "算赏心、清话古来多，如今少。"]'),
('song-ci-991','满江红','范成大','宋','宋词','song-ci','满江红','[]','柳外轻雷，催几阵、雨丝飞急。',114,'宋词/ci.song.9000.json','["柳外轻雷，催几阵、雨丝飞急。", "雷雨过、半川荷气，粉融香浥。", "弄蕊攀条春一笑，从教水溅罗衣湿。", "打梁州、箫鼓浪花中，跳鱼立。", "山倒影，云千叠。", "横浩荡，舟如叶。", "有采菱清些，桃根双楫。", "忘却天涯泊地，尊前不放闲愁人。", "任碧筒、十丈卷金波，长鲸吸。"]'),
('song-ci-992','满江红','范成大','宋','宋词','song-ci','满江红','[]','罨画溪山，行欲遍、风蒲还举。',115,'宋词/ci.song.9000.json','["罨画溪山，行欲遍、风蒲还举。", "天渐远、水云初静，柁楼人语。", "月色波光看不定，玉虹横卧金鳞舞。", "看五湖、今夜只边舟，追千古。", "怀往事，渔樵侣。", "曾共醉，松江渚。", "算今年依旧，一杯沧浦。", "宇宙此身元是客，不须怅望家何许。", "但中秋、时节好溪山，皆吾土。"]'),
('song-ci-993','千秋岁','范成大','宋','宋词','song-ci','千秋岁','[]','北城南埭。',87,'宋词/ci.song.9000.json','["北城南埭。", "玉水方流汇。", "青樾里，红尘外。", "万桃春不老，双竹寒相对。", "回首处，满城明月曾同载。", "分散西园盖。", "消减东阳带。", "人事改，花源在。", "神仙虽可学，功行无过醉。", "新酒好，就船况有鱼堪买。"]'),
('song-ci-994','浣溪沙','范成大','宋','宋词','song-ci','浣溪沙','[]','倾坐东风百媚生。',48,'宋词/ci.song.9000.json','["倾坐东风百媚生。", "万红无语笑逢迎。", "照妆醒睡蜡烟轻。", "采蝀横斜春不夜，绛霞浓淡月微明。", "梦中重到锦官城。"]'),
('song-ci-995','浣溪沙','范成大','宋','宋词','song-ci','浣溪沙','[]','催下珠帘护绮丛。',48,'宋词/ci.song.9000.json','["催下珠帘护绮丛。", "花枝红里烛枝红。", "烛光花影夜葱茏。", "锦地绣天香雾里，珠星璧月彩云中。", "人间别有几春风。"]'),
('song-ci-996','浣溪沙','范成大','宋','宋词','song-ci','浣溪沙','[]','送尽残春更出游。',48,'宋词/ci.song.9000.json','["送尽残春更出游。", "风前踪迹似沙鸥。", "浅斟低唱小淹留。", "月见西楼清夜醉，雨添南浦绿波愁。", "有人无计恋行舟。"]'),
('song-ci-997','浣溪沙','范成大','宋','宋词','song-ci','浣溪沙','[]','歙浦钱塘一水通。',48,'宋词/ci.song.9000.json','["歙浦钱塘一水通。", "闲云如幕碧重重。", "吴山应在碧云东。", "无力海棠风淡荡，半眠官柳日葱茏。", "眼前春色为谁浓。"]'),
('song-ci-998','浣溪沙','范成大','宋','宋词','song-ci','浣溪沙','[]','宝髻双双出绮丛。',48,'宋词/ci.song.9000.json','["宝髻双双出绮丛。", "妆光梅影各春风。", "收灯时候却相逢。", "鱼子笺中此宛转，龙香拨上语玲珑。", "明朝车马莫西东。"]'),
('song-ci-999','浣溪沙','范成大','宋','宋词','song-ci','浣溪沙','[]','红锦障泥杏叶鞯。',48,'宋词/ci.song.9000.json','["红锦障泥杏叶鞯。", "解鞍呼渡忆当年。", "马骄不肯上航船。", "茅店竹篱开席市，绛裙青袂斸姜田。", "临平风物故依然。"]'),
('yuanqu-0','诈妮子调风月・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','半世为人，不曾教大人心困。',37,'元曲/yuanqu.json','["半世为人，不曾教大人心困。", "虽是搽胭粉，只争不裹头巾，将那等不做人的婆娘恨。"]'),
('yuanqu-1','诈妮子调风月・混江龙','关汉卿','元','元曲','yuanqu','','[]','男儿人若不依本分，一个抢白是非两家分。',97,'元曲/yuanqu.json','["男儿人若不依本分，一个抢白是非两家分。", "壮鼻凹硬如石铁，教满耳根都做了烧云。", "普天下汉子尽教都先有意，牢把定自己休不成人。", "虽然两家无意，便待一面成亲，不分晓便似包着一肚皮干牛粪。", "知人无意，及早抽身。"]'),
('yuanqu-2','诈妮子调风月・那吒令','关汉卿','元','元曲','yuanqu','','[]','等不得水温，一声要面盆；恰递与面盆，一声要手巾；却执与手巾，一声解纽门。',49,'元曲/yuanqu.json','["等不得水温，一声要面盆；恰递与面盆，一声要手巾；却执与手巾，一声解纽门。", "使的人无淹润、百般支分！。"]'),
('yuanqu-3','诈妮子调风月・鹊踏枝','关汉卿','元','元曲','yuanqu','','[]','入得房门，怎回身？厅独卧房儿窄窄别别，有甚铺呈？燕燕己身有甚么孝顺？拗不过哥哥行在意殷勤。',45,'元曲/yuanqu.json','["入得房门，怎回身？厅独卧房儿窄窄别别，有甚铺呈？燕燕己身有甚么孝顺？拗不过哥哥行在意殷勤。"]'),
('yuanqu-4','诈妮子调风月・寄生草','关汉卿','元','元曲','yuanqu','','[]','卧地观经史，坐地对圣人。',89,'元曲/yuanqu.json','["卧地观经史，坐地对圣人。", "你观的国风、雅、颂施诂训，诵的典谟训诰居尧舜，（末云了）（正旦唱）说的温良恭俭行忠信。", "燕燕子理会得龙盘虎踞灭燕齐，谁会甚儿婚女聘成秦晋？（末云）这书院好。"]'),
('yuanqu-5','诈妮子调风月・幺篇','关汉卿','元','元曲','yuanqu','','[]','这书房存得阿马，会得客宾。',69,'元曲/yuanqu.json','["这书房存得阿马，会得客宾。", "翠筠月朗龙蛇印，碧轩夜冷灯香信，绿窗雨细琴书润。", "每朝席上宴佳宾，抵多少\"十年窗下无人问\"！（末云住）（正旦唱）。"]'),
('yuanqu-6','诈妮子调风月・村里迓鼓','关汉卿','元','元曲','yuanqu','','[]','更做道一家生女，百家求问。',67,'元曲/yuanqu.json','["更做道一家生女，百家求问。", "才说贞烈，那里取一个时辰？见他语言儿栽排得淹润，怕不待言词硬，性格村、他怎比寻常世人？（末云了）（正旦唱）。"]'),
('yuanqu-7','诈妮子调风月・元和令','关汉卿','元','元曲','yuanqu','','[]','无男儿只一身，担寂寞受孤闷；有男儿呓梦入劳魂，心肠百处分。',47,'元曲/yuanqu.json','["无男儿只一身，担寂寞受孤闷；有男儿呓梦入劳魂，心肠百处分。", "知得有情人不曾来问肯，便待要成眷姻。"]'),
('yuanqu-8','诈妮子调风月・上马娇','关汉卿','元','元曲','yuanqu','','[]','自勘婚，自说亲，也是"贱媳妇责媒人"。',52,'元曲/yuanqu.json','["自勘婚，自说亲，也是\"贱媳妇责媒人\"。", "往常我冰清玉洁难亲近，是他亲，子管教话儿亲。", "我煞待嗔，我便恶相闻。"]'),
('yuanqu-9','诈妮子调风月・胜葫芦','关汉卿','元','元曲','yuanqu','','[]','怕不依随蒙君一夜恩，争奈忒达地、忒知根，兼上亲上成亲好对门。',51,'元曲/yuanqu.json','["怕不依随蒙君一夜恩，争奈忒达地、忒知根，兼上亲上成亲好对门。", "觑了他兀的模样，这般身分。", "若脱过这好郎君。"]'),
('yuanqu-10','诈妮子调风月・幺篇','关汉卿','元','元曲','yuanqu','','[]','教人道"眼里无珍一世贫"；成就了又怕辜恩。',52,'元曲/yuanqu.json','["教人道\"眼里无珍一世贫\"；成就了又怕辜恩。", "若往常烈焰飞腾情性紧，若一遭儿恩爱，再来不问，枉侵了这百年恩。"]'),
('yuanqu-11','诈妮子调风月・柳叶儿','关汉卿','元','元曲','yuanqu','','[]','一个个背槽抛粪，一个个负义忘恩，自来鱼雁无音信。',46,'元曲/yuanqu.json','["一个个背槽抛粪，一个个负义忘恩，自来鱼雁无音信。", "自思忖，不审得话儿真，枉葫芦提了\"燕尔新婚。"]'),
('yuanqu-12','诈妮子调风月・尾','关汉卿','元','元曲','yuanqu','','[]','忽地却掀帘，兜地回头问，不由我心儿里便亲。',122,'元曲/yuanqu.json','["忽地却掀帘，兜地回头问，不由我心儿里便亲。", "你把那并枕睡的日头儿再定轮，休教我逐宵价握雨携云。", "过今春，先教我不系腰裙，便是半簸箕头钱扑个复纯。", "教人道\"眼里有珍\"，你可休\"言而无信\"！（云）许下我包髻、团衫、绣手巾。", "专等你世袭千户的小夫人。", "（下）。"]'),
('yuanqu-13','诈妮子调风月・中吕/粉蝶儿','关汉卿','元','元曲','yuanqu','','[]','年例寒食，邻姬每斗来邀会，去年时没人将我拘管收拾。',60,'元曲/yuanqu.json','["年例寒食，邻姬每斗来邀会，去年时没人将我拘管收拾。", "打秋千，闲斗草，直到个昏天黑地；今年个不敢来迟，有一个未拿着性儿女婿。"]'),
('yuanqu-14','诈妮子调风月・醉春风','关汉卿','元','元曲','yuanqu','','[]','因甚把玉粳米牙儿抵，金莲花攒枕倚？或嗔或喜脸儿多？哎！你、你！教我没想没思，两心两意，早晨古自一家一计！。',53,'元曲/yuanqu.json','["因甚把玉粳米牙儿抵，金莲花攒枕倚？或嗔或喜脸儿多？哎！你、你！教我没想没思，两心两意，早晨古自一家一计！。"]'),
('yuanqu-15','诈妮子调风月・朱履曲','关汉卿','元','元曲','yuanqu','','[]','莫不是郊外去逢着甚邪祟？又不疯又不呆痴，面没罗、呆答孩、死堆灰。',56,'元曲/yuanqu.json','["莫不是郊外去逢着甚邪祟？又不疯又不呆痴，面没罗、呆答孩、死堆灰。", "这烦恼在谁身上？莫不在我根底，打听得些闲是非？。"]'),
('yuanqu-16','诈妮子调风月・满庭芳','关汉卿','元','元曲','yuanqu','','[]','见我这般微微喘息，语言恍惚，脚步儿查梨。',51,'元曲/yuanqu.json','["见我这般微微喘息，语言恍惚，脚步儿查梨。", "慢松松胸带儿频那系，裙腰儿空闲里偷提。", "见我这般气丝丝偏斜了髟。"]'),
('yuanqu-17','诈妮子调风月・十二月','关汉卿','元','元曲','yuanqu','','[]','直到个天昏地黑，不肯更换衣袂；把兔鹘解开，纽扣相离，把袄子疏剌剌松开上拆，将手帕撇漾在田地。',46,'元曲/yuanqu.json','["直到个天昏地黑，不肯更换衣袂；把兔鹘解开，纽扣相离，把袄子疏剌剌松开上拆，将手帕撇漾在田地。"]'),
('yuanqu-18','诈妮子调风月・尧民歌','关汉卿','元','元曲','yuanqu','','[]','见那厮手慌脚乱紧收拾，被我先藏在香罗袖儿里。',70,'元曲/yuanqu.json','["见那厮手慌脚乱紧收拾，被我先藏在香罗袖儿里。", "是好哥哥和我做头敌，咱两个官司有商议。", "休提！体提！哥哥撇下的手帕是阿谁的？（末云了）（正旦唱）。"]'),
('yuanqu-19','诈妮子调风月・江儿水','关汉卿','元','元曲','yuanqu','','[]','老阿者使将来伏侍你，展污了咱身起。',55,'元曲/yuanqu.json','["老阿者使将来伏侍你，展污了咱身起。", "你养着别个的，看我如奴婢，燕燕那些儿亏负你？（旦做住）（末告科）（正旦唱）。"]'),
('yuanqu-20','诈妮子调风月・上小楼','关汉卿','元','元曲','yuanqu','','[]','我敢摔碎这盒子，玳瑁纳子，教石头砸碎。',77,'元曲/yuanqu.json','["我敢摔碎这盒子，玳瑁纳子，教石头砸碎。", "（带云）这手帕。", "（唱）剪了做靴檐，染了做鞋面，持了做铺持。", "一万分好待你，好觑你！如今刀子根底，我敢割得来粉零麻碎！。"]'),
('yuanqu-21','诈妮子调风月・幺','关汉卿','元','元曲','yuanqu','','[]','更做道你好处打唤来的，却怎看得非轻，看得值钱，待得尊贵？这两下里捻捎的，有多少功绩，到重如细搀绒绣来胸背？。',54,'元曲/yuanqu.json','["更做道你好处打唤来的，却怎看得非轻，看得值钱，待得尊贵？这两下里捻捎的，有多少功绩，到重如细搀绒绣来胸背？。"]'),
('yuanqu-22','诈妮子调风月・哨遍','关汉卿','元','元曲','yuanqu','','[]','并不是婆娘人把你抑勒，招取那肯心儿自说来的神前誓。',121,'元曲/yuanqu.json','["并不是婆娘人把你抑勒，招取那肯心儿自说来的神前誓。", "天果报，无差移，子争个来早来迟。", "限时刻，十王地藏，六道轮回，单劝化人间世。", "善恶天心人意，\"人间私语，天闻若雷\"。", "但年高都是积善好心人；早寿夭都是辜恩负德贼。", "好说话清晨，变了卦今日，冷了心晚夕。"]'),
('yuanqu-23','诈妮子调风月・五煞','关汉卿','元','元曲','yuanqu','','[]','别人斩眉我早举动眼，道头知道尾。',78,'元曲/yuanqu.json','["别人斩眉我早举动眼，道头知道尾。", "你这般沙糖般甜话儿多曾吃！你又不是\"残花酝酿蜂儿蜜，细雨调和燕子泥\"。", "自笑我狂踪迹。", "我往常受那无男儿烦恼，今日知有丈夫滋味。"]'),
('yuanqu-24','诈妮子调风月・四煞','关汉卿','元','元曲','yuanqu','','[]','待争来怎地争？待悔来怎地悔？怎补得我这有气分全身体？打也阿儿包髻，真加要带与别人成美，况团衫怎能勾披？他若不在俺宅司内，便大家南北，各自东西！。',72,'元曲/yuanqu.json','["待争来怎地争？待悔来怎地悔？怎补得我这有气分全身体？打也阿儿包髻，真加要带与别人成美，况团衫怎能勾披？他若不在俺宅司内，便大家南北，各自东西！。"]'),
('yuanqu-25','诈妮子调风月・三煞','关汉卿','元','元曲','yuanqu','','[]','明日索一般供与他衣袂穿，一般过与他茶饭吃，到晚送得他被底成双睡。',78,'元曲/yuanqu.json','["明日索一般供与他衣袂穿，一般过与他茶饭吃，到晚送得他被底成双睡。", "他\"做成暖帐三更梦\"，我\"拨尽寒炉一夜灰\"。", "有句话存心记：则愿得辜恩负德，一个个荫于封妻！。"]'),
('yuanqu-26','诈妮子调风月・二煞','关汉卿','元','元曲','yuanqu','','[]','出门来一脚高一脚低，自不觉鞋底儿着田地。',68,'元曲/yuanqu.json','["出门来一脚高一脚低，自不觉鞋底儿着田地。", "痛连心除他外谁根前说，气夯破肚别人行怎又不敢提？独自向银蟾底，则道是孤鸿伴影，几时吃四马攒蹄？。"]'),
('yuanqu-27','诈妮子调风月・尾','关汉卿','元','元曲','yuanqu','','[]','呆敲才、呆敲才休怨天；死贱人、死贱人自骂你！本待要皂腰裙，刚待要蓝包髻，则这的是折挂攀高落得的！（下）。',52,'元曲/yuanqu.json','["呆敲才、呆敲才休怨天；死贱人、死贱人自骂你！本待要皂腰裙，刚待要蓝包髻，则这的是折挂攀高落得的！（下）。"]'),
('yuanqu-28','诈妮子调风月・越调/斗鹌鹑','关汉卿','元','元曲','yuanqu','','[]','短叹长吁，千声万声；捣枕捶床，到三更四更。',58,'元曲/yuanqu.json','["短叹长吁，千声万声；捣枕捶床，到三更四更。", "便似止渴思梅，充饥画饼，因甚顷刻体？则伤我取次成。", "好个个舒心，干支刺没兴。"]'),
('yuanqu-29','诈妮子调风月・紫花儿序','关汉卿','元','元曲','yuanqu','','[]','好轻乞列薄命，热忽刺姻缘，短古取恩情。',91,'元曲/yuanqu.json','["好轻乞列薄命，热忽刺姻缘，短古取恩情。", "（见灯蛾科，云）哎！蛾儿，俺两个有比喻：见一个耍蛾儿来往向烈焰上飞腾，正撞着银灯，拦头送了性命。", "咱两个堪为比并：我为那包譬白身，你为这灯火青荧。"]'),
('yuanqu-30','诈妮子调风月・幺篇','关汉卿','元','元曲','yuanqu','','[]','我把这银灯来指定，引了咱两个魂灵，都是这一点虚名。',74,'元曲/yuanqu.json','["我把这银灯来指定，引了咱两个魂灵，都是这一点虚名。", "怕不百伶百俐，千战千赢，更做道\"能行怎离得影\"？这一场其身不正，怎当那厮大四至铺排，小夫人名称？。"]'),
('yuanqu-31','诈妮子调风月・梨花儿','关汉卿','元','元曲','yuanqu','','[]','是教我软地上吃交，我也不共你争。',117,'元曲/yuanqu.json','["是教我软地上吃交，我也不共你争。", "煞是多劳重，降尊临卑，（云）有劳长者车马，贵脚踏于贱地，小的每多谢承。", "本待麻线道上不和你一处行；（云）你依得我一件事，依得我愿随鞭镫。", "（云）你要我饶你咱，再对星月赌一个誓。", "（云了）（出门了）（正旦唱）。"]'),
('yuanqu-32','诈妮子调风月・紫花儿序','关汉卿','元','元曲','yuanqu','','[]','你把遥天指定，指定那淡月疏星，再说一个海誓山盟；我便收撮了火性，铺撒了人情，忍气吞声，饶过你那亏人不志诚。',77,'元曲/yuanqu.json','["你把遥天指定，指定那淡月疏星，再说一个海誓山盟；我便收撮了火性，铺撒了人情，忍气吞声，饶过你那亏人不志诚。", "赚出门程，（入房科）呼的关上栊门，铺的吹灭残灯。"]'),
('yuanqu-33','诈妮子调风月・小桃红','关汉卿','元','元曲','yuanqu','','[]','燕燕上复传示煞曾经，谁会甚儿女成婚聘？甚的是许出羞、下红定？问这洛阳城，少甚么能言快语官媒证？燕燕怎敢假名托姓？但教我一权为政，情取"火上等冬凌"。',74,'元曲/yuanqu.json','["燕燕上复传示煞曾经，谁会甚儿女成婚聘？甚的是许出羞、下红定？问这洛阳城，少甚么能言快语官媒证？燕燕怎敢假名托姓？但教我一权为政，情取\"火上等冬凌\"。"]'),
('yuanqu-34','诈妮子调风月・调笑令','关汉卿','元','元曲','yuanqu','','[]','这厮短命，没前程，做得个"轻人还自轻"，横死口里栽排定。',57,'元曲/yuanqu.json','["这厮短命，没前程，做得个\"轻人还自轻\"，横死口里栽排定。", "老夫人随邪水性，道我能言快语说合成，我说波娘七代先灵！，。"]'),
('yuanqu-35','诈妮子调风月・圣药王','关汉卿','元','元曲','yuanqu','','[]','然道户厮迎，也合再打听，两门亲便走一遭儿成。',144,'元曲/yuanqu.json','["然道户厮迎，也合再打听，两门亲便走一遭儿成。", "我若到那户庭，见那婢婷，若是那女孩儿言语没实诚，俺这厮强风情。", "（虚下）（外孤上）（旦上，见孤云）夫人使来问小姐亲事，相公许不许，燕燕回去。", "（外孤云了）（闪下）（外旦上）（旦随上，见了，云）特地来问小姐亲事，许不许？回去。", "（外旦许了）（正旦唱）。"]'),
('yuanqu-36','诈妮子调风月・天净沙','关汉卿','元','元曲','yuanqu','','[]','先教人掩扑了我几夜恩情，来这里被他骂得我百节酸疼，我便似□墙贼蝎蜇呼声。',52,'元曲/yuanqu.json','["先教人掩扑了我几夜恩情，来这里被他骂得我百节酸疼，我便似□墙贼蝎蜇呼声。", "空使心作幸，被小夫人引了我魂灵。"]'),
('yuanqu-37','诈妮子调风月・拙鲁速','关汉卿','元','元曲','yuanqu','','[]','终身无簸箕星，指云中雁做羹。',64,'元曲/yuanqu.json','["终身无簸箕星，指云中雁做羹。", "时下且口口声声，战战兢兢，袅袅婷婷，坐坐行行；有一日孤孤另另，冷冷清清，咽咽哽哽，觑着你个拖汉精！。"]'),
('yuanqu-38','诈妮子调风月・收尾','关汉卿','元','元曲','yuanqu','','[]','大刚来"主人有福牙推胜"，不似这调风月媒人背厅。',53,'元曲/yuanqu.json','["大刚来\"主人有福牙推胜\"，不似这调风月媒人背厅。", "说得他美甘甘枕头儿上双成，闪得我薄设设被窝儿里冷！（下）。"]'),
('yuanqu-39','诈妮子调风月・双调/新水令','关汉卿','元','元曲','yuanqu','','[]','双撒敦是部尚书，女婿是世袭千户。',63,'元曲/yuanqu.json','["双撒敦是部尚书，女婿是世袭千户。", "有二百匹金勒马，五十辆画轮车。", "说得他儿女妻夫，似水如鱼；撇得我鳏寡孤独，那的是撮合山养身处？。"]'),
('yuanqu-40','诈妮子调风月・驻马听','关汉卿','元','元曲','yuanqu','','[]','官人石碾连珠，满腰背无瑕玉免鹘；夫人每是依时按序，细搀绒全套绣衣服。',70,'元曲/yuanqu.json','["官人石碾连珠，满腰背无瑕玉免鹘；夫人每是依时按序，细搀绒全套绣衣服。", "包髻是缨络大真珠，额花是秋色玲珑玉。", "悠悠的品着鹧鸪，雁行般但举手都能舞。"]'),
('yuanqu-41','诈妮子调风月・甜水令','关汉卿','元','元曲','yuanqu','','[]','姐姐骨甜肉净，堪描堪塑。',40,'元曲/yuanqu.json','["姐姐骨甜肉净，堪描堪塑。", "生得肌肤似凝酥。", "从小里梅香、嬷嬷抬举，问燕燕梳裹何如？。"]'),
('yuanqu-42','诈妮子调风月・水仙子','关汉卿','元','元曲','yuanqu','','[]','推那领系眼落处，采揪住那系腰行行掐胯骨。',75,'元曲/yuanqu.json','["推那领系眼落处，采揪住那系腰行行掐胯骨。", "我这般拈拈掐掐有甚难当处？想我那声冤不得苦痛处。", "你不合先发头怒；你若无言语，怎敢将你觑付，你则索做使长、郎主。"]'),
('yuanqu-43','诈妮子调风月・殿前欢','关汉卿','元','元曲','yuanqu','','[]','俺千户跨龙驹，称得上的敢望七香车。',64,'元曲/yuanqu.json','["俺千户跨龙驹，称得上的敢望七香车。", "愿结同心结，永挂合欢树。", "蛮凤娇雏，连理枝比目鱼。", "千载相完聚，花发无风雨。", "头白相守，眼黑处全无。"]'),
('yuanqu-44','诈妮子调风月・乔牌儿','关汉卿','元','元曲','yuanqu','','[]','勘婚处恰岁数，出嫁后有衣禄。',28,'元曲/yuanqu.json','["勘婚处恰岁数，出嫁后有衣禄。", "若言招女婿，下财钱将娶过去。"]'),
('yuanqu-45','诈妮子调风月・挂玉钩','关汉卿','元','元曲','yuanqu','','[]','是个破败家私铁扫帚，没些儿发旺夫家处，可更绝子嗣、妨公婆、克丈夫，脸上承泪靥无重数。',63,'元曲/yuanqu.json','["是个破败家私铁扫帚，没些儿发旺夫家处，可更绝子嗣、妨公婆、克丈夫，脸上承泪靥无重数。", "今年见吊客临，丧门聚；反阴覆阴，半载其余。"]'),
('yuanqu-46','诈妮子调风月・落梅风','关汉卿','元','元曲','yuanqu','','[]','据着生的年月，演的岁数，不是个义夫节妇，休想得五男并二女，死得教灭门绝户！（夫人云了）（旦跪唱）。',49,'元曲/yuanqu.json','["据着生的年月，演的岁数，不是个义夫节妇，休想得五男并二女，死得教灭门绝户！（夫人云了）（旦跪唱）。"]'),
('yuanqu-47','诈妮子调风月・雁儿落','关汉卿','元','元曲','yuanqu','','[]','燕燕那书房中伏侍处，许第二个夫人做。',34,'元曲/yuanqu.json','["燕燕那书房中伏侍处，许第二个夫人做。", "他须是人身人面皮，人口人言语！。"]'),
('yuanqu-48','诈妮子调风月・得胜令','关汉卿','元','元曲','yuanqu','','[]','到如今总是彻梢虚，燕燕不是石头镌、铁头做；教我死临侵身无措，错支刺心受苦。',79,'元曲/yuanqu.json','["到如今总是彻梢虚，燕燕不是石头镌、铁头做；教我死临侵身无措，错支刺心受苦。", "（夫人云了）（正旦唱）瘫痪着身躯，教我两下里难停住；气夯破胸脯，教燕燕两下里没是处。"]'),
('yuanqu-49','诈妮子调风月・阿古令','关汉卿','元','元曲','yuanqu','','[]','满盏内盈盈绿醑，子合当作婢为奴。',52,'元曲/yuanqu.json','["满盏内盈盈绿醑，子合当作婢为奴。", "谢相公、夫人抬举，怎敢做三妻两妇？子得和丈夫一处对舞，便是燕燕花生满路。"]'),
('yuanqu-50','正宫・白鹤子（四首）','关汉卿','元','元曲','yuanqu','','[]','四时春富贵，万物酒风流。',113,'元曲/yuanqu.json','["四时春富贵，万物酒风流。", "澄澄水如蓝，灼灼花如绣。", "（之一）花边停骏马，柳外缆轻舟。", "湖内画船交，湖上骅骝骤。", "（之二）鸟啼花影里，人立粉墙头。", "春意两丝牵，秋水双波溜。", "（之三）香焚金鸭鼎，闲傍小红楼。", "月在柳梢头，人约黄昏后。", "（之四）。"]'),
('yuanqu-51','南吕・四块玉别情','关汉卿','元','元曲','yuanqu','','[]','自送别，心难舍，一点相思几时绝？凭阑袖拂杨花雪。',37,'元曲/yuanqu.json','["自送别，心难舍，一点相思几时绝？凭阑袖拂杨花雪。", "溪又斜，山又遮，人去也！。"]'),
('yuanqu-52','南吕・四块玉闲适（四首）','关汉卿','元','元曲','yuanqu','','[]','适意行，安心坐，渴时饮饥时餐醉时歌，困来时就向莎茵卧。',175,'元曲/yuanqu.json','["适意行，安心坐，渴时饮饥时餐醉时歌，困来时就向莎茵卧。", "日月长，天地阔，闲快活！（之一）旧酒投，新醅泼，老瓦盆边笑呵呵，共山僧野叟闲吟和。", "他出一对鸡，我出一个鹅，闲快活！（之二）意马多，心猿锁，跳出红尘恶风波，槐阴午梦谁惊破？离了利名场，钻入安乐窝，闲快活！（之三）南亩耕，东山卧，世态人情经历多，闲将往事思量过。", "贤的是他，愚的是我，争甚么！（之四）。"]'),
('yuanqu-53','中吕・朝天子书所见','关汉卿','元','元曲','yuanqu','','[]','鬓鸦，脸霞，屈杀将陪嫁。',53,'元曲/yuanqu.json','["鬓鸦，脸霞，屈杀将陪嫁。", "规模全是大人家，不在红娘下。", "笑眼偷瞧，文谈回话，真如解语花。", "若咱得他，倒了葡萄架。"]'),
('yuanqu-54','商调・梧叶儿别情','关汉卿','元','元曲','yuanqu','','[]','别离易，相见难，何处锁雕鞍？春将去，人未还。',34,'元曲/yuanqu.json','["别离易，相见难，何处锁雕鞍？春将去，人未还。", "这其间，殃及杀愁眉泪眼。"]'),
('yuanqu-55','双调・大德歌（四首）春','关汉卿','元','元曲','yuanqu','','[]','子规啼，不如归，道是春归人未归。',194,'元曲/yuanqu.json','["子规啼，不如归，道是春归人未归。", "几日添憔悴，虚飘飘柳絮飞。", "一春鱼雁无消息，则见双燕斗衔泥。", "夏俏冤家，在天涯，偏那里绿杨堪系马？困坐南窗下，数对清风想念他。", "蛾眉淡了教谁画？瘦岩岩羞带石榴花。", "秋风飘飘，雨潇潇，便做陈抟睡不着。", "懊恼伤怀抱，扑簌簌泪点抛。", "秋蝉儿噪罢寒蛩儿叫，淅零零细雨打芭蕉。", "冬雪纷纷，掩重门，不由人不断魂，瘦损江梅韵。", "那里是清江江上村？香闺里冷落谁瞅问？好一个憔悴的凭阑人！。"]'),
('yuanqu-56','双调・大德歌（六首）','关汉卿','元','元曲','yuanqu','','[]','粉墙低，景凄凄，正是那西厢月上时。',319,'元曲/yuanqu.json','["粉墙低，景凄凄，正是那西厢月上时。", "会得琴中意，我是个香闺里钟子期。", "好教人暗想张君瑞，敢则是爱月夜眠迟。", "（之一）绿杨堤，画船儿，正撞着一帆风赶上水。", "冯魁吃的醺醺醉，怎想着金山寺壁上诗。", "醒来不见多姝丽，冷清清空载月明归。", "（之二）郑元和，受寂寞，道是你无钱怎奈何？哥哥家缘破，谁着你摇铜铃唱换歌。", "因打亚仙门前过，恰便是司马泪痕多。", "（之三）谢家村，赏芳春，疑怪他桃花冷笑人。", "着谁传芳信，强题诗也断魂。", "花阴下等待无人问，则听得黄犬吠柴门。", "（之四）雪粉华，舞梨花，再不见烟村四五家。", "密洒堪图画，看疏林噪晚鸦。", "黄芦掩映清江下，斜缆着钓鱼航模。", "（之五）吹一个，弹一个，唱新行大德歌。", "快活休张罗，想人生能几何？十分淡薄随缘过，得磨陀处且磨陀。", "（之六）套数。"]'),
('yuanqu-57','黄钟・侍香金童','关汉卿','元','元曲','yuanqu','','[]','春闺院宇，柳絮飘香雪。',37,'元曲/yuanqu.json','["春闺院宇，柳絮飘香雪。", "帘幕轻寒雨乍歇，东风落花迷粉蝶。", "芍药初开，海棠才谢。"]'),
('yuanqu-58','幺・柔肠脉脉，新愁千万叠。偶记年前人乍别，秦台玉萧声断绝。雁底关','关汉卿','元','元曲','yuanqu','','[]','河，马头明月。',7,'元曲/yuanqu.json','["河，马头明月。"]'),
('yuanqu-59','降黄龙衮・鳞鸿无个，锦笺慵写。腕松金，肌削玉，罗衣宽彻。泪痕淹破，','关汉卿','元','元曲','yuanqu','','[]','胭脂双颊。',15,'元曲/yuanqu.json','["胭脂双颊。", "宝鉴愁临，翠钿羞贴。"]'),
('yuanqu-60','幺・等闲辜负，好天良夜。玉炉中，银台上，香消烛灭。凤帏冷落，鸳衾','关汉卿','元','元曲','yuanqu','','[]','虚设，玉笋频搓，绣鞋重扌颠。',14,'元曲/yuanqu.json','["虚设，玉笋频搓，绣鞋重扌颠。"]'),
('yuanqu-61','幺・铜壶玉漏催凄切，正更阑人静也。金闺潇洒转伤嗟，莲步轻移呼侍妾：','关汉卿','元','元曲','yuanqu','','[]','“把香桌儿安排打快些。',11,'元曲/yuanqu.json','["“把香桌儿安排打快些。"]'),
('yuanqu-62','仙吕・翠裙腰闺怨','关汉卿','元','元曲','yuanqu','','[]','晓来雨过山横秀，野水涨汀洲。',34,'元曲/yuanqu.json','["晓来雨过山横秀，野水涨汀洲。", "阑干倚遍空回首。", "下危楼，一天风物暮伤秋。"]'),
('yuanqu-63','六幺遍・乍凉时候，西风透。碧梧脱叶，余暑才收。香生凤口，帘垂玉钩，','关汉卿','元','元曲','yuanqu','','[]','小院深闲清昼。',19,'元曲/yuanqu.json','["小院深闲清昼。", "清幽，听声声蝉噪柳梢头。"]'),
('yuanqu-64','寄生草・为甚忧，为甚愁？为萧郎一去经今久。玉台宝鉴生尘垢，绿窗冷','关汉卿','元','元曲','yuanqu','','[]','落闲针锈。',24,'元曲/yuanqu.json','["落闲针锈。", "岂知人玉腕钏儿松，岂知人两叶眉儿皱！。"]'),
('yuanqu-65','后庭花煞・掩袖暗含羞，开樽越酿愁。闷把苔墙画，慵将锦字修。最风流，','关汉卿','元','元曲','yuanqu','','[]','真真恩爱，等闲分付等闲休。',13,'元曲/yuanqu.json','["真真恩爱，等闲分付等闲休。"]'),
('yuanqu-66','南吕・一枝花赠朱帘秀','关汉卿','元','元曲','yuanqu','','[]','轻裁虾万须，巧织珠千串；金钩光错落，绣带舞蹁跹。',62,'元曲/yuanqu.json','["轻裁虾万须，巧织珠千串；金钩光错落，绣带舞蹁跹。", "似雾非烟，妆点就深闺院，不许那等闲人取次展。", "摇四壁翡翠浓阴，射万瓦琉璃色浅。"]'),
('yuanqu-67','梁州・富贵似侯家紫帐，风流如谢府红莲，锁春愁不放双飞燕。绮窗相近，','关汉卿','元','元曲','yuanqu','','[]','翠户相连，雕栊相映，绣幕相牵。',99,'元曲/yuanqu.json','["翠户相连，雕栊相映，绣幕相牵。", "拂苔痕满砌榆钱，惹杨花飞点如锦。", "愁的是抹回廊暮雨萧萧，恨的是筛曲槛西风剪剪，爱的是透长门夜月娟娟。", "凌波殿前，碧玲珑掩映湘妃面，没福怎能够见？十里扬州风物妍，出落着神仙。"]'),
('yuanqu-68','南吕・一枝花杭州景','关汉卿','元','元曲','yuanqu','','[]','普天下锦绣乡，寰海内风流地。',63,'元曲/yuanqu.json','["普天下锦绣乡，寰海内风流地。", "大元朝新附国，亡宋家旧华夷。", "水秀山奇，一到处堪游戏。", "这答儿忒富贵，满城中绣幕风帘，一哄地人烟辏集。"]'),
('yuanqu-69','梁州・百十里街衢整齐，万余家楼阁参差，并无半答儿闲田地。松轩竹径，','关汉卿','元','元曲','yuanqu','','[]','药圃花蹊，茶园稻陌，竹坞梅溪。',100,'元曲/yuanqu.json','["药圃花蹊，茶园稻陌，竹坞梅溪。", "一陀儿一句诗题，行一步扇面屏帏。", "西盐场便似一带琼瑶，吴山色千叠悲翠。", "兀良，望钱塘江万顷玻璃。", "更有清溪绿水，画船儿来往闲游戏。", "浙江亭紧相对，相对着险岭高峰长怪石，堪羡堪题。"]'),
('yuanqu-70','尾・家家掩映渠流水，楼阁峥嵘出翠微。遥望西湖暮山势，看了这壁，觑','关汉卿','元','元曲','yuanqu','','[]','了那壁，纵有丹青下不得笔。',13,'元曲/yuanqu.json','["了那壁，纵有丹青下不得笔。"]'),
('yuanqu-71','南吕・一枝花不伏老','关汉卿','元','元曲','yuanqu','','[]','攀出墙朵朵花，折临路枝枝柳。',65,'元曲/yuanqu.json','["攀出墙朵朵花，折临路枝枝柳。", "花攀红蕊嫩，柳折翠条柔，浪子风流。", "凭着我折柳攀花手，直煞得花残柳败休。", "半生来折柳攀花，一世里眠花卧柳。"]'),
('yuanqu-72','梁州・我是个普天下郎君领袖，盖世界浪子班头。愿朱颜不改常依旧，花','关汉卿','元','元曲','yuanqu','','[]','中消遣，酒内忘忧。',131,'元曲/yuanqu.json','["中消遣，酒内忘忧。", "分茶扌颠竹，打马藏阄；通五音六律滑熟，甚闲愁到我心头！伴的是银筝女银台前理银筝笑倚银屏，伴的是玉天仙携玉手并玉肩同登玉楼，伴的是金钗客歌《金缕》捧金樽满泛金瓯。", "你道我老也，暂休。", "占排场风月功名首，更玲珑又剔透。", "我是个锦阵花营都帅头，曾玩府游州。"]'),
('yuanqu-73','隔尾・子弟每是个茅草冈、沙土窝初生的兔羔儿乍向围场上走，我是个经','关汉卿','元','元曲','yuanqu','','[]','笼罩、受索网苍翎毛老野鸡踏踏的阵马儿熟。',59,'元曲/yuanqu.json','["笼罩、受索网苍翎毛老野鸡踏踏的阵马儿熟。", "经了些窝弓冷箭蜡枪头，不曾落人后。", "恰不道“人到中年万事休”，我怎肯虚度了春秋。"]'),
('yuanqu-74','尾・我是个蒸不烂、煮不熟、捶不匾、炒不爆响当当一粒铜豌豆，恁子弟','关汉卿','元','元曲','yuanqu','','[]','每谁教你钻入他锄不断、斫不下、解不开、顿不脱慢腾腾千层锦套头。',184,'元曲/yuanqu.json','["每谁教你钻入他锄不断、斫不下、解不开、顿不脱慢腾腾千层锦套头。", "我玩的是梁园月，饮的是东京酒，赏的是洛阳花，攀的是章台柳。", "我也会围棋、会蹴リ、会打围、会插科、会歌舞、会吹弹、会咽作、会吟诗、会双陆。", "你便是落了我牙、歪了我嘴、瘸了我腿、折了我手，天赐与我这几般儿歹症候，尚兀自不肯休。", "则除是阎王亲自唤，神鬼自来勾，三魂归地府，七魂丧冥幽，天那，那其间才不向烟花路儿上走！。"]'),
('yuanqu-75','中吕・古调石榴花闺思','关汉卿','元','元曲','yuanqu','','[]','颠狂柳絮扑帘飞，绿暗红稀。',62,'元曲/yuanqu.json','["颠狂柳絮扑帘飞，绿暗红稀。", "垂杨影里杜鹃啼，一弄儿断送了春归。", "牡丹亭畔人寂静，恼芳心似醉如痴。", "恹恹为他成病也，松金钏，褪罗衣。"]'),
('yuanqu-76','酥枣儿・一自相逢，将人来萦系。樽前席上，眼约心期。比及道是配合了，','关汉卿','元','元曲','yuanqu','','[]','受了些闲是闲非。',24,'元曲/yuanqu.json','["受了些闲是闲非。", "咱各办着个坚心，要拨个终缘之计。"]'),
('yuanqu-77','鲍老儿・当初指望成家计，谁想琼簪碎；当初指望无抛弃，谁想银瓶坠。','关汉卿','元','元曲','yuanqu','','[]','烦烦恼恼，哀哀怨怨，哭哭啼啼，回黄倒皂，长吁短叹，自跌自堆。',30,'元曲/yuanqu.json','["烦烦恼恼，哀哀怨怨，哭哭啼啼，回黄倒皂，长吁短叹，自跌自堆。"]'),
('yuanqu-78','墙头花・守香闺，镇日情如醉，闷懊恼离愁空教我诉与谁？愁闻的是紫燕','关汉卿','元','元曲','yuanqu','','[]','关关，倦听的是黄莺呖呖。',12,'元曲/yuanqu.json','["关关，倦听的是黄莺呖呖。"]'),
('yuanqu-79','卖花声煞・愁山闷海不许当敌，好教我无一个百刂划，耐心儿多陪下些凄','关汉卿','元','元曲','yuanqu','','[]','惶泪。',26,'元曲/yuanqu.json','["惶泪。", "呼侍婢将绣帘低放，把重门深闭，怕莺花笑人憔悴。"]'),
('yuanqu-80','幺・天付两风流，翻成南北悠悠，落花流水人何处？相思一点，离愁几许，','关汉卿','元','元曲','yuanqu','','[]','撮上心头。',5,'元曲/yuanqu.json','["撮上心头。"]'),
('yuanqu-81','荼コ香・记得初相守，偶尔间因循成就，美满效绸缪。花朝月夜同宴赏，','关汉卿','元','元曲','yuanqu','','[]','佳节须酬，到今一旦休。',35,'元曲/yuanqu.json','["佳节须酬，到今一旦休。", "常言道好事天悭，美姻缘他娘间阻，生拆散鸾交凤友。"]'),
('yuanqu-82','幺・坐想行思，伤怀感旧，各辜负了星前月下深深咒。愿不损，愁不煞，','关汉卿','元','元曲','yuanqu','','[]','神天还佑。',23,'元曲/yuanqu.json','["神天还佑。", "他有日不测相逢，话别离情取一场消瘦。"]'),
('yuanqu-83','好观音煞・与怪友狂朋寻花柳，时复间和哄消愁。对着浪蕊浮花懒回首，','关汉卿','元','元曲','yuanqu','','[]','怏怏归来，原不饮杯中酒。',12,'元曲/yuanqu.json','["怏怏归来，原不饮杯中酒。"]'),
('yuanqu-85','大石调・青杏子骋怀','关汉卿','元','元曲','yuanqu','','[]','花月酒家楼，可追欢亦可悲秋。',37,'元曲/yuanqu.json','["花月酒家楼，可追欢亦可悲秋。", "悲欢聚散为常事，明眸皓齿，歌莺舞燕，各逞温柔。"]'),
('yuanqu-86','幺・人俊惜风流，欠前生酒病花愁。尚还不彻相思债，携云挈雨，批风切','关汉卿','元','元曲','yuanqu','','[]','月，到处绸缪。',7,'元曲/yuanqu.json','["月，到处绸缪。"]'),
('yuanqu-87','催拍子・爱共寝花间锦鸠，恨孤眠水上白鸥。月宵花昼，大筵排回雪韦娘，','关汉卿','元','元曲','yuanqu','','[]','小酌会窃香韩寿。',81,'元曲/yuanqu.json','["小酌会窃香韩寿。", "举觞红袖，玉纤横管，银甲调筝，酒令诗筹。", "曲成诗就，韵协声律，情动魂消，腹稿冥搜，美恩当受。", "水仙山鬼，月妹花妖，如还得遇，不许干休，会埋伏未尝泄漏。"]'),
('yuanqu-88','幺・群芳会首，繁英故友，梦回时绿肥红瘦。荣华过可见蔬薄，财物广始','关汉卿','元','元曲','yuanqu','','[]','知亲厚。',77,'元曲/yuanqu.json','["知亲厚。", "慕新思旧，簪遗佩解，镜破钗分，蜂妒蝶羞。", "恶缘难救，痼疾常发，业贯将盈，努力呈头。", "冷餐重馏，口刀舌剑，吻槊唇枪，独攻决胜，混战无忧，不到得落人奸彀。"]'),
('yuanqu-90','天净沙・平生肥马轻裘，何须锦带吴钩？百岁光阴转首，休闲生受，叹功','关汉卿','元','元曲','yuanqu','','[]','名似水上浮沤。',7,'元曲/yuanqu.json','["名似水上浮沤。"]'),
('yuanqu-91','寨儿冷・得自由，莫刚求。茶余饭饱邀故友，谢馆秦楼，散闷消愁，惟蹴','关汉卿','元','元曲','yuanqu','','[]','リ最风流。',46,'元曲/yuanqu.json','["リ最风流。", "演习得踢打温柔，施逞得解数滑熟。", "引脚蹑龙斩眼，担枪拐凤摇头。", "一左一右，折叠鹘胜游。"]'),
('yuanqu-92','尾・锦缠腕、叶底桃、鸳鸯叩，入脚面带黄河逆流。斗白打赛官场，三场','关汉卿','元','元曲','yuanqu','','[]','儿尽皆有。',5,'元曲/yuanqu.json','["儿尽皆有。"]'),
('yuanqu-93','越调・斗鹌鹑又','关汉卿','元','元曲','yuanqu','','[]','蹴リ场中，鸣珂巷里，南北驰名，寰中可意。',63,'元曲/yuanqu.json','["蹴リ场中，鸣珂巷里，南北驰名，寰中可意。", "夹缝堪夸，抛声尽喜。", "那换活，煞整齐。", "款侧金莲，微那玉体。", "唐裙轻荡，绣带斜飘，舞袖低垂。"]'),
('yuanqu-94','小桃红・装跷委实用心机，不枉了夸强会，女辈丛中最为贵。煞曾习，沾','关汉卿','元','元曲','yuanqu','','[]','身那取着田地。',20,'元曲/yuanqu.json','["身那取着田地。", "赶起了白踢，诸余里快收拾。"]'),
('yuanqu-95','秃厮儿・粉汗湿珍珠乱滴，宝髻偏鸦玉斜堆。虚蹬落实拾蹑起，侧身动，','关汉卿','元','元曲','yuanqu','','[]','柳腰脆，丸惜。',7,'元曲/yuanqu.json','["柳腰脆，丸惜。"]'),
('yuanqu-96','圣药王・甚旖旎，解数儿希，左盘右折煞曾习。甚整齐，省气力，旁行侧','关汉卿','元','元曲','yuanqu','','[]','脚步频移，来往似粉蝶儿飞。',13,'元曲/yuanqu.json','["脚步频移，来往似粉蝶儿飞。"]'),
('yuanqu-97','尾・不离了花前柳影闲田地，斗白打官场小踢。竿网下世无双，全场儿占','关汉卿','元','元曲','yuanqu','','[]','了第一。',4,'元曲/yuanqu.json','["了第一。"]'),
('yuanqu-98','双调・新水令','关汉卿','元','元曲','yuanqu','','[]','楚台云雨会巫峡，赴昨宵约来的期话。',41,'元曲/yuanqu.json','["楚台云雨会巫峡，赴昨宵约来的期话。", "楼头栖燕子，庭院已闻鸦，料想他家，收针指晚妆罢。"]'),
('yuanqu-99','乔牌儿・款将花径踏，独立在纱窗下，颤钦钦把不定心头怕。不敢将小名','关汉卿','元','元曲','yuanqu','','[]','呼，咱则索等候他。',9,'元曲/yuanqu.json','["呼，咱则索等候他。"]'),
('yuanqu-100','挂搭钩・等候多时不见他，这的是约下佳期话，莫不是贪睡人儿忘了那？','关汉卿','元','元曲','yuanqu','','[]','伏冢在蓝桥下。',28,'元曲/yuanqu.json','["伏冢在蓝桥下。", "意懊恼却待将他骂，听得呀的门开，蓦见如花。"]'),
('yuanqu-101','豆叶黄・髻挽乌云，蝉鬓堆鸦，粉腻酥胸，脸衬红霞；袅娜腰肢更喜恰，','关汉卿','元','元曲','yuanqu','','[]','堪讲堪夸。',21,'元曲/yuanqu.json','["堪讲堪夸。", "比月里嫦娥，媚媚孜孜，那更撑达。"]'),
('yuanqu-102','梅花酒・两情浓，兴转佳。地权为床榻，月高烧银蜡。夜深沉，人静悄，','关汉卿','元','元曲','yuanqu','','[]','低低的问如花终是个女儿家。',13,'元曲/yuanqu.json','["低低的问如花终是个女儿家。"]'),
('yuanqu-103','收江南・好风吹绽牡丹花，半合儿揉损绛裙纱。冷丁丁舌尖上送香茶，都','关汉卿','元','元曲','yuanqu','','[]','不到半霎，森森一向遍身麻。',13,'元曲/yuanqu.json','["不到半霎，森森一向遍身麻。"]'),
('yuanqu-104','尾・整乌云欲把金莲さ，纽回身再说些儿话：“你明夜个早些儿来，我专','关汉卿','元','元曲','yuanqu','','[]','听着纱窗外芭蕉叶儿上打。',12,'元曲/yuanqu.json','["听着纱窗外芭蕉叶儿上打。"]'),
('yuanqu-105','双调・新水令','关汉卿','元','元曲','yuanqu','','[]','闲争夺鼎沸了丽春园，欠排场不堪久恋。',41,'元曲/yuanqu.json','["闲争夺鼎沸了丽春园，欠排场不堪久恋。", "时间相敬爱，端的怎团圆？白没事教人笑，惹人怨。"]'),
('yuanqu-106','驻马听・锦阵里争先，紧卷旗幡不再展；花营中挑战，劳拴意马与心猿。','关汉卿','元','元曲','yuanqu','','[]','降书执写纳君前，唇枪舌剑难施展。',31,'元曲/yuanqu.json','["降书执写纳君前，唇枪舌剑难施展。", "参破脱空禅，早抽头索甚他人劝。"]'),
('yuanqu-107','天仙子・从今后，识破野狐涎。红粉无情，灾星不现。村酒酽野花浓，再','关汉卿','元','元曲','yuanqu','','[]','不粘拈。',17,'元曲/yuanqu.json','["不粘拈。", "当时话儿无应显，好事天悭。"]'),
('yuanqu-109','双调・新水令','关汉卿','元','元曲','yuanqu','','[]','搅闲风吹散楚台云，天对付满怀愁闷。',47,'元曲/yuanqu.json','["搅闲风吹散楚台云，天对付满怀愁闷。", "您那里欢娱嫌夜短，俺寂寞恨长更。", "恰似线断风筝，绝鱼雁杳音信。"]'),
('yuanqu-110','驻马听・多绪多情，病身躯憔悴损；闲愁闲闷，将柳带结同心。瘦岩岩宽','关汉卿','元','元曲','yuanqu','','[]','褪了绛绡裙，羞答答恐怕他邻姬问。',29,'元曲/yuanqu.json','["褪了绛绡裙，羞答答恐怕他邻姬问。", "若道伤春，今年更比年时甚。"]'),
('yuanqu-111','幺・早是我愁怀闷哽，更那堪四扇帏屏。遣人愁，添人恨，无端怨煞丹青。','关汉卿','元','元曲','yuanqu','','[]','画得来双双厮配定，做得伤情对景。',16,'元曲/yuanqu.json','["画得来双双厮配定，做得伤情对景。"]'),
('yuanqu-112','天仙子・一扇儿画着双通叔，和苏氏到豫章城；一扇儿是司马文君；一扇','关汉卿','元','元曲','yuanqu','','[]','儿是王魁桂英。',39,'元曲/yuanqu.json','["儿是王魁桂英。", "画的来厮顾盼厮温存，比各青春。", "这一扇儿比他每情更深，是君瑞莺莺。"]'),
('yuanqu-113','随煞・您团圆偏俺孤另，拥被和衣坐等。听鼓打四更过，搭伏定鸳鸯枕头','关汉卿','元','元曲','yuanqu','','[]','儿等。',3,'元曲/yuanqu.json','["儿等。"]'),
('yuanqu-114','双调・新水令','关汉卿','元','元曲','yuanqu','','[]','寨儿中风月煞经谙，收心也合搠淹。',44,'元曲/yuanqu.json','["寨儿中风月煞经谙，收心也合搠淹。", "再不缠头戴蜀锦，沽酒典春衫。", "心如柳絮粘泥，狂风过怎摇撼。"]'),
('yuanqu-116','夜行船・又引起往前风月胆，今番做得尴。且休说久远当来，奈何时暂，','关汉卿','元','元曲','yuanqu','','[]','这些时陡羞惨。',7,'元曲/yuanqu.json','["这些时陡羞惨。"]'),
('yuanqu-117','天仙子・咱非参，坏怪斗来搀。怎肯袄庙火绝，蓝桥水淹。难掩盖泼风声，','关汉卿','元','元曲','yuanqu','','[]','被各俱耽。',22,'元曲/yuanqu.json','["被各俱耽。", "怎只恁两下里阻隔情分减，面北眉南。"]'),
('yuanqu-118','离亭宴煞・你休起风波剁断渔舟缆，得团圆摔破青铜鉴。冤家行再三，再','关汉卿','元','元曲','yuanqu','','[]','三嘱付勤相探。',43,'元曲/yuanqu.json','["三嘱付勤相探。", "常将好事贪，却休教花星暗。", "万一问休将人倒赚，眼挫了可憎才，心疼煞志诚俺。"]'),
('yuanqu-119','双调・新水令','关汉卿','元','元曲','yuanqu','','[]','凤凰台上忆吹箫，似钱塘梦魂初觉。',36,'元曲/yuanqu.json','["凤凰台上忆吹箫，似钱塘梦魂初觉。", "花月约，凤鸾交，半世疏狂，总做了一场懊。"]'),
('yuanqu-120','驻马听・黄诏奢豪，桑木剑熬乏古定刀；双郎穷薄，纸糊锹撅了点刚锹。','关汉卿','元','元曲','yuanqu','','[]','怕不待争锋取债恋多娇，又索书名画字寻人保。',33,'元曲/yuanqu.json','["怕不待争锋取债恋多娇，又索书名画字寻人保。", "枉徒劳，供钱买笑教人笑。"]'),
('yuanqu-121','落梅风・姨夫闹，咱便晓，君子不夺人之好。他揽定磨杆儿夸俏，推不动','关汉卿','元','元曲','yuanqu','','[]','磨杆上自吊。',6,'元曲/yuanqu.json','["磨杆上自吊。"]'),
('yuanqu-122','步步娇・积趱下三十两通行鸦青钞，买取个大笠子粗麻罩。妆甚腰，眼落','关汉卿','元','元曲','yuanqu','','[]','处和他契丹交。',20,'元曲/yuanqu.json','["处和他契丹交。", "虽是不风骚，不到得着圈套。"]'),
('yuanqu-123','甜水令・佳人有意郎君俏，郎君没钞莺花恼。如今等惜花人弄巧，指不过','关汉卿','元','元曲','yuanqu','','[]','美话儿排，虚科儿套，实心儿少。',49,'元曲/yuanqu.json','["美话儿排，虚科儿套，实心儿少。", "想着月下情，星前约，是则是花木瓜儿看好。", "李亚仙负心疾，郑元和下番早。"]'),
('yuanqu-124','庆东原・或向幽窗下，或向曲槛前，春纤相对摇纨扇。闲凭着玉肩，双歌','关汉卿','元','元曲','yuanqu','','[]','《采莲》，斗抚冰弦。',22,'元曲/yuanqu.json','["《采莲》，斗抚冰弦。", "遂却少年心，称了于飞愿。"]'),
('yuanqu-125','早乡词・九秋天，三径边，绽黄花遍撒金钱。露春纤把花笑捻，捧金杯酒','关汉卿','元','元曲','yuanqu','','[]','频劝，畅好是风流如五柳庄前。',14,'元曲/yuanqu.json','["频劝，畅好是风流如五柳庄前。"]'),
('yuanqu-126','挂打沽・浅浅江梅驿使传，乱剪碎鹅毛片。旋剖温橙列着玳筵，玉液着金','关汉卿','元','元曲','yuanqu','','[]','瓶旋。',23,'元曲/yuanqu.json','["瓶旋。", "酒晕红，新妆面，人道是穷冬，我道是虚言。"]'),
('yuanqu-127','石竹子・夜夜嬉游赛上元，朝朝宴乐赏禁烟。密爱幽欢不能恋，无奈被名','关汉卿','元','元曲','yuanqu','','[]','缰利锁牵。',5,'元曲/yuanqu.json','["缰利锁牵。"]'),
('yuanqu-130','醉也摩挲・真个索去也么天，真个索去也么天！再要团圆，动是经年，思','关汉卿','元','元曲','yuanqu','','[]','量杀俺也么天！。',8,'元曲/yuanqu.json','["量杀俺也么天！。"]'),
('yuanqu-131','相公爱・晚宿在孤村闷怎生眠，伴人离愁月当轩。月圆，人几时圆？不似','关汉卿','元','元曲','yuanqu','','[]','他南楼上斗婵娟。',8,'元曲/yuanqu.json','["他南楼上斗婵娟。"]'),
('yuanqu-132','胡十八・天配合俏姻眷，分拆开并头莲。思量席上与樽前，天生的自然，','关汉卿','元','元曲','yuanqu','','[]','那些儿体面。',20,'元曲/yuanqu.json','["那些儿体面。", "也是俺心上有，常常的梦中见。"]'),
('yuanqu-133','一锭银・心友每相邀列着管弦，却子待欢解动凄然。十分酒十分悲怨，却','关汉卿','元','元曲','yuanqu','','[]','不道怎生般消遣。',8,'元曲/yuanqu.json','["不道怎生般消遣。"]'),
('yuanqu-135','不拜门・酒入愁肠闷怎生言，疏竹萧萧西风战。如年，如年似长夜天，正','关汉卿','元','元曲','yuanqu','','[]','是恰黄昏庭院。',7,'元曲/yuanqu.json','["是恰黄昏庭院。"]'),
('yuanqu-136','金盏子・咱无缘，风流十全。尽可怜，芙蓉面。腕松着金钏，鬓贴着翠钿，','关汉卿','元','元曲','yuanqu','','[]','脸朵着秋莲。',22,'元曲/yuanqu.json','["脸朵着秋莲。", "眼去眉来相思恋，春山摇，秋波转。"]'),
('yuanqu-137','也不罗・只听得乐声喧，列着华筵，聚集诸亲眷。首先一盏拦门劝，走马','关汉卿','元','元曲','yuanqu','','[]','身劳倦。',4,'元曲/yuanqu.json','["身劳倦。"]'),
('yuanqu-138','喜人心・人丛里遥见，半遮着罗扇，可喜的风流业冤，两叶眉儿未展。百','关汉卿','元','元曲','yuanqu','','[]','般的陪告，一创的求和，只管里熬煎。',33,'元曲/yuanqu.json','["般的陪告，一创的求和，只管里熬煎。", "他越将个庞儿变，咱百般的难分辨。"]'),
('yuanqu-139','风流体・胡猜咱，胡猜咱居帝辇，和别人、和别人相留恋。上放着、上放','关汉卿','元','元曲','yuanqu','','[]','着赐福天，你不知、你不知神明见。',16,'元曲/yuanqu.json','["着赐福天，你不知、你不知神明见。"]'),
('yuanqu-140','忽都白・我半载来孤眠，信口胡言，枉了把我冤也么冤。打听的真实，有','关汉卿','元','元曲','yuanqu','','[]','人曾见，母亲跟前，恁儿情愿，一任当刑宪，死而心无怨。',26,'元曲/yuanqu.json','["人曾见，母亲跟前，恁儿情愿，一任当刑宪，死而心无怨。"]'),
('yuanqu-141','唐兀歹・不付能告求的绣帏里头眠，痛惜轻怜。斩眼不觉得绿窗儿外月明','关汉卿','元','元曲','yuanqu','','[]','却又早转，畅好是疾明也么天！。',15,'元曲/yuanqu.json','["却又早转，畅好是疾明也么天！。"]'),
('yuanqu-142','尾・腰肢困摆垂杨软，舌尖笑吐丁香喘。绣帐里无人，并枕低言。畅道美','关汉卿','元','元曲','yuanqu','','[]','满姻缘，风流缱绻，天若肯为人，为人是今生愿。',40,'元曲/yuanqu.json','["满姻缘，风流缱绻，天若肯为人，为人是今生愿。", "尽老同眠也者，也强如雁底关河路儿远。"]'),
('yuanqu-143','双调・乔牌儿','关汉卿','元','元曲','yuanqu','','[]','世情推物理，人生贵适意。',29,'元曲/yuanqu.json','["世情推物理，人生贵适意。", "想人间造物搬兴废，吉藏凶，凶暗吉。"]'),
('yuanqu-144','夜行船・富贵那能长富贵，日盈昃月满亏蚀。地下东南，天高西北，天地','关汉卿','元','元曲','yuanqu','','[]','尚无完体。',5,'元曲/yuanqu.json','["尚无完体。"]'),
('yuanqu-145','庆宣和・算到天明走到黑，赤紧的是衣食。凫短鹤长不能齐，且休题，谁','关汉卿','元','元曲','yuanqu','','[]','是非。',3,'元曲/yuanqu.json','["是非。"]'),
('yuanqu-146','锦上花・展放愁眉，休争闲气。今日容颜，老如昨日。古往今来，恁须尽','关汉卿','元','元曲','yuanqu','','[]','知，贤的愚的，贫的和富的。',13,'元曲/yuanqu.json','["知，贤的愚的，贫的和富的。"]'),
('yuanqu-147','幺・到头这一身，难逃那一日。受用了一朝，一朝便宜。百岁光阴，七十','关汉卿','元','元曲','yuanqu','','[]','者稀。',13,'元曲/yuanqu.json','["者稀。", "急急流年，滔滔逝水。"]'),
('yuanqu-148','清江引・落花满院春又归，晚景成何济！车尘马足中，蚁穴蜂衙内，寻取','关汉卿','元','元曲','yuanqu','','[]','个稳便处闲坐地。',8,'元曲/yuanqu.json','["个稳便处闲坐地。"]'),
('yuanqu-149','碧玉箫・乌兔相催，日月走东西。人生别离，白发故人稀。不停闲岁月疾，','关汉卿','元','元曲','yuanqu','','[]','光阴似驹过隙。',28,'元曲/yuanqu.json','["光阴似驹过隙。", "君莫痴，休争名利。", "幸有几杯，且不如花前醉。"]'),
('yuanqu-150','歇拍煞・恁则待闲熬煎、闲烦恼、闲萦系、闲追欢、闲落魄、闲游戏。金','关汉卿','元','元曲','yuanqu','','[]','鸡触祸机，得时间早弃迷途。',65,'元曲/yuanqu.json','["鸡触祸机，得时间早弃迷途。", "繁华重念箫韶歇，急流勇退寻归计。", "采蕨薇，洗是非；夷齐等，巢由辈。", "这两个谁人似得？松菊晋陶潜，江湖越范蠡。"]'),
('yuanqu-151','仙吕・桂枝香','关汉卿','元','元曲','yuanqu','','[]','因他别后，恹恹消瘦。',69,'元曲/yuanqu.json','["因他别后，恹恹消瘦。", "粉褪了雨后桃花，带宽了风前杨柳。", "这相思怎休？这相思怎休？害得我天长地久，难禁难受！泪痕流，滴破芙蓉面，却似珍珠断线头。"]'),
('yuanqu-152','不是路・万种风流，今日番成一段愁。泪盈眸，云山满目恨悠悠。谩追求，','关汉卿','元','元曲','yuanqu','','[]','情如柳絮风前斗，性似桃花逐水流。',43,'元曲/yuanqu.json','["情如柳絮风前斗，性似桃花逐水流。", "沉吟久，因他数尽残更漏，恁般亻孱亻愁！恁般亻孱亻愁！。"]'),
('yuanqu-153','木丫叉・雾锁秦楼，雾锁秦楼。云迷楚岫，御沟红叶空流。偷香韩寿，锦','关汉卿','元','元曲','yuanqu','','[]','帐中枉自绸缪，蹙破两眉头。',51,'元曲/yuanqu.json','["帐中枉自绸缪，蹙破两眉头。", "小蛮腰瘦如杨柳，浅淡樱桃樊素口。", "空教人目断去时舟，又不知风流浪子，何处温柔。"]'),
('yuanqu-154','幺篇・月下砧声幽，月下砧声幽，风前笛秦。断肠声无了无休，捣碎我心','关汉卿','元','元曲','yuanqu','','[]','又加上一场症候，顿使我愁不寐，襄王梦雨散云收。',23,'元曲/yuanqu.json','["又加上一场症候，顿使我愁不寐，襄王梦雨散云收。"]'),
('yuanqu-156','仙吕・赏花时','阚志学','元','元曲','yuanqu','','[]','香径泥融燕语喧，彩槛风微蝶影翩。',33,'元曲/yuanqu.json','["香径泥融燕语喧，彩槛风微蝶影翩。", "飞絮擘香绵，娇莺时啭，惊起绿窗眠。"]'),
('yuanqu-157','煞尾・惜花愁，伤春怨，萦系杀多情少年。何处狂游袅玉鞭，谩教人暗卜','阚志学','元','元曲','yuanqu','','[]','金钱。',45,'元曲/yuanqu.json','["金钱。", "空写遍翠涛笺，鱼雁难传。", "似这般白日黄昏怎过遣？青鸾信远。", "紫箫声转，画楼中闲杀月明天。"]'),
('yuanqu-158','钱大尹智宠谢天香・仙吕/赏花时','关汉卿','元','元曲','yuanqu','','[]','则这一曲翻成和泪篇，最苦偏高离恨天，双泪落尊前。',35,'元曲/yuanqu.json','["则这一曲翻成和泪篇，最苦偏高离恨天，双泪落尊前。", "山长水远，愁见理行轩。"]'),
('yuanqu-159','钱大尹智宠谢天香・玄篇','关汉卿','元','元曲','yuanqu','','[]','待得鸾胶续断弦，欲盼雕鞍难顾恋。',48,'元曲/yuanqu.json','["待得鸾胶续断弦，欲盼雕鞍难顾恋。", "谢他新理任这官员，常好是与民方便，咱又得个一夜并头莲。", "（同下）。"]'),
('yuanqu-160','钱大尹智宠谢天香・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','讲论诗词，笑谈街市，学难似风里扬丝，一世常如此。',24,'元曲/yuanqu.json','["讲论诗词，笑谈街市，学难似风里扬丝，一世常如此。"]'),
('yuanqu-161','钱大尹智宠谢天香・混江龙','关汉卿','元','元曲','yuanqu','','[]','我逐日家把您相试，乞求的教您做人时，但能勾终朝为父，也想着一日为师。',87,'元曲/yuanqu.json','["我逐日家把您相试，乞求的教您做人时，但能勾终朝为父，也想着一日为师。", "但有个敢接我这上厅行首案，情愿分会与你这搬演戏台儿。", "则为四般儿误了前程事，都只为聪明智慧，因此上辛苦无辞。"]'),
('yuanqu-162','钱大尹智宠谢天香・油葫芦','关汉卿','元','元曲','yuanqu','','[]','你道是金笼内鹦哥能念诗，这便是咱家的好比似。',155,'元曲/yuanqu.json','["你道是金笼内鹦哥能念诗，这便是咱家的好比似。", "原来越聪明越得不出笼时！能吹弹好比人每日常看伺，惯歌讴好比人每日常差使。", "（云）我不怨别人。", "（众旦云）姐姐，你怨谁？（旦云）咱会弹唱的，日日官身；不会弹唱的，倒得些自在！（唱）我怨那礼案里几个令史，他每都是我掌命司，先将那等不会弹不会唱的除了名字，早知道则做个哑猱儿。"]'),
('yuanqu-163','钱大尹智宠谢天香・天下乐','关汉卿','元','元曲','yuanqu','','[]','俺可也图甚么香名贯人耳！想当也波时，不三思：越聪明，不能勾无外事。',224,'元曲/yuanqu.json','["俺可也图甚么香名贯人耳！想当也波时，不三思：越聪明，不能勾无外事。", "卖弄的有伎俩，卖弄的有艳姿，则落的临老来呼\"弟子\"！（张千云）谢大姐，你怎生这早晚才来？你只在这里，我报复去。", "（做报科，云）报的老爷得知：有乐人每来参见。", "（钱大尹云）别的休进来，则着那为头的一人来见。", "（张千云）别的都回去，则着谢大姐过去哩！（众旦下）（正旦见、拜科，云）上厅行首谢天香谨参。", "（钱大尹云）休要误了官身。", "（旦云）理会的。", "（做出门科，云）爷爷，那官人好个冷脸子也！（唱）。"]'),
('yuanqu-164','钱大尹智宠谢天香・金盏儿','关汉卿','元','元曲','yuanqu','','[]','猛觑了那容姿，不觉的下阶址，下场头少不的跟官长厅前死；往常觑品官宣使似小孩儿。',68,'元曲/yuanqu.json','["猛觑了那容姿，不觉的下阶址，下场头少不的跟官长厅前死；往常觑品官宣使似小孩儿。", "他则道官身休失误，启口更无词。", "立地刚一饭间，心战勾两炊时。"]'),
('yuanqu-165','钱大尹智宠谢天香・醉中天','关汉卿','元','元曲','yuanqu','','[]','初相见呼你为学士，谨厚不因而；今遍回身嘱付尔，相公也冷眼儿频偷视。',64,'元曲/yuanqu.json','["初相见呼你为学士，谨厚不因而；今遍回身嘱付尔，相公也冷眼儿频偷视。", "你觑他交椅上抬颏样儿，待的你不同前次，他则是微分间将表字呼之。"]'),
('yuanqu-166','钱大尹智宠谢天香・醉扶归','关汉卿','元','元曲','yuanqu','','[]','你陡恁的无才思，有甚省不的两桩儿？我道这相公不是漫词，你怎么不解其中意？他道是种桃花砍折竹枝，则说你重色轻君子！。',57,'元曲/yuanqu.json','["你陡恁的无才思，有甚省不的两桩儿？我道这相公不是漫词，你怎么不解其中意？他道是种桃花砍折竹枝，则说你重色轻君子！。"]'),
('yuanqu-167','钱大尹智宠谢天香・赚煞','关汉卿','元','元曲','yuanqu','','[]','我这府里祗候几曾闲，差拨无铨次，从今后无倒断嗟呀怨咨。',108,'元曲/yuanqu.json','["我这府里祗候几曾闲，差拨无铨次，从今后无倒断嗟呀怨咨。", "我去这触热也似官人行将礼数使，若是轻咳嗽便有官司。", "我直到揭席时、来到家时，我又索趱下些工夫忆念尔。", "是我那清歌皓齿，是我那言谈情思，是我那湿浸浸舞困袖梢儿。", "（下）。"]'),
('yuanqu-168','钱大尹智宠谢天香・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','往常时唤官身可早眉黛舒，今日个叫祗候喉咙响。',86,'元曲/yuanqu.json','["往常时唤官身可早眉黛舒，今日个叫祗候喉咙响。", "原来是你这狠首领，我则道是那个面前桑？恰才陪着笑脸儿应昂，怎觑我这查梨相，只因他忒过当。", "据妾身貌陋残妆，谁教他大尹行将咱过奖？。"]'),
('yuanqu-169','钱大尹智宠谢天香・隔尾','关汉卿','元','元曲','yuanqu','','[]','我见他严容端坐挨着罗幌，可甚么和气春风满画堂！我最愁是劈先里递一声唱，这里但有个女娘、坐场，可敢烘散我家私做的赏。',57,'元曲/yuanqu.json','["我见他严容端坐挨着罗幌，可甚么和气春风满画堂！我最愁是劈先里递一声唱，这里但有个女娘、坐场，可敢烘散我家私做的赏。"]'),
('yuanqu-170','钱大尹智宠谢天香・贺新郎','关汉卿','元','元曲','yuanqu','','[]','呀，想东坡一曲〔满庭芳〕则道一个"香霭雕盘"，可又早祸从天降！当时嘲拨无拦当，乞相公宽洪海量，怎不的仔细参详？（钱大尹云）怎么在我行打关节那？（正旦唱）小人便关',136,'元曲/yuanqu.json','["呀，想东坡一曲〔满庭芳〕则道一个\"香霭雕盘\"，可又早祸从天降！当时嘲拨无拦当，乞相公宽洪海量，怎不的仔细参详？（钱大尹云）怎么在我行打关节那？（正旦唱）小人便关节煞，怎生勾除籍不做娼，弃贱得为良。", "他则是一时间带酒闲支谎，量妾身本开封府阶下承应辈，怎做的柳耆卿心上谢天香？。"]'),
('yuanqu-171','钱大尹智宠谢天香・牧羊关','关汉卿','元','元曲','yuanqu','','[]','相公名誉传天下，妾身乐籍在教坊；量妾身则是个妓女排场，相公是当代名儒。',90,'元曲/yuanqu.json','["相公名誉传天下，妾身乐籍在教坊；量妾身则是个妓女排场，相公是当代名儒。", "妾身则好去待宾客，供些优唱。", "妾身是临路金丝柳，相公是架海紫金梁；想你便意错见、心错爱，怎做的门厮敌、户厮当？。"]'),
('yuanqu-172','钱大尹智宠谢天香・二煞','关汉卿','元','元曲','yuanqu','','[]','则恁这秀才每活计似鱼翻浪，大人家前程似狗探汤。',109,'元曲/yuanqu.json','["则恁这秀才每活计似鱼翻浪，大人家前程似狗探汤。", "则俺这侍妾每近帏房，止不过供手巾到他行，能勾见些模样？着护衣须是相亲傍，止不过梳头处俺胸前靠着脊梁，几时得儿女成双？（云）指望嫁杭州柳耆卿，做个自在人，如今怎了也？（唱）。"]'),
('yuanqu-173','钱大尹智宠谢天香・正宫/端正好','关汉卿','元','元曲','yuanqu','','[]','往常我在风尘为歌妓，止不过见了那几个筵席，到家来须做个自由鬼；今日个打我在无底磨牢笼内！。',45,'元曲/yuanqu.json','["往常我在风尘为歌妓，止不过见了那几个筵席，到家来须做个自由鬼；今日个打我在无底磨牢笼内！。"]'),
('yuanqu-174','钱大尹智宠谢天香・滚绣球','关汉卿','元','元曲','yuanqu','','[]','到早起过洗面水，到晚来又索铺床叠被，我服侍的都入罗帏，我恰才舒铺盖似孤鬼，少不的足恋蜷寝睡，整三年有名无实。',180,'元曲/yuanqu.json','["到早起过洗面水，到晚来又索铺床叠被，我服侍的都入罗帏，我恰才舒铺盖似孤鬼，少不的足恋蜷寝睡，整三年有名无实。", "本是个见交风月耆卿伴，教我做遥受恩情大尹妻，端的谁知？（二旦扮姬妾上，云）俺二人是钱大尹家侍妾。", "今日无甚事，去望姓谢的姐姐走一遭去。", "（见旦科，云）姐姐，俺二人竟来望姐姐。", "（正旦云）二位姐姐请坐。", "（二旦云）姐姐，你在宅中三年，相公曾亲近你么？（正旦唱）。"]'),
('yuanqu-175','钱大尹智宠谢天香・倘秀才','关汉卿','元','元曲','yuanqu','','[]','俺若是曾宿睡呵，则除是天知地知；相公那铺盖儿，知他是横的竖的！比我那初使唤，如今越更稀。',64,'元曲/yuanqu.json','["俺若是曾宿睡呵，则除是天知地知；相公那铺盖儿，知他是横的竖的！比我那初使唤，如今越更稀。", "想是我出身处本低微，则怕展污了相公贵体。"]'),
('yuanqu-176','钱大尹智宠谢天香・滚绣球','关汉卿','元','元曲','yuanqu','','[]','姐姐每肯教诲，怕不是好意？争奈我官人行，怎敢便话不投机？（二旦云）姐姐，你又无甚么过失。',141,'元曲/yuanqu.json','["姐姐每肯教诲，怕不是好意？争奈我官人行，怎敢便话不投机？（二旦云）姐姐，你又无甚么过失。", "（正旦唱）你道是无过失，学恁的，姐姐每会也那不会？我则是斟量着紧慢迟疾，强何郎旖旎煞难搽粉，狠张敞央及煞怎画眉？要识个高低。", "（二旦云）敢问姐姐，当日柳七官人《乐章集》，姐姐收的好么？（正旦唱）。"]'),
('yuanqu-177','钱大尹智宠谢天香・倘秀才','关汉卿','元','元曲','yuanqu','','[]','便休题花七、柳七，若听得这里是那里，相公的耳朵里风闻那旧是非。',47,'元曲/yuanqu.json','["便休题花七、柳七，若听得这里是那里，相公的耳朵里风闻那旧是非。", "休只管这几句，滥黄齑，我也记得。"]'),
('yuanqu-178','钱大尹智宠谢天香・穷河西','关汉卿','元','元曲','yuanqu','','[]','姐姐每谁敢道袖褪《乐章集》，都则是断送的我一身亏。',91,'元曲/yuanqu.json','["姐姐每谁敢道袖褪《乐章集》，都则是断送的我一身亏。", "怕待学大曲子我从头儿唱与你，本记的人前会，挂口儿从今后再休提。", "（二旦云）咱和你同去竹云亭上赌戏咱。", "（正旦云）姐姐每，咱去波。", "（唱）。"]'),
('yuanqu-179','钱大尹智宠谢天香・滚绣球','关汉卿','元','元曲','yuanqu','','[]','想前日使象棋，说下的则是个手帕儿赌戏，你将我那玉束纳藤箱子，便不放空回。',92,'元曲/yuanqu.json','["想前日使象棋，说下的则是个手帕儿赌戏，你将我那玉束纳藤箱子，便不放空回。", "近新来，下雨的那一日，你输与我绣鞋儿一对，挂口儿再不曾提。", "那里为些些赌赛绝了交契，小小输赢丑了面皮，道我不精细。"]'),
('yuanqu-180','钱大尹智宠谢天香・倘秀才','关汉卿','元','元曲','yuanqu','','[]','幺四五骰着个撮十，二三二趁着个夹七；一面打个色儿，也当得幺二三是鼠尾。',51,'元曲/yuanqu.json','["幺四五骰着个撮十，二三二趁着个夹七；一面打个色儿，也当得幺二三是鼠尾。", "赌钱的、不伶俐，姐姐你可便再掷。"]'),
('yuanqu-181','钱大尹智宠谢天香・呆骨朵','关汉卿','元','元曲','yuanqu','','[]','我将这色数儿轻放在骰盆内，二三五又掷个乌十；不下钱打赛，我可便赢了你两回。',75,'元曲/yuanqu.json','["我将这色数儿轻放在骰盆内，二三五又掷个乌十；不下钱打赛，我可便赢了你两回。", "这上面分明见，色数儿且休提。", "姐姐，我可便做桩儿三个五，你今日这般输说甚的？。"]'),
('yuanqu-182','钱大尹智宠谢天香・倘秀才','关汉卿','元','元曲','yuanqu','','[]','你休要不君子便将闹起，我永世儿不和你厮极，塌着那臭尸骸一壁稳坐的。',114,'元曲/yuanqu.json','["你休要不君子便将闹起，我永世儿不和你厮极，塌着那臭尸骸一壁稳坐的。", "（钱将拄仗放在旦右肩上）（正旦拨科，唱）兀的不闲着您！（钱将拄杖放在旦左肩上）（正旦拔科，唱）臭驴蹄！（钱又将拄杖放在旦右肩上）（正旦拿住回头科，唱）兀的是谁？。"]'),
('yuanqu-183','钱大尹智宠谢天香・醉太平','关汉卿','元','元曲','yuanqu','','[]','唬的我连忙的跪膝，不由我泪雨似扒推；可又早七留七力来到我跟底，不言语立地；我见他出留出律两个都回避。',165,'元曲/yuanqu.json','["唬的我连忙的跪膝，不由我泪雨似扒推；可又早七留七力来到我跟底，不言语立地；我见他出留出律两个都回避。", "相公将必留不剌拄杖相调戏，我不该必丢不搭口内失尊卑，这的是天香犯罪。", "（钱大尹云）天香，你怕么？（正旦云）可知怕哩。", "（钱大尹云）你要饶么？（正旦云）可知要饶哩。", "（钱大尹云）既然要饶，或诗或词，作一首来我看，我便饶了你。", "（正旦云）请。"]'),
('yuanqu-184','钱大尹智宠谢天香・二煞','关汉卿','元','元曲','yuanqu','','[]','往常时不曾挂眼都无意，今日回心有甚迟？相公的言语更怕不中，委付妾身教我转转猜疑。',78,'元曲/yuanqu.json','["往常时不曾挂眼都无意，今日回心有甚迟？相公的言语更怕不中，委付妾身教我转转猜疑。", "相公又不是戏笑，又不是沉醉，又不是昏迷；待道是颠狂睡呓，兀的不青天这白日？。"]'),
('yuanqu-185','钱大尹智宠谢天香・一煞','关汉卿','元','元曲','yuanqu','','[]','相公，你一言既出如何悔，驷马奔驰不可追。',109,'元曲/yuanqu.json','["相公，你一言既出如何悔，驷马奔驰不可追。", "妾身出入兰堂，身居画阁，行有香车，宿有罗帏。", "相公，整过了三年，可便调理，无个消息；不想道今朝错爱我这匪妓，也则是可怜见哭啼啼。", "（钱大尹云）天香，后堂中换衣服去。", "（下）（正旦唱）。"]'),
('yuanqu-186','钱大尹智宠谢天香・煞尾','关汉卿','元','元曲','yuanqu','','[]','则今番文诌诌的施才艺，从来个扑籁籁没气力。',108,'元曲/yuanqu.json','["则今番文诌诌的施才艺，从来个扑籁籁没气力。", "相公这一句言语可立碑，我也不敢十分相信的。", "许来大官员，恁来大职位，发出言词忒口疾。", "你不委心为自家没见识，又不是花街中、柳陌里，那一个彻梢虚、雾塌桥，浑身我可也认的你！（下）。"]'),
('yuanqu-187','钱大尹智宠谢天香・中吕/粉蝶儿','关汉卿','元','元曲','yuanqu','','[]','送的那水护衣为头，先使了熬麸浆细香澡豆，暖的那温泔清手面轻揉；打底干南定粉，把蔷擞露和就；破开那苏合香油，我嫌棘针梢燎的来油臭。',64,'元曲/yuanqu.json','["送的那水护衣为头，先使了熬麸浆细香澡豆，暖的那温泔清手面轻揉；打底干南定粉，把蔷擞露和就；破开那苏合香油，我嫌棘针梢燎的来油臭。"]'),
('yuanqu-188','钱大尹智宠谢天香・醉春风','关汉卿','元','元曲','yuanqu','','[]','那里敢深蘸着指头搽，我则索轻将绵絮纽。',67,'元曲/yuanqu.json','["那里敢深蘸着指头搽，我则索轻将绵絮纽。", "比俺那门前乐探等着官身，我今日个不丑、丑。", "虽不是宅院里夫人，也是那大人家姬妾，强似那上厅的祗候。"]'),
('yuanqu-189','钱大尹智宠谢天香・石榴花','关汉卿','元','元曲','yuanqu','','[]','我则道坐着的是那个俊儒流，我这里猛窥视细凝眸，原来是三年不肯往杭州，闪的我落后，有国难投！莫不是将咱故意相迤逗，特教的露丑呈羞？你觑那衣服每各自施忠厚，百般儿省',86,'元曲/yuanqu.json','["我则道坐着的是那个俊儒流，我这里猛窥视细凝眸，原来是三年不肯往杭州，闪的我落后，有国难投！莫不是将咱故意相迤逗，特教的露丑呈羞？你觑那衣服每各自施忠厚，百般儿省不的甚缘由。"]'),
('yuanqu-190','钱大尹智宠谢天香・斗鹌鹑','关汉卿','元','元曲','yuanqu','','[]','并无那私事公仇，倒与俺张筵置酒。',135,'元曲/yuanqu.json','["并无那私事公仇，倒与俺张筵置酒。", "（带云）我这一过去，说些甚么的是？（唱）我则是佯不相瞅，怎敢道特来问候。", "（见科）（钱大尹云）天香，与耆卿施礼咱。", "（正旦唱）我这里施罢礼，官人行紧低首。", "（钱大尹云）天香、近前来些。", "（正旦唱）谁敢道是离了左右，我则索侍立旁边，我则索趋前褪后。"]'),
('yuanqu-191','钱大尹智宠谢天香・哨遍','关汉卿','元','元曲','yuanqu','','[]','一自才郎别后，相公那帘幕里香风透。',114,'元曲/yuanqu.json','["一自才郎别后，相公那帘幕里香风透。", "又无个交错觥筹，又无个宾客闲游饮杯酒，坐衙紧唤，乐探忙勾，唬的我难收救，只得向公厅祗候。", "不问我舞旋，只着我歌讴。", "将凤凰杯注酒尊前递，把商角调填词韵脚搜，唱到\"惨绿愁红\"。", "\"事事可可\"，一时禁口。"]'),
('yuanqu-192','钱大尹智宠谢天香・耍孩儿','关汉卿','元','元曲','yuanqu','','[]','相公讳字都全有，我将别韵儿轻轻换偷；即时间乐案里便除名，扬言说要结绸缪。',80,'元曲/yuanqu.json','["相公讳字都全有，我将别韵儿轻轻换偷；即时间乐案里便除名，扬言说要结绸缪。", "三年甚事曾占着铺盖，千日何曾靠着枕头？相公意，难参透。", "我本是沾泥飞絮，倒做了不缆孤舟！。"]'),
('yuanqu-193','钱大尹智宠谢天香・二煞','关汉卿','元','元曲','yuanqu','','[]','见妾身精神比杏桃，相公如何共卯酉？见天香颜色当春昼。',113,'元曲/yuanqu.json','["见妾身精神比杏桃，相公如何共卯酉？见天香颜色当春昼。", "观花不比观娇态，饮酒合当饮巨瓯。", "谁把清香嗅？则是深围在阑底，又何曾插个花头！（钱大尹云）张千，快收拾车马，送谢夫人到状元宅上去！（柳同旦拜谢科，云）深感相公大恩！（正旦唱）。"]'),
('yuanqu-194','钱大尹智宠谢天香・煞尾','关汉卿','元','元曲','yuanqu','','[]','这天香不想艳阳天气开，我则道无情干罢休！谁想这牡丹花折入东君手，今日个分与章台路傍柳。',43,'元曲/yuanqu.json','["这天香不想艳阳天气开，我则道无情干罢休！谁想这牡丹花折入东君手，今日个分与章台路傍柳。"]'),
('yuanqu-195','草桥店梦莺莺(第四本)・仙吕/端正好','王实甫','元','元曲','yuanqu','','[]','因姐姐玉精神，花模样，无倒断晓夜思量。',78,'元曲/yuanqu.json','["因姐姐玉精神，花模样，无倒断晓夜思量。", "着一片志诚心盖抹了漫天谎。", "出画阁，向书房；离楚岫，赴高唐；学窃玉，试偷香；巫娥女，楚襄王；楚襄王敢先在阳台上。", "(下)。"]'),
('yuanqu-196','草桥店梦莺莺(第四本)・仙吕/点绛唇','王实甫','元','元曲','yuanqu','','[]','伫立闲阶。',25,'元曲/yuanqu.json','["伫立闲阶。", "夜深香霭、横金界。", "萧洒书斋，闷杀读书客。"]'),
('yuanqu-197','草桥店梦莺莺(第四本)・油葫芦','王实甫','元','元曲','yuanqu','','[]','情思昏昏眼倦开，单枕侧，梦魂飞入梦阳台。',78,'元曲/yuanqu.json','["情思昏昏眼倦开，单枕侧，梦魂飞入梦阳台。", "早知道无明无夜因他害，想当初\"不如不遇倾城色\"。", "人有过，必自责，勿惮改。", "我却待\"贤贤易色\"将心戒，怎禁他兜的上心来。"]'),
('yuanqu-198','草桥店梦莺莺(第四本)・天下乐','王实甫','元','元曲','yuanqu','','[]','我则索倚定门儿手托腮，好着我难猜：来也那不来？夫人行料应难离侧。',55,'元曲/yuanqu.json','["我则索倚定门儿手托腮，好着我难猜：来也那不来？夫人行料应难离侧。", "望得人眼欲穿，想得人心越窄，多管是冤家不自在。"]'),
('yuanqu-199','草桥店梦莺莺(第四本)・那吒令','王实甫','元','元曲','yuanqu','','[]','他若是肯来，早身离贵宅；他若是到来，便春生敝斋；他若是不来，似石沉大海。',57,'元曲/yuanqu.json','["他若是肯来，早身离贵宅；他若是到来，便春生敝斋；他若是不来，似石沉大海。", "数着他脚步儿行，倚定窗棂儿待。", "寄语多才：。"]'),
('yuanqu-200','草桥店梦莺莺(第四本)・鹊踏枝','王实甫','元','元曲','yuanqu','','[]','恁的般恶抢白，并不曾记心怀；拔得个意转心回，夜去明来。',44,'元曲/yuanqu.json','["恁的般恶抢白，并不曾记心怀；拔得个意转心回，夜去明来。", "空调眼色经今半载，这其间委实难捱。"]'),
('yuanqu-201','草桥店梦莺莺(第四本)・寄生草','王实甫','元','元曲','yuanqu','','[]','安排着害，准备着抬。',70,'元曲/yuanqu.json','["安排着害，准备着抬。", "想着这异乡身强把茶汤捱，则为这可憎才熬得心肠耐，办一片志诚心留得形骸在。", "试着那司天台打算半年愁，端的是太平车约有十余载。"]'),
('yuanqu-202','草桥店梦莺莺(第四本)・村里迓鼓','王实甫','元','元曲','yuanqu','','[]','猛见他可憎模样，--小生那里得病来--早医可九分不快。',91,'元曲/yuanqu.json','["猛见他可憎模样，--小生那里得病来--早医可九分不快。", "先前见责，谁承望今宵欢爱！着小姐这般用心，不才张珙，合当跪拜。", "小生无宋玉般容，潘安般貌，子建般才；姐姐，你则是可怜见为人在客！。"]'),
('yuanqu-203','草桥店梦莺莺(第四本)・元和令','王实甫','元','元曲','yuanqu','','[]','绣鞋儿刚半拆，柳腰儿勾一搦，羞答答不肯把头抬，只将鸳枕捱。',45,'元曲/yuanqu.json','["绣鞋儿刚半拆，柳腰儿勾一搦，羞答答不肯把头抬，只将鸳枕捱。", "云鬟仿佛坠金钗，偏宜髟狄髻儿歪。"]'),
('yuanqu-204','草桥店梦莺莺(第四本)・胜葫芦','王实甫','元','元曲','yuanqu','','[]','我这里软玉温香抱满怀。',44,'元曲/yuanqu.json','["我这里软玉温香抱满怀。", "呀，阮肇到天台，春至人间花弄色。", "将柳腰款摆，花心轻拆，露滴牡丹开。"]'),
('yuanqu-205','草桥店梦莺莺(第四本)・后庭花','王实甫','元','元曲','yuanqu','','[]','春罗原莹白，早见红香点嫩色。',105,'元曲/yuanqu.json','["春罗原莹白，早见红香点嫩色。", "(旦云)羞人答答的，看甚么？(末)灯下偷晴觑，胸前着肉揣。", "畅奇战，浑身通泰，不知春从何处来？无能的张秀才，孤身西洛客，自从逢稔色，思量的不下怀；忧愁因间隔，相思无摆划，谢芳卿不见责。"]'),
('yuanqu-206','草桥店梦莺莺(第四本)・柳叶儿','王实甫','元','元曲','yuanqu','','[]','我将你做心肝儿般看待，点污了小姐清白。',50,'元曲/yuanqu.json','["我将你做心肝儿般看待，点污了小姐清白。", "忘餐废寝舒心害，若不是真心耐，志诚捱，怎能够这相思苦尽甘来？。"]'),
('yuanqu-207','草桥店梦莺莺(第四本)・青哥儿','王实甫','元','元曲','yuanqu','','[]','成就了今宵欢爱，魂正在九霄云外。',85,'元曲/yuanqu.json','["成就了今宵欢爱，魂正在九霄云外。", "投至得见你多情小奶奶，憔悴形骸，瘦似麻秸。", "今夜和谐，犹自疑猜。", "露滴香埃，风静闲阶，月射书斋，云锁阳台；审问明白，只疑是昨夜梦中来，愁无奈。"]'),
('yuanqu-208','草桥店梦莺莺(第四本)・寄生草','王实甫','元','元曲','yuanqu','','[]','多丰韵，忒稔色。',48,'元曲/yuanqu.json','["多丰韵，忒稔色。", "乍时相见教人害，霎时不见教人怪，些儿得见教人爱。", "今宵同会碧纱厨，何时重解香罗带。"]'),
('yuanqu-209','草桥店梦莺莺(第四本)・煞尾','王实甫','元','元曲','yuanqu','','[]','春意透酥胸，春色横眉黛，贱却人间玉帛。',98,'元曲/yuanqu.json','["春意透酥胸，春色横眉黛，贱却人间玉帛。", "杏脸桃腮，乘着月色，娇滴滴越显得红白。", "下香阶，懒步苍苔，动人处弓鞋凤头窄。", "叹鲰生不才，谢多娇错爱。", "若小姐不弃小生，此情一心者，你是必破工夫明夜早些来。", "(下)。"]'),
('yuanqu-210','草桥店梦莺莺(第四本)・越调/斗鹌鹑','王实甫','元','元曲','yuanqu','','[]','则着你夜去明来，倒有个天长地久，不争你握雨携云，常使我提心在口。',74,'元曲/yuanqu.json','["则着你夜去明来，倒有个天长地久，不争你握雨携云，常使我提心在口。", "你则合带月披星，谁着你停眠整宿？老夫人心数多，情性亻刍；使不着我巧语花言，将没做有。"]'),
('yuanqu-211','草桥店梦莺莺(第四本)・紫花儿序','王实甫','元','元曲','yuanqu','','[]','老夫人猜那穷酸做了新婿，小姐做了娇妻，这小贱人做了牵头。',120,'元曲/yuanqu.json','["老夫人猜那穷酸做了新婿，小姐做了娇妻，这小贱人做了牵头。", "俺小姐这些时春山低翠，秋水凝眸。", "别样的都休，试把你裙带儿拴，纽门儿扣，比着你旧时肥瘦，出落得精神，别样的风流。", "(旦云)红娘，你到那里小心回话者！(红云)我到夫人处，必问：\"这小贱人，。"]'),
('yuanqu-212','草桥店梦莺莺(第四本)・金蕉叶','王实甫','元','元曲','yuanqu','','[]','"我着你但去处行监坐守，谁着你拖逗的胡行乱走？"若问着此一节呵如何诉休？你便索与他个"知情"的犯由。',50,'元曲/yuanqu.json','["\"我着你但去处行监坐守，谁着你拖逗的胡行乱走？\"若问着此一节呵如何诉休？你便索与他个\"知情\"的犯由。"]'),
('yuanqu-213','草桥店梦莺莺(第四本)・调笑令','王实甫','元','元曲','yuanqu','','[]','你绣帏里效绸缪，倒凤颠鸾百事有。',65,'元曲/yuanqu.json','["你绣帏里效绸缪，倒凤颠鸾百事有。", "我在窗儿外几曾轻咳嗽，立苍苔将绣鞋儿冰透。", "今日个嫩皮肤到将粗棍抽，姐姐呵，俺这通殷勤的着甚来由？。"]'),
('yuanqu-214','草桥店梦莺莺(第四本)・鬼三台','王实甫','元','元曲','yuanqu','','[]','夜坐时停了针绣，共姐姐闲穷究，说张生哥哥病久。',104,'元曲/yuanqu.json','["夜坐时停了针绣，共姐姐闲穷究，说张生哥哥病久。", "咱两个背着夫人，向书房问候。", "(夫人云)问候呵，他说甚么？(红云)他说来，道\"老夫人事已休，将恩变为仇，着小生半途喜变做忧\"。", "他道：\"红娘你且先行，教小姐权时落后。"]'),
('yuanqu-215','草桥店梦莺莺(第四本)・秃厮儿','王实甫','元','元曲','yuanqu','','[]','我则道神针法灸，谁承望燕侣莺俦。',39,'元曲/yuanqu.json','["我则道神针法灸，谁承望燕侣莺俦。", "他两个经今月余则是一处宿，何须你一一问缘由？。"]'),
('yuanqu-216','草桥店梦莺莺(第四本)・圣药王','王实甫','元','元曲','yuanqu','','[]','他每不识忧，不识愁，一双心意两相投。',48,'元曲/yuanqu.json','["他每不识忧，不识愁，一双心意两相投。", "夫人得好休，便好休，这其间何必苦追求？常言道\"女大不中留\"。"]'),
('yuanqu-217','草桥店梦莺莺(第四本)・麻郎儿','王实甫','元','元曲','yuanqu','','[]','秀才是文章魁首，姐姐是仕女班头；一个通彻三教九流，一个晓尽描鸾刺绣。',34,'元曲/yuanqu.json','["秀才是文章魁首，姐姐是仕女班头；一个通彻三教九流，一个晓尽描鸾刺绣。"]'),
('yuanqu-218','草桥店梦莺莺(第四本)・幺篇','王实甫','元','元曲','yuanqu','','[]','世有、便休、罢手，大恩人怎做敌头？起白马将军故友，斩飞虎叛贼草寇。',33,'元曲/yuanqu.json','["世有、便休、罢手，大恩人怎做敌头？起白马将军故友，斩飞虎叛贼草寇。"]'),
('yuanqu-219','草桥店梦莺莺(第四本)・络丝娘','王实甫','元','元曲','yuanqu','','[]','不争和张解元参辰卯酉，便是与崔相国出乖弄丑。',186,'元曲/yuanqu.json','["不争和张解元参辰卯酉，便是与崔相国出乖弄丑。", "到底干连着自己骨肉，夫人索穷究。", "(夫人云)这小贱人也道得是。", "我不合养了这个不肖之女。", "待经官呵，玷辱家门。", "罢罢！俺家无犯法之男，再婚之女，与了这厮罢。", "红娘唤那贱人来！(红见旦云)且喜姐姐，那棍子则是滴溜溜在我身上，吃我直说过了。", "我也怕不得许多，夫人如今唤你来，待成合亲事。", "(旦去)羞人答答的，怎么见夫人？(红云)娘跟前有甚么羞？。"]'),
('yuanqu-220','草桥店梦莺莺(第四本)・小桃红','王实甫','元','元曲','yuanqu','','[]','当日个月明才上柳梢头，却早人约黄昏后。',78,'元曲/yuanqu.json','["当日个月明才上柳梢头，却早人约黄昏后。", "羞得我脑背后将牙儿衬着衫儿袖。", "猛凝眸，则见鞋底尖儿瘦。", "一个恣情的不休，一个哑声儿厮耨。", "呸！那其间可怎生不害半星儿羞？。"]'),
('yuanqu-221','草桥店梦莺莺(第四本)・东原乐','王实甫','元','元曲','yuanqu','','[]','想思事，一笔勾，早则展放从前眉儿皱，美爱幽欢恰动头。',49,'元曲/yuanqu.json','["想思事，一笔勾，早则展放从前眉儿皱，美爱幽欢恰动头。", "既能够，张生，你觑兀的般可喜娘庞儿也要人消受。"]'),
('yuanqu-222','草桥店梦莺莺(第四本)・收尾','王实甫','元','元曲','yuanqu','','[]','来时节画堂箫鼓鸣春昼，列着一对儿鸾交凤友。',43,'元曲/yuanqu.json','["来时节画堂箫鼓鸣春昼，列着一对儿鸾交凤友。", "那其间才受你说媒红，方吃你谢亲酒。", "(并下)。"]'),
('yuanqu-223','草桥店梦莺莺(第四本)・正宫/端正好','王实甫','元','元曲','yuanqu','','[]','碧云天，黄花地，西风紧，北雁南飞。',31,'元曲/yuanqu.json','["碧云天，黄花地，西风紧，北雁南飞。", "晓来谁染霜林醉？总是离人泪。"]'),
('yuanqu-224','草桥店梦莺莺(第四本)・脱布衫','王实甫','元','元曲','yuanqu','','[]','下西风黄叶纷飞，染寒烟衰草萋迷。',33,'元曲/yuanqu.json','["下西风黄叶纷飞，染寒烟衰草萋迷。", "酒席上斜签着坐的，蹙愁眉死临侵地。"]'),
('yuanqu-225','草桥店梦莺莺(第四本)・小梁州','王实甫','元','元曲','yuanqu','','[]','我见他阁泪汪汪不敢垂，恐怕人知；猛然见了把头低，长吁气，推整素罗衣。',34,'元曲/yuanqu.json','["我见他阁泪汪汪不敢垂，恐怕人知；猛然见了把头低，长吁气，推整素罗衣。"]'),
('yuanqu-226','草桥店梦莺莺(第四本)・幺篇','王实甫','元','元曲','yuanqu','','[]','虽然久后成佳配，奈时间怎不悲啼。',66,'元曲/yuanqu.json','["虽然久后成佳配，奈时间怎不悲啼。", "意似痴，心如醉，昨宵今日，清减了小腰围。", "(夫人云)小姐把盏者！(红递酒，旦把盏长吁科，云)请吃酒！。"]'),
('yuanqu-227','草桥店梦莺莺(第四本)・上小楼','王实甫','元','元曲','yuanqu','','[]','合欢未已，离愁相继。',51,'元曲/yuanqu.json','["合欢未已，离愁相继。", "想着俺前暮私情，昨夜成亲，今日别离。", "我谂知这几日相思滋味，却原来比别离情更增十倍。"]'),
('yuanqu-228','草桥店梦莺莺(第四本)・幺篇','王实甫','元','元曲','yuanqu','','[]','年少呵轻远别，情薄呵易弃掷。',85,'元曲/yuanqu.json','["年少呵轻远别，情薄呵易弃掷。", "全不想腿儿相挨，脸儿相偎，手儿相携。", "你与俺崔相国做女婿，妻荣夫贵，但得一个并头莲，煞强如状元及第。", "(夫人云)红娘把盏者！(红把酒科)(旦唱)。"]'),
('yuanqu-229','草桥店梦莺莺(第四本)・满庭芳','王实甫','元','元曲','yuanqu','','[]','供食太急，须臾对面，顷刻别离。',115,'元曲/yuanqu.json','["供食太急，须臾对面，顷刻别离。", "若不是酒席间子母每当回避，有心待与他举案齐眉。", "虽然是厮守得一时半刻，也合着俺夫妻每共桌而食。", "眼底空留意，寻思起就里，险化做望夫石。", "(红云)姐姐不曾吃早饭，饮一口儿汤水。", "(旦云)红娘，甚么汤水咽得下！。"]'),
('yuanqu-230','草桥店梦莺莺(第四本)・快活三','王实甫','元','元曲','yuanqu','','[]','将来的酒共食，尝着似土和泥。',33,'元曲/yuanqu.json','["将来的酒共食，尝着似土和泥。", "假若便是上和泥，也有些土气息，泥滋味。"]'),
('yuanqu-231','草桥店梦莺莺(第四本)・朝天子','王实甫','元','元曲','yuanqu','','[]','暖溶溶玉醅，白泠泠似水，多半是相思泪。',75,'元曲/yuanqu.json','["暖溶溶玉醅，白泠泠似水，多半是相思泪。", "眼面前茶饭怕不待要吃，恨塞满愁肠胃。", "\"蜗角虚名，蝇头微利\"，拆鸳鸯在两下里。", "一个这壁，一个那壁，一递一声长吁气。"]'),
('yuanqu-232','草桥店梦莺莺(第四本)・四边静','王实甫','元','元曲','yuanqu','','[]','霎时间杯盘狼籍，车儿投东，马儿向西，两意徘徊，落日山横翠。',45,'元曲/yuanqu.json','["霎时间杯盘狼籍，车儿投东，马儿向西，两意徘徊，落日山横翠。", "知他今宵宿在那里？有梦也难寻觅。"]'),
('yuanqu-233','草桥店梦莺莺(第四本)・耍孩儿','王实甫','元','元曲','yuanqu','','[]','淋漓襟袖啼红泪，比司马青衫更湿。',64,'元曲/yuanqu.json','["淋漓襟袖啼红泪，比司马青衫更湿。", "伯劳东去燕西飞，未释程九问归期。", "虽然眼底人千里，且尽生前洒一杯。", "未饮心先醉，眼中流血，心水成灰。"]'),
('yuanqu-234','草桥店梦莺莺(第四本)・五煞','王实甫','元','元曲','yuanqu','','[]','到京师服水土，趁程途节饮食，顺时自保揣身体。',54,'元曲/yuanqu.json','["到京师服水土，趁程途节饮食，顺时自保揣身体。", "荒村雨露宜眠早，野店风霜要起迟！鞍马秋风里，最难调护，最要扶持。"]'),
('yuanqu-235','草桥店梦莺莺(第四本)・四煞','王实甫','元','元曲','yuanqu','','[]','这忧愁诉与谁？相思只自知，老天不管人憔悴。',59,'元曲/yuanqu.json','["这忧愁诉与谁？相思只自知，老天不管人憔悴。", "泪添九曲黄河溢，恨压三峰华岳低。", "到晚来闷把西楼倚，见了些夕阳古道，衰柳长堤。"]'),
('yuanqu-236','草桥店梦莺莺(第四本)・三煞','王实甫','元','元曲','yuanqu','','[]','笑吟吟一处来。',58,'元曲/yuanqu.json','["笑吟吟一处来。", "哭啼啼独自归。", "归家若到罗帏里，昨宵个绣衾香暖留春住，今夜个翠被生寒有梦知。", "留恋你别无意，见据鞍上马，。"]'),
('yuanqu-237','草桥店梦莺莺(第四本)・二煞','王实甫','元','元曲','yuanqu','','[]','你休忧"文齐福不齐"，我则怕你"停妻再娶妻"。',105,'元曲/yuanqu.json','["你休忧\"文齐福不齐\"，我则怕你\"停妻再娶妻\"。", "休要\"一春鱼雁无消息\"！我这里青鸾有信频须寄，你却休\"金榜无名誓不归\"。", "此一节君须记，若见了那异乡花草，再休似此处栖迟。", "(末云)再谁似小妇？小生又生此念。", "(旦唱)。"]'),
('yuanqu-238','草桥店梦莺莺(第四本)・一煞','王实甫','元','元曲','yuanqu','','[]','青山隔送行，疏林不做美，淡烟暮蔼相遮蔽。',57,'元曲/yuanqu.json','["青山隔送行，疏林不做美，淡烟暮蔼相遮蔽。", "夕阳古道无人语，禾黍秋风听马嘶。", "我为甚么懒上车儿内，来时甚急，去后何迟？。"]'),
('yuanqu-239','草桥店梦莺莺(第四本)・收尾','王实甫','元','元曲','yuanqu','','[]','四围山色中，一鞭残照里。',35,'元曲/yuanqu.json','["四围山色中，一鞭残照里。", "遍人间烦恼填胸臆，量这些大小车儿如何载得起？。"]'),
('yuanqu-240','草桥店梦莺莺(第四本)・双调/新水令','王实甫','元','元曲','yuanqu','','[]','望薄东萧寺暮云遮，惨离情半林黄叶。',41,'元曲/yuanqu.json','["望薄东萧寺暮云遮，惨离情半林黄叶。", "马迟人意懒，风急雁行斜。", "离恨重叠，破题儿第一夜。"]'),
('yuanqu-241','草桥店梦莺莺(第四本)・落梅风','王实甫','元','元曲','yuanqu','','[]','旅馆欹单枕，秋蛩鸣四野，助人愁的是纸窗儿风裂。',41,'元曲/yuanqu.json','["旅馆欹单枕，秋蛩鸣四野，助人愁的是纸窗儿风裂。", "乍孤眠被儿薄又怯，冷清清几时温热！。"]'),
('yuanqu-242','草桥店梦莺莺(第四本)・乔木查','王实甫','元','元曲','yuanqu','','[]','走荒郊旷野，把不住心娇怯，喘吁吁难将两气接。',33,'元曲/yuanqu.json','["走荒郊旷野，把不住心娇怯，喘吁吁难将两气接。", "疾忙赶上者，打草惊蛇。"]'),
('yuanqu-243','草桥店梦莺莺(第四本)・锦上花','王实甫','元','元曲','yuanqu','','[]','有限姻缘，方才宁贴；无奈功名，使人离缺。',44,'元曲/yuanqu.json','["有限姻缘，方才宁贴；无奈功名，使人离缺。", "害不了的愁怀，却才觉些；撇不下的相思，如今又也。"]'),
('yuanqu-244','草桥店梦莺莺(第四本)・幺篇','王实甫','元','元曲','yuanqu','','[]','清霜净碧波，白露下黄叶。',45,'元曲/yuanqu.json','["清霜净碧波，白露下黄叶。", "下下高高，道路曲折；四野风来，左右乱踅。", "我这里奔驰，他何处困歇？。"]'),
('yuanqu-245','草桥店梦莺莺(第四本)・清江引','王实甫','元','元曲','yuanqu','','[]','呆答孩店房儿里没话说，闷对如年夜。',85,'元曲/yuanqu.json','["呆答孩店房儿里没话说，闷对如年夜。", "暮雨催寒蛩，晓风吹残月，今宵酒醒何处也？(旦云)在这个店儿里，不免敲门。", "(末云)谁敲门哩？是一个女人的声音。", "我且开门看咱，这早晚是谁？。"]'),
('yuanqu-246','草桥店梦莺莺(第四本)・庆宣和','王实甫','元','元曲','yuanqu','','[]','是人呵疾忙快分说，是鬼呵合速灭。',71,'元曲/yuanqu.json','["是人呵疾忙快分说，是鬼呵合速灭。", "(旦云)是我。", "老夫人睡了。", "想你去了，几时再得见，特来和你同去。", "(末唱)听说罢将香罗袖儿拽，却原来是姐姐、姐姐。"]'),
('yuanqu-247','草桥店梦莺莺(第四本)・乔牌儿','王实甫','元','元曲','yuanqu','','[]','你是为人须为彻，将衣袂不藉。',32,'元曲/yuanqu.json','["你是为人须为彻，将衣袂不藉。", "绣鞋儿被露水泥沾惹，脚心儿管踏破也。"]'),
('yuanqu-248','草桥店梦莺莺(第四本)・甜水令','王实甫','元','元曲','yuanqu','','[]','想着你废寝忘餐，香消玉减，花开花谢，犹自觉争些；便枕冷衾寒，凤只鸾孤，月圆云遮，寻思来有甚伤嗟。',48,'元曲/yuanqu.json','["想着你废寝忘餐，香消玉减，花开花谢，犹自觉争些；便枕冷衾寒，凤只鸾孤，月圆云遮，寻思来有甚伤嗟。"]'),
('yuanqu-249','草桥店梦莺莺(第四本)・折桂令','王实甫','元','元曲','yuanqu','','[]','想人生最苦离别，可怜见千里关山，独自跋涉。',79,'元曲/yuanqu.json','["想人生最苦离别，可怜见千里关山，独自跋涉。", "似这般割肚牵肠，倒不如义断恩绝。", "虽然是一时间花残月缺，休猜做瓶坠簪折。", "不恋豪杰，不羡骄奢；自愿的生则同衾，死则同穴。"]'),
('yuanqu-250','草桥店梦莺莺(第四本)・雁儿落','王实甫','元','元曲','yuanqu','','[]','绿依依墙高柳半遮，静悄悄门掩清秋夜，疏剌剌林梢落叶风，昏惨惨云际穿窗月。',36,'元曲/yuanqu.json','["绿依依墙高柳半遮，静悄悄门掩清秋夜，疏剌剌林梢落叶风，昏惨惨云际穿窗月。"]'),
('yuanqu-251','草桥店梦莺莺(第四本)・得胜令','王实甫','元','元曲','yuanqu','','[]','惊觉我的是颤巍巍竹影走龙蛇，虚飘飘庄周梦蝴蝶，絮叨叨促织儿无休歇，韵悠悠砧声儿不断绝。',77,'元曲/yuanqu.json','["惊觉我的是颤巍巍竹影走龙蛇，虚飘飘庄周梦蝴蝶，絮叨叨促织儿无休歇，韵悠悠砧声儿不断绝。", "痛煞煞伤别，急煎煎好梦儿应难舍；冷清清的咨嗟，娇滴滴玉人儿何处也！。"]'),
('yuanqu-252','草桥店梦莺莺(第四本)・鸳鸯煞','王实甫','元','元曲','yuanqu','','[]','柳丝长咫尺情牵惹，水声幽仿佛人呜咽。',73,'元曲/yuanqu.json','["柳丝长咫尺情牵惹，水声幽仿佛人呜咽。", "斜月残灯，半明不灭。", "畅道是旧恨连绵，新愁郁结；别恨离愁，满肺腑难淘泻。", "除纸笔代喉舌，千种相思对谁说。", "(并下)。"]'),
('yuanqu-253','草桥店梦莺莺(第四本)・络丝娘煞尾','王实甫','元','元曲','yuanqu','','[]','都则为一官半职，阻隔得千山万水。',16,'元曲/yuanqu.json','["都则为一官半职，阻隔得千山万水。"]'),
('yuanqu-254','中吕・普天乐','杨维桢','元','元曲','yuanqu','','[]','十月六日，云窝主者设燕于清香亭，侑卮者东平玉无瑕张氏也。',119,'元曲/yuanqu.json','["十月六日，云窝主者设燕于清香亭，侑卮者东平玉无瑕张氏也。", "酒半，张氏乞手乐章。", "为赋双飞燕调，俾度腔行酒以佐主宾。", "玉无瑕，春无价，清歌一曲，俐齿伶牙。", "斜簪剃髻花，紧嵌凌波袜。", "玉手琵琶弹初罢，怎教他流落天涯。", "抱来帐下，梨园弟子，学士人家。", "套数。"]'),
('yuanqu-255','斗哈蟆・堪悲，身国俱亡。把烟花山水，等闲无主。叹高台百尺，顿遭烈','杨维桢','元','元曲','yuanqu','','[]','休觑，珠翠总劫灰，繁华只废基。',33,'元曲/yuanqu.json','["休觑，珠翠总劫灰，繁华只废基。", "恼人意，叵耐范蠡扁舟，一片太湖烟水。"]'),
('yuanqu-256','锦衣香・馆娃宫，荆榛蔽。响さ廊，莓苔翳。可惜剩水残山，断崖高寺，','杨维桢','元','元曲','yuanqu','','[]','百花深处一僧归。',53,'元曲/yuanqu.json','["百花深处一僧归。", "空遗旧迹，走狗斗鸡。", "想当年僭祭，望郊台凄凉云树，香水鸳鸯去。", "酒城倾坠，茫茫练渎，无边秋水。"]'),
('yuanqu-257','浆水令・采莲泾红芳尽死，越来溪吴歌惨凄。宫中鹿走草萋萋，黍离故墟，','杨维桢','元','元曲','yuanqu','','[]','过客伤悲。',46,'元曲/yuanqu.json','["过客伤悲。", "离宫废，谁避暑？琼姬墓冷苍烟蔽。", "空原滴，空原滴，梧桐秋雨，台城上，台城上，夜乌啼。"]'),
('yuanqu-259','双调・新水令','蒲察善长','元','元曲','yuanqu','','[]','听楼头画鼓打三更，绣帏中枕余衾剩。',48,'元曲/yuanqu.json','["听楼头画鼓打三更，绣帏中枕余衾剩。", "明朗朗窗前月，昏惨惨榻前灯。", "我这里独倚定帏屏，檐间铁好难听！。"]'),
('yuanqu-260','驻马听・聒煞我也当当丁丁，恰便似再出世陈抟睡不成。度一宵如同百岁，','蒲察善长','元','元曲','yuanqu','','[]','捱一朝胜似三春。',41,'元曲/yuanqu.json','["捱一朝胜似三春。", "金炉香烬酒初醒，孤眠那怕心肠硬。", "闲愁可惯经？惟有相思最是难熬的症。"]'),
('yuanqu-261','乔牌儿・一回家睡不着独自个寝，非干是咱薄幸。没来由簪折瓶沉井，将','蒲察善长','元','元曲','yuanqu','','[]','鸳鸯两下里分。',7,'元曲/yuanqu.json','["鸳鸯两下里分。"]'),
('yuanqu-263','得胜令・担不得翠弯眉黛远山青，红馥馥桃脸褪朱唇。细袅袅杨柳腰肢瘦，','蒲察善长','元','元曲','yuanqu','','[]','齐臻臻青丝髻绾云。',38,'元曲/yuanqu.json','["齐臻臻青丝髻绾云。", "天生下精神，更那堪十指纤纤嫩。", "描不就丹青，比天仙少个净瓶。"]'),
('yuanqu-264','川拨棹・不由我泪盈盈，听长空孤雁声。我与你暂出门庭，听我丁宁。自','蒲察善长','元','元曲','yuanqu','','[]','别情人，雁儿，我其实捱不过衾寒枕冷，相思病积渐成。',25,'元曲/yuanqu.json','["别情人，雁儿，我其实捱不过衾寒枕冷，相思病积渐成。"]'),
('yuanqu-265','七弟兄・雁儿，你却是怎生？暂停，听我诉离情。一封书与你牢拴定，快','蒲察善长','元','元曲','yuanqu','','[]','疾忙飞过蓼花汀，听人家寝睡长门静。',17,'元曲/yuanqu.json','["疾忙飞过蓼花汀，听人家寝睡长门静。"]'),
('yuanqu-266','梅花酒・雁儿呀呀的叫几声，惊起那人听，说着咱名姓，他自有人相迎。','蒲察善长','元','元曲','yuanqu','','[]','从别后不见影，闪得人亡了魂灵。',43,'元曲/yuanqu.json','["从别后不见影，闪得人亡了魂灵。", "罗帷中愁怎禁，则为他挂心情。", "朝忘餐泪如倾，曲慵唱酒慵斟。"]'),
('yuanqu-267','收江南・雁儿，可怜见今宵独自个冷清清，你与我疾回疾转莫留停，山遥','蒲察善长','元','元曲','yuanqu','','[]','水远煞劳神。',26,'元曲/yuanqu.json','["水远煞劳神。", "雁儿，天道儿未明，且休要等闲寻伴宿沙汀。"]'),
('yuanqu-268','正宫・鹦鹉曲','白贲','元','元曲','yuanqu','','[]','侬家鹦鹉洲边住，是个不识字渔父。',31,'元曲/yuanqu.json','["侬家鹦鹉洲边住，是个不识字渔父。", "浪花中一叶扁舟，睡煞江南烟雨。"]'),
('yuanqu-270','双调・百字折桂令','白贲','元','元曲','yuanqu','','[]','弊裘尘土压征鞍鞭倦袅芦花，弓剑萧萧，一径入烟霞。',116,'元曲/yuanqu.json','["弊裘尘土压征鞍鞭倦袅芦花，弓剑萧萧，一径入烟霞。", "动羁怀西风木叶秋水兼葭，千点万点老树昏鸦，三行两行写长空哑哑雁落平沙。", "曲岸西边近水湾鱼网纶竿钓槎，断桥东壁傍溪山竹篱茅舍人家。", "满山满谷，红叶黄花，正是伤感凄凉时候，离人又在天涯。", "套数。"]'),
('yuanqu-271','黄钟・醉花阴','白贲','元','元曲','yuanqu','','[]','独倚屏山把玉纤屈，并鸳枕将归期算彻。',35,'元曲/yuanqu.json','["独倚屏山把玉纤屈，并鸳枕将归期算彻。", "一自玉人别，瘦骨岩岩，趱过裙腰摺。"]'),
('yuanqu-272','出队子・粉香一捻，不思量难弃舍。语怜檀口口咨嗟，情怨芳心心哽噎，','白贲','元','元曲','yuanqu','','[]','愁压蛾眉眉暗结。',8,'元曲/yuanqu.json','["愁压蛾眉眉暗结。"]'),
('yuanqu-273','幺・秦欢晋爱成吴越，料今生缘分拙。四时饮饣善强捱些，千种恩情有间','白贲','元','元曲','yuanqu','','[]','隔，海洋相思无处说。',10,'元曲/yuanqu.json','["隔，海洋相思无处说。"]'),
('yuanqu-274','神仗儿煞・菱花半缺，合欢带绝。楚岫云迷，蓝桥月缺。银瓶沉坠，琼簪','白贲','元','元曲','yuanqu','','[]','碎折。',51,'元曲/yuanqu.json','["碎折。", "锦筝应折弦难接，骖鸾梦宁贴，修鸳简更悲切。", "紫砚飞香，墨浮兰麝。", "蘸秋毫撇代喉舌，诉离情粉笺和泪写。"]'),
('yuanqu-275','仙吕・祆神急','白贲','元','元曲','yuanqu','','[]','绿阴笼小院，红雨点苍苔。',53,'元曲/yuanqu.json','["绿阴笼小院，红雨点苍苔。", "谁想东君也是人间客，纵分连理枝，谩解合欢带，伤春早是心地窄。", "愁山和闷海，畅会栽排。"]'),
('yuanqu-276','六幺遍・更别离怨，风流债。云归楚岫，月冷秦台。当时眷爱，如今阻隔。','白贲','元','元曲','yuanqu','','[]','准备从今因他害，伤怀，冷清清日月怎生捱？。',21,'元曲/yuanqu.json','["准备从今因他害，伤怀，冷清清日月怎生捱？。"]'),
('yuanqu-277','元和令・鸾交何日重？鸳梦几时再？清明前后约归期，到如今牡丹开。空','白贲','元','元曲','yuanqu','','[]','等待翠屏香里掩东风，铺陈下愁境界。',17,'元曲/yuanqu.json','["等待翠屏香里掩东风，铺陈下愁境界。"]'),
('yuanqu-278','赚尾・无情子规声更哀，畅好明白。既道不如归去，看你几声儿撺掇得那','白贲','元','元曲','yuanqu','','[]','人来？。',4,'元曲/yuanqu.json','["人来？。"]'),
('yuanqu-279','双调・新水令','白贲','元','元曲','yuanqu','','[]','离情不奈子规啼，更那堪困人天气。',36,'元曲/yuanqu.json','["离情不奈子规啼，更那堪困人天气。", "红玉软，绿云低。", "春昼迟迟，东风恨两眉系。"]'),
('yuanqu-280','风入松・玉钩闲控绣帘垂，半掩朱扉。宝鉴鸾台尽尘昧，凤凰箫谁品谁吹？','白贲','元','元曲','yuanqu','','[]','绣塌空闲枕犀，篆烟消香冷金猊。',15,'元曲/yuanqu.json','["绣塌空闲枕犀，篆烟消香冷金猊。"]'),
('yuanqu-281','不拜门・冷清清寂寞在香闺，闷恹恹潇洒在罗帏。画苔墙划短金锴，尚未','白贲','元','元曲','yuanqu','','[]','得回归。',4,'元曲/yuanqu.json','["得回归。"]'),
('yuanqu-283','胡十八・往常时星月底，雨云期。到如今成间阔，受孤栖，奈何楚岫冷烟','白贲','元','元曲','yuanqu','','[]','迷？当初时想伊，为伊，消玉体减香肌。',18,'元曲/yuanqu.json','["迷？当初时想伊，为伊，消玉体减香肌。"]'),
('yuanqu-284','离带歇拍煞・急煎煎愁滴相思泪，意悬悬慵拥鲛绡被。揽衣儿倦起，恨绵','白贲','元','元曲','yuanqu','','[]','绵，情脉脉，人千里。',41,'元曲/yuanqu.json','["绵，情脉脉，人千里。", "非是俺，贪春睡，勉强将鸳鸯枕欹。", "薄幸可憎才，只怕相逢在梦儿里。"]'),
('yuanqu-285','仙吕・一半儿拟美人八咏春梦','查德卿','元','元曲','yuanqu','','[]','梨花云绕锦香亭，胡蝶春融软玉屏，花外鸟啼三四声。',318,'元曲/yuanqu.json','["梨花云绕锦香亭，胡蝶春融软玉屏，花外鸟啼三四声。", "梦初惊，一半儿昏迷一半儿醒。", "春困琐窗人静日初曛，宝鼎香消火尚温，斜倚绣床深闭门。", "眼昏昏，一半儿微开一半儿盹。", "春妆自将杨柳品题人，笑捻花枝比较春，输与海棠三四分。", "再偷匀，一半儿胭脂一半儿粉。", "春愁厌听野鹊语雕檐，怕见杨花扑绣帘，拈起绣针还倒拈。", "两眉尖，一半儿微舒一半儿敛。", "春醉海棠红晕润初妍，杨柳纤腰舞自偏，笑倚玉奴娇欲眠。", "粉郎前，一半儿支吾一半儿软。", "春绣绿窗时有唾茸粘，银甲频将彩线ㄎ，绣到凤凰心自嫌。", "按春纤，一半儿端相一半儿掩。", "春夜柳绵扑槛晚风轻，花影横窗淡月明，翠被麝兰薰梦醒。", "最关情，一半儿温温一半儿冷。", "春情自调花露染霜毫，一种春心无处托，欲写写残三四遭。", "絮叨叨，一半儿连真一半儿草。"]'),
('yuanqu-286','南吕・醉太平寄情','查德卿','元','元曲','yuanqu','','[]','钗分凤凰，衾剩鸳鸯，锦笺遗恨爱花香，写新愁半张。',283,'元曲/yuanqu.json','["钗分凤凰，衾剩鸳鸯，锦笺遗恨爱花香，写新愁半张。", "晚妆楼阁空凝望，旧游台榭添惆怅，落花庭院又昏黄，正离人断肠。", "春情东风柳丝，细雨花枝，好春能有几多时？韶华迅指。", "芭蕉叶上鸳鸯字，芙蓉帐里鸾凰事，海棠亭畔鹧鸪词，问莺儿燕子。", "楼台管弦，院落秋千，香风淡淡月娟娟，朱帘半卷。", "香消玉腕黄金钏，歌残素手白罗扇，汗溶粉面翠花细，倚阑人未眠。", "春风管弦，夜月秋千，调风弄月醉花前，把花枝笑捻。", "千金曾许如花面，半生未了看花愿，一春长费买花钱。", "风流少年。", "清名先生子陵，隐者渊明，南州旧隐老云卿，为清高显名。", "一个向七里滩曾受君王聘，一个向五柳庄终受彭泽令，一个向百花洲不受宋朝征，与巢由共清。"]'),
('yuanqu-287','越调・柳营曲金陵故址','查德卿','元','元曲','yuanqu','','[]','临故国，认残碑，伤心六朝如逝水。',136,'元曲/yuanqu.json','["临故国，认残碑，伤心六朝如逝水。", "物换星移，城是人非，今古一枰棋。", "南柯梦一觉初回，北邙坟三尺荒堆。", "四围山护绕，几处树高低。", "谁，曾赋黍离离。", "江上烟艇闲，雨蓑干，渔翁醉醒江上晚。", "啼鸟关关，流水潺潺，乐似富春山。", "数声柔橹江湾，一钩香饵波寒。", "回头贪兔魄，失意放渔竿。", "看，流下蓼花滩。"]'),
('yuanqu-288','双调・蟾宫曲怀古','查德卿','元','元曲','yuanqu','','[]','问从来谁是英雄？一个农夫，一个渔翁。',144,'元曲/yuanqu.json','["问从来谁是英雄？一个农夫，一个渔翁。", "晦迹南阳，栖身东海，一举成功。", "八阵图名成卧龙，《六韬》书功在非熊。", "霸业成空，遗恨无穷。", "蜀道寒云，渭水秋风。", "层楼有感倚西风百尺层楼，一道秦淮，九点齐州。", "塞雁南来，夕阳西下，江水东流。", "愁极处消除是酒，酒醒时依旧多愁。", "山岳糟丘，糊海杯瓯。", "醉了方休，醒后从头。"]'),
('yuanqu-289','双调・庆东原','查德卿','元','元曲','yuanqu','','[]','达时务，薄利名，秋风吹动田园兴。',43,'元曲/yuanqu.json','["达时务，薄利名，秋风吹动田园兴。", "Θ瓜邵平，思莼季鹰，采菊渊明。", "清淡老生涯，进退知天命。"]'),
('yuanqu-290','鹧鸪天','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','完颜寿马住西京，风流慷慨煞惺惺。',70,'元曲/yuanqu.json','["完颜寿马住西京，风流慷慨煞惺惺。", "因迷散乐王金榜，致使爹爹捍离门。", "为路岐，恋佳人，金珠使尽没分文。", "贤每雅静看敷演：《宦门子弟错立身》。", "(下)。"]'),
('yuanqu-291','粉蝶儿','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','积世簪缨，家传宦门之裔，更那堪富豪之后。',44,'元曲/yuanqu.json','["积世簪缨，家传宦门之裔，更那堪富豪之后。", "看诗书，观史记，无心雅丽。", "乐声平，无非四时佳致。"]'),
('yuanqu-292','一封书','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','伊且住试听：唤取多娇金榜来，书房内等待。',60,'元曲/yuanqu.json','["伊且住试听：唤取多娇金榜来，书房内等待。", "休道侯门深似海，说与婆婆休虑猜，只道家中管待客。", "展华筵，已安排，是必教它疾快来。"]'),
('yuanqu-293','同前','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','哥哥听拜禀：它是伶伦一妇人，何须恁用心，谩终朝愁闷倾。',59,'元曲/yuanqu.json','["哥哥听拜禀：它是伶伦一妇人，何须恁用心，谩终朝愁闷倾。", "若要和它同共枕，恐怕你爹行生嗔。", "那时节，悔无因，玷辱家门豪富人。"]'),
('yuanqu-294','七精令','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','相公不在家里，老汉心下欢喜。',31,'元曲/yuanqu.json','["相公不在家里，老汉心下欢喜。", "看官不认是阿谁？我是一个佗背乌龟。"]'),
('yuanqu-295','梁州令','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','深感吾皇赐重职，官名播西京。',35,'元曲/yuanqu.json','["深感吾皇赐重职，官名播西京。", "但一心中政煞公平，清如水，明如镜，亮如冰。"]'),
('yuanqu-296','紫苏丸','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','伶伦门户曾经历，早不觉鬓发霜侵。',32,'元曲/yuanqu.json','["伶伦门户曾经历，早不觉鬓发霜侵。", "孩儿一个干家门，算来总是前生定。"]'),
('yuanqu-297','紫苏丸','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','奴家年少正青春，占州城煞有声名。',33,'元曲/yuanqu.json','["奴家年少正青春，占州城煞有声名。", "把梨园格范尽番腾，当场敷演人钦敬。"]'),
('yuanqu-298','桂枝香','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','孩儿听启，疾忙收拾。',68,'元曲/yuanqu.json','["孩儿听启，疾忙收拾。", "侵早已挂了招子，你却百般推抵。", "又不知你每，生着何意？生着何意？教娘呕气。", "靠着你，这的是求衣饭，不成误了看的。", "(旦)。"]'),
('yuanqu-299','同前','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','娘行听启，孩儿说与。',63,'元曲/yuanqu.json','["娘行听启，孩儿说与。", "如今病染着身，岂是奴家推抵。", "你只管苦苦，将人催逼，教奴怎地。", "娘，尽教它，任取红轮坠，尤它误看的。", "(末上)。"]'),
('yuanqu-300','同上','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','勾阑收拾，家中怎地？莫是我的孩儿，想是官身出去？你娘儿两个，休闲争气，休闲争气。',66,'元曲/yuanqu.json','["勾阑收拾，家中怎地？莫是我的孩儿，想是官身出去？你娘儿两个，休闲争气，休闲争气。", "婆婆且住，听说与：阵马挨楼满，不成误看的。", "(净上)。"]'),
('yuanqu-301','同上','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','适蒙台旨，教咱来至。',61,'元曲/yuanqu.json','["适蒙台旨，教咱来至。", "如今到得它家，相公安排筵席。", "勾谏罢却，勾阑罢却。", "休得收拾，疾忙前去，莫迟疑。", "你莫胡言语，我和你也棘赤。"]'),
('yuanqu-302','醉落魄','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','令人去久传音耗，至今不到。',40,'元曲/yuanqu.json','["令人去久传音耗，至今不到。", "(净上)心忙意急归来报。", "(旦上)得见情人，心下称怀抱。"]'),
('yuanqu-303','赏花时','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','憔悴容颜只为你，每日在书房攻甚诗书！(生)闲话且休提，你把这时行的传奇，(旦白)看掌记。',58,'元曲/yuanqu.json','["憔悴容颜只为你，每日在书房攻甚诗书！(生)闲话且休提，你把这时行的传奇，(旦白)看掌记。", "(生连唱)你从头与我再温习。"]'),
('yuanqu-304','排歌','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','听说因依，其中就里：一个负王魁；孟姜女千里送寒衣；脱像云卿鬼做媒；鸳鸯会，卓氏女；郭华因为买胭脂，琼莲女，船浪举，临江驿内再相会。',69,'元曲/yuanqu.json','["听说因依，其中就里：一个负王魁；孟姜女千里送寒衣；脱像云卿鬼做媒；鸳鸯会，卓氏女；郭华因为买胭脂，琼莲女，船浪举，临江驿内再相会。", "(又)。"]'),
('yuanqu-305','那吒令','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','这一本传奇，是《周孛太尉》；这一本传奇，是《崔护觅水》；这一本传奇，是《秋胡戏妻》；这一本是《关于王独赴单刀会》；这一本是《马践杨妃》。',72,'元曲/yuanqu.json','["这一本传奇，是《周孛太尉》；这一本传奇，是《崔护觅水》；这一本传奇，是《秋胡戏妻》；这一本是《关于王独赴单刀会》；这一本是《马践杨妃》。", "(又)。"]'),
('yuanqu-306','鹊踏枝','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','刘先主，跳檀溪；雷轰了荐福碑；丙吉教子立起宣帝；老莱子斑衣；包待制上陈州粜米；这一本是《孟母三移》。',55,'元曲/yuanqu.json','["刘先主，跳檀溪；雷轰了荐福碑；丙吉教子立起宣帝；老莱子斑衣；包待制上陈州粜米；这一本是《孟母三移》。", "(生唱)。"]'),
('yuanqu-307','乐安神','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','一从当日，心中指望燕莺期。',52,'元曲/yuanqu.json','["一从当日，心中指望燕莺期。", "功名不恋待何如？拚却和伊抛故里。", "不图身富贵，不去苦攻书，但只教两眉舒。", "(又)。"]'),
('yuanqu-308','六么序','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','一意随它去，情愿为路岐。',80,'元曲/yuanqu.json','["一意随它去，情愿为路岐。", "管甚么抹土搽灰，折莫擂鼓吹笛，点拗收拾。", "更温习几本杂剧，问甚么妆孤扮末诸般会，更那堪会跳索扑旗。", "只得同欢共乐同鸳被，冲州撞府，求衣觅食。"]'),
('yuanqu-309','尾声','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','我和你同心意，愿得百岁镇相随，尽老今生不暂离。',23,'元曲/yuanqu.json','["我和你同心意，愿得百岁镇相随，尽老今生不暂离。"]'),
('yuanqu-310','锁南枝','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','泼禽兽，没道理！书院中怎不攻文艺？指望你背紫腰金，怎知你不成器！因甚底，来这里？便与我，捍出去！(生)。',52,'元曲/yuanqu.json','["泼禽兽，没道理！书院中怎不攻文艺？指望你背紫腰金，怎知你不成器！因甚底，来这里？便与我，捍出去！(生)。"]'),
('yuanqu-311','同前换头','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','爹爹听咨启：孩儿又怎知？正在书房中独坐，忽见狗儿都管，与它同来至。',57,'元曲/yuanqu.json','["爹爹听咨启：孩儿又怎知？正在书房中独坐，忽见狗儿都管，与它同来至。", "我问它，只因甚的？它说道是爹爹，唤它至。", "(旦)。"]'),
('yuanqu-312','同前','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','相公听，奴拜启：它说道相公排宴会，特地唤取奴，来到这书房里。',50,'元曲/yuanqu.json','["相公听，奴拜启：它说道相公排宴会，特地唤取奴，来到这书房里。", "谁信道，都是计。", "智赚奴，望容恕。", "(净)。"]'),
('yuanqu-313','同前换头','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','思量老奴婢，只是怨恨你，两个将咱连累。',49,'元曲/yuanqu.json','["思量老奴婢，只是怨恨你，两个将咱连累。", "如今打得我，浑身上下都麻痹。", "要把刀，割下腿。", "告相公：沙八赤。"]'),
('yuanqu-314','玉交枝','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','只因痴迷，与王金榜同谐比翼。',61,'元曲/yuanqu.json','["只因痴迷，与王金榜同谐比翼。", "谁知被我爹捉住，拆散了鸳侣。", "情人去也不见踪，我如今在此无依倚。", "免不得寻个死处，免不得寻个死处。"]'),
('yuanqu-315','同前','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','略听说与，丧残生一命可惜。',60,'元曲/yuanqu.json','["略听说与，丧残生一命可惜。", "若还放得伊家去，恐把我每连累。", "寻思你去真惨凄，只得与你耽着罪。", "到前途作个道理，到前途作个道理。"]'),
('yuanqu-316','西地锦','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','当职心怀公正，更名播朝廷。',27,'元曲/yuanqu.json','["当职心怀公正，更名播朝廷。", "从官判断无私曲，管民乐升平。"]'),
('yuanqu-317','八声甘州','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','子规两三声，劝道不如归去，羁旅伤情。',60,'元曲/yuanqu.json','["子规两三声，劝道不如归去，羁旅伤情。", "花残莺老，虚度几多芳春。", "家乡万里，烟水万重，奈隔断鳞鸿无处寻。", "一身，似雪里杨花飞轻。"]'),
('yuanqu-318','同前换头','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','艰辛，登山渡水，见夕阳西下，玉兔东生。',61,'元曲/yuanqu.json','["艰辛，登山渡水，见夕阳西下，玉兔东生。", "牧童吹笛，惊动暮鸦投林。", "残霞散绮，新月渐明，望隐隐奇峰锁暮云。", "泠泠，见溪水围绕孤村。"]'),
('yuanqu-319','解三酲','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','奈行程路途劳顿，到黄昏转添愁闷。',71,'元曲/yuanqu.json','["奈行程路途劳顿，到黄昏转添愁闷。", "山回路僻人绝影，不觉长叹两三声。", "(旦)望断天涯无故人，便做铁打心肠珠泪倾。", "只伤着，蝇头微利，蜗角虚名。", "(卜)。"]'),
('yuanqu-320','同前换头','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','向村庄上借宿安此身，只邮孤馆萧条扃。',70,'元曲/yuanqu.json','["向村庄上借宿安此身，只邮孤馆萧条扃。", "(旦)想村醪易醒愁难醒。", "暗思昔情人，临风对月欢娱频宴饮，转教我添愁离恨。", "您今宵里，孤衾展转，谁与安存？。"]'),
('yuanqu-321','尾声','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','且宽心，休忧闷。',24,'元曲/yuanqu.json','["且宽心，休忧闷。", "放怀款款慢登程，借宿今宵安此身。"]'),
('yuanqu-322','江和水','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','离了家乡里，奔路途。',55,'元曲/yuanqu.json','["离了家乡里，奔路途。", "不知它在何州住？使我心中添愁闷。", "闪得我今日成孤另，渡水登山劳顿。", "未知何日，再与多情欢会？。"]'),
('yuanqu-323','紫花儿序','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','似这般失业，似这般逐浪随波，忍冷耽饥。',71,'元曲/yuanqu.json','["似这般失业，似这般逐浪随波，忍冷耽饥。", "来到这围墙直下，柳树周回，向这河中掬的长流水，洗了面皮。", "掠得我鬓发伶俐，着些个吐津儿润了，拨浪便入城池。"]'),
('yuanqu-324','四国朝','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','听得听得人呼唤，特特来此处。',14,'元曲/yuanqu.json','["听得听得人呼唤，特特来此处。"]'),
('yuanqu-325','金蕉叶','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','子这撇末区老赚，我学那刘耍和行踪步迹。',41,'元曲/yuanqu.json','["子这撇末区老赚，我学那刘耍和行踪步迹。", "敢一个小哨儿喉咽韵美，我说散嗽咳呵如瓶贮水。"]'),
('yuanqu-326','圣药王','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','更做《四不知》；《双斗医》；更做《风流浪子两相宜》；黄鲁直，《打得底》；《马明王村里会佳期》；更做《搬运太湖石》。',57,'元曲/yuanqu.json','["更做《四不知》；《双斗医》；更做《风流浪子两相宜》；黄鲁直，《打得底》；《马明王村里会佳期》；更做《搬运太湖石》。"]'),
('yuanqu-327','麻郎儿','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','我能添插更疾，一管笔如飞。',28,'元曲/yuanqu.json','["我能添插更疾，一管笔如飞。", "真字能抄掌记，更压着御京书会。"]'),
('yuanqu-328','尾声','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','正不过沿村转庄，撞工耕地。',39,'元曲/yuanqu.json','["正不过沿村转庄，撞工耕地。", "我若得妆旦色如鱼似水，背杖鼓有何羞！提行头怕甚的！。"]'),
('yuanqu-329','菊花新','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','路岐岐路两悠悠，不到天涯未肯休。',37,'元曲/yuanqu.json','["路岐岐路两悠悠，不到天涯未肯休。", "这的是子弟下场头。", "(旦上)挑行李怎禁生受。"]'),
('yuanqu-330','同前换头','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','休休，提起泪交流，那更担儿说重心忧。',70,'元曲/yuanqu.json','["休休，提起泪交流，那更担儿说重心忧。", "我亲朋知道，真个笑破人口。", "(旦)男儿到头，管终须，和你得成就。", "那时节有月登楼，无花永不酌酒。", "(末上唱)。"]'),
('yuanqu-331','扑灯蛾','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','你门不三思，红日渐西流。',64,'元曲/yuanqu.json','["你门不三思，红日渐西流。", "两人没来由，只管此迤逗。", "(生)爹行听分剖：奈担儿难担生受，更驴儿不肯快走。", "(旦)致令得，两人途路恁淹留。"]'),
('yuanqu-332','同前','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','孩儿离家去久，公公惑不度己。',70,'元曲/yuanqu.json','["孩儿离家去久，公公惑不度己。", "泼畜生因甚底，缘何尚然落后！(末)婆婆住休，又何用唧唧啾啾，料不是冤家不就头。", "且担着担儿，疾速向前走。", "(生唱)。"]'),
('yuanqu-333','尾声','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','终须共你同鸳偶，事到头如今不自由，那些个男儿得志秋。',26,'元曲/yuanqu.json','["终须共你同鸳偶，事到头如今不自由，那些个男儿得志秋。"]'),
('yuanqu-334','菊花新','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','深感当今圣主，恩赐金紫双鱼。',37,'元曲/yuanqu.json','["深感当今圣主，恩赐金紫双鱼。", "公心正直遍采访，治国安民，但愿得国泰岁时丰富。"]'),
('yuanqu-335','羽调排歌','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','自从当日，不见我儿，心下镇长忧虑，两眼长是泪双垂。',71,'元曲/yuanqu.json','["自从当日，不见我儿，心下镇长忧虑，两眼长是泪双垂。", "怎地孩儿为路岐？(合)今日里，得见你，焚香子父谢神祗。", "它乡里，重会遇，夫妻百岁效于飞(生)。"]'),
('yuanqu-336','同前','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','那日孩儿，私奔故里，历尽万山烟水。',42,'元曲/yuanqu.json','["那日孩儿，私奔故里，历尽万山烟水。", "途中寂寞痛伤悲，到了东平得见伊。", "(合同前)(旦)。"]'),
('yuanqu-337','三叠排歌','无名氏《宦门子弟错立身》','元','元曲','yuanqu','','[]','告恩官，听拜启：当日书房里，一意会佳期。',68,'元曲/yuanqu.json','["告恩官，听拜启：当日书房里，一意会佳期。", "蓦忽撞着伊公相，一时见却怒起，令人星夜捍分离。", "怎知道，今日做夫妻，谢得恩官作主议。", "……(并下)。"]'),
('yuanqu-338','越调・黄蔷薇过庆元贞燕燕别无甚孝顺，哥哥行在意殷勤。三纳子藤箱儿','高克礼','元','元曲','yuanqu','','[]','问肯，便待要锦帐罗帏就亲。',153,'元曲/yuanqu.json','["问肯，便待要锦帐罗帏就亲。", "唬得我惊急列蓦出卧房门，他措支刺扯住我皂腰裙，我软兀刺好话儿倒温存：“一来怕夫人，情性哏，二来怕误妾百年身。", "”又不曾看生见长，便这般割肚牵肠。", "唤奶奶酩子里赐赏，撮醋醋孩儿弄璋。", "断送得他萧萧鞍马出咸阳，只因他重重恩爱在昭阳，引惹得纷纷戈戟闹渔阳。", "哎，三郎，睡海棠，都则为一曲舞霓裳。"]'),
('yuanqu-339','李云英风送梧桐叶・仙吕/赏花时','李唐宾','元','元曲','yuanqu','','[]','雨泪流红翠袖斑，锦被分香凤枕闲。',38,'元曲/yuanqu.json','["雨泪流红翠袖斑，锦被分香凤枕闲。", "无计锁雕鞍，江空岁晚，何处问平安！(同下)。"]'),
('yuanqu-340','李云英风送梧桐叶・仙吕/点绛唇','李唐宾','元','元曲','yuanqu','','[]','镜破钗分，粉消香褪，萦力寸。',25,'元曲/yuanqu.json','["镜破钗分，粉消香褪，萦力寸。", "酒美花新，总是思家恨。"]'),
('yuanqu-341','李云英风送梧桐叶・油葫芦','李唐宾','元','元曲','yuanqu','','[]','悔杀当初不自忖，轻将罗袂分，今日个锦笺无路托鸿鳞。',74,'元曲/yuanqu.json','["悔杀当初不自忖，轻将罗袂分，今日个锦笺无路托鸿鳞。", "我如今瘦岩岩腰减罗裙褪，他那里急煎煎人远大涯近。", "昨日是秋，今日是春。", "叹光阴有尽情难尽，无计觅行云。"]'),
('yuanqu-342','李云英风送梧桐叶・天下乐','李唐宾','元','元曲','yuanqu','','[]','可正是一样相思两断魂，青也波春，断送了人，叹孤身恰如飞絮滚。',51,'元曲/yuanqu.json','["可正是一样相思两断魂，青也波春，断送了人，叹孤身恰如飞絮滚。", "虚飘飘离乱人，孤另另多病身，对轻风憔悴损。"]'),
('yuanqu-343','李云英风送梧桐叶・鹊踏枝','李唐宾','元','元曲','yuanqu','','[]','随侍着母亲，去游春，列两行侍妾丫环，簇拥定绣毂雕轮。',51,'元曲/yuanqu.json','["随侍着母亲，去游春，列两行侍妾丫环，簇拥定绣毂雕轮。", "虞候们行得来大紧，早来到耸青霄金碧山门。", "(虚下)。"]'),
('yuanqu-344','李云英风送梧桐叶・寄生草','李唐宾','元','元曲','yuanqu','','[]','是何处风流客，谁家年少人？他转回廊忙把身躯褪，我隔雕栏不敢题名问，他出山门不肯回头认。',65,'元曲/yuanqu.json','["是何处风流客，谁家年少人？他转回廊忙把身躯褪，我隔雕栏不敢题名问，他出山门不肯回头认。", "莫不是游仙梦里乍相逢，多管是武陵溪畔曾相近。"]'),
('yuanqu-345','李云英风送梧桐叶・醉中天','李唐宾','元','元曲','yuanqu','','[]','这书学宗秦汉摹唐晋。',115,'元曲/yuanqu.json','["这书学宗秦汉摹唐晋。", "这笔阵流三峡扫千军。", "好与俺男儿字逼真，一点画从头儿认，字法儿不差了半分。", "既传芳信，不题名却为何因？(云)虽然如此，天下人写的字多有一般的，未审是与不是，索和一首，若是俺丈夫见了，必寻我也。", "我试写在此咱。", "(唱)。"]'),
('yuanqu-346','李云英风送梧桐叶・后庭花','李唐宾','元','元曲','yuanqu','','[]','捻霜毫诉事因，别夫君又几春。',89,'元曲/yuanqu.json','["捻霜毫诉事因，别夫君又几春。", "思往事浑如梦，恨不的上青山便化身。", "拂绰了驻间尘，(云)我依着他韵，也做一首咱。", "(唱)待酬前韵，两三行字体匀，说当年夫妇恩。", "愿儿夫亲见闻，任傍人胡议论。"]'),
('yuanqu-347','李云英风送梧桐叶・青哥儿','李唐宾','元','元曲','yuanqu','','[]','也是我一旨、一言难尽，泼残生进退、进退无门，恰便似月待圆花待春。',74,'元曲/yuanqu.json','["也是我一旨、一言难尽，泼残生进退、进退无门，恰便似月待圆花待春。", "想当日阮肇刘展，采约寻真，花雨香云？隔断凡尘。", "尚儿自笙歌迎入，画堂春，他也有姻缘分。"]'),
('yuanqu-348','李云英风送梧桐叶・赚煞','李唐宾','元','元曲','yuanqu','','[]','听孩儿诉衷情，休嗔忿，(卜儿云)你是个女孩儿，题诗恐怕旁人耻笑。',178,'元曲/yuanqu.json','["听孩儿诉衷情，休嗔忿，(卜儿云)你是个女孩儿，题诗恐怕旁人耻笑。", "(正旦唱)有共他每笑哂，非是荒淫惹外人。", "(卜儿云)你题甚诗？(正旦唱)这词又不是道春情子曰诗云，暗伤神，雨泪纷纷，低首无言听处分。", "(卜儿怒云)虽然如此，你是女子，赓和他人词章，是何体面？(正旦云)母亲息怒，孩儿再不敢了也。", "(唱)则今日从朝至昏，不离分寸，酩子里向晚妆楼，目断楚台云。", "(同下)。"]'),
('yuanqu-349','李云英风送梧桐叶・正官/端正好','李唐宾','元','元曲','yuanqu','','[]','荐新凉，消残暑，落行云顷刻须臾。',30,'元曲/yuanqu.json','["荐新凉，消残暑，落行云顷刻须臾。", "翻江搅海惊涛怒，摇脱秋林木。"]'),
('yuanqu-350','李云英风送梧桐叶・滚绣球','李唐宾','元','元曲','yuanqu','','[]','荡岸芦，撼庭竹，送长江片帆归去，动群山万籁喧呼。',76,'元曲/yuanqu.json','["荡岸芦，撼庭竹，送长江片帆归去，动群山万籁喧呼。", "他翻手云，覆手雨，没定指性儿难据，乱纷纷败叶凋梧。", "则为你分开丹凤难成侣，吹断征鸿不寄书，使离人感叹嗟吁。"]'),
('yuanqu-351','李云英风送梧桐叶・倘秀才','李唐宾','元','元曲','yuanqu','','[]','有一等入椒桂穿洞房的似大王般敬伏，有一等扬腐儒起陋巷的以庶民比喻。',77,'元曲/yuanqu.json','["有一等入椒桂穿洞房的似大王般敬伏，有一等扬腐儒起陋巷的以庶民比喻。", "他也曾感动思乡汉高祖，催张翰，忆纯鲈，休官出帝都。", "(小旦云)姐姐这风真个大哩(正旦唱)。"]'),
('yuanqu-352','李云英风送梧桐叶・倘秀才','李唐宾','元','元曲','yuanqu','','[]','风呵！你略停止呼号怒容咱告覆，暂定息那颠狂性听咱嘱付，休信他刚道雌雄楚宋玉。',63,'元曲/yuanqu.json','["风呵！你略停止呼号怒容咱告覆，暂定息那颠狂性听咱嘱付，休信他刚道雌雄楚宋玉。", "敢劳你吹嘘力，相寻他飘荡的那儿夫，是必与离人做主。"]'),
('yuanqu-353','李云英风送梧桐叶・呆骨朵','李唐宾','元','元曲','yuanqu','','[]','你与我起青萍一阵阵吹将去，到天涯只在斯须。',75,'元曲/yuanqu.json','["你与我起青萍一阵阵吹将去，到天涯只在斯须。", "休恋他醉琼姬歌扇桃花，休摇动搅离人空庭翠竹。", "休入桃源洞，休过章台路。", "递一叶起商飚梧叶儿，恰便似寄青鸾肠断书。"]'),
('yuanqu-354','李云英风送梧桐叶・叨叨令','李唐宾','元','元曲','yuanqu','','[]','你管他送胡笳声断城头暮，休道他搅旌旗影动边城戍。',76,'元曲/yuanqu.json','["你管他送胡笳声断城头暮，休道他搅旌旗影动边城戍。", "休恋他逐歌声罗绮筵前舞，休从他传花信桃李园中入。", "你是吹来也么哥，是吹来也么哥，直吹到受凄凉鳏寡儿夫行驻。"]'),
('yuanqu-355','李云英风送梧桐叶・伴读书','李唐宾','元','元曲','yuanqu','','[]','顺手儿吹将去，一叶儿随风度。',48,'元曲/yuanqu.json','["顺手儿吹将去，一叶儿随风度。", "刮马儿也似回头不知处，谢天公肯念俺离人苦。", "飘然有似神灵助，旋起阶除。"]'),
('yuanqu-356','李云英风送梧桐叶・三煞','李唐宾','元','元曲','yuanqu','','[]','到春来向楼台度歌声轻敲檀板黄金缕，入庭院扇和气香引琼浆白玉壶。',78,'元曲/yuanqu.json','["到春来向楼台度歌声轻敲檀板黄金缕，入庭院扇和气香引琼浆白玉壶。", "园花鸣条，溪河解冻，柳叫青摇，桃萼红舒。", "花飞锦机，草偃青苔，梅落琼酥。", "帘垂槛曲，寒料峭透罗厨。"]'),
('yuanqu-357','李云英风送梧桐叶・二煞','李唐宾','元','元曲','yuanqu','','[]','到夏来竹床枕簟凉生处，茶罢轩窗梦觉余。',72,'元曲/yuanqu.json','["到夏来竹床枕簟凉生处，茶罢轩窗梦觉余。", "波皱鱼鳞，扇摇蝉翼，香袅龙涎，帘漾虾须。", "水面相牵荷蒂，池头远递莲香，波心摇落荷珠。", "凉生院宇，送微雨出云衢。"]'),
('yuanqu-358','李云英风送梧桐叶・煞尾','李唐宾','元','元曲','yuanqu','','[]','到秋来啾啾响和蛩吟絮，飒飒吹斜雁影孤。',199,'元曲/yuanqu.json','["到秋来啾啾响和蛩吟絮，飒飒吹斜雁影孤。", "感动秋声八月初，采扇题清班婕好，对景悲秋宋大夫。", "江上纷纷折败芦，田内潇潇偃禾黍。", "则送流萤入座隅，积渐雕零岸柳疏，荏苒荷盘老柄枯，飘尽丹枫落井梧。", "女怨凄凉滴泪珠，悲向晚窗忆征旅。", "到冬来羊角呼号最狠毒，走石飞沙满路途。", "透入毡帘酒力徂，寒助冰霜透体肤，袅尽清香冷篆炉。", "凛冽严凝挂冰箸，刮面穿衣怎遮护？四季中间无日无，惟有秋深更凄楚。", "怎当他，协和芭蕉夜窗雨。", "(同下)。"]'),
('yuanqu-359','李云英风送梧桐叶・中吕/粉蝶儿','李唐宾','元','元曲','yuanqu','','[]','粉悴脂憔，闷恹恹暗伤怀抱，困腾腾划损眉梢。',48,'元曲/yuanqu.json','["粉悴脂憔，闷恹恹暗伤怀抱，困腾腾划损眉梢。", "画堂深，朱户悄，雁书不到。", "情绪萧条，影儿孤，镜鸾羞照。"]'),
('yuanqu-360','李云英风送梧桐叶・醉春风','李唐宾','元','元曲','yuanqu','','[]','人去玉箫闲，云深外凤杳。',45,'元曲/yuanqu.json','["人去玉箫闲，云深外凤杳。", "梦魂无夜不关山，何日是了，了。", "长则是锦被捞笼，绮窗嗟叹，书楼凝眺。"]'),
('yuanqu-361','李云英风送梧桐叶・迎仙客','李唐宾','元','元曲','yuanqu','','[]','老尊亲错见了，失节罪难逃，妾身况兼年纪小。',99,'元曲/yuanqu.json','["老尊亲错见了，失节罪难逃，妾身况兼年纪小。", "(云)我想雁有雌雄一对，没了一个，再不入群，永为孤雁。", "(唱)若婿了再求婿，这是人不如鸟。", "母亲意下量度，(云)我是个相门之女，再嫁事于人。", "(唱)则恐被傍人笑。"]'),
('yuanqu-362','李云英风送梧桐叶・红绣鞋','李唐宾','元','元曲','yuanqu','','[]','一来是先王礼教，二来是唐宰相根苗，(卜儿云)今日主张不从，再休后悔。',94,'元曲/yuanqu.json','["一来是先王礼教，二来是唐宰相根苗，(卜儿云)今日主张不从，再休后悔。", "(正旦唱)弦断无心觅鸾胶。", "(卜儿云)你敢待守丈夫的消耗么？(正旦唱)芳心悬玉杵，旧约在蓝桥，哎！则我个云英怎生便嫁了？。"]'),
('yuanqu-363','李云英风送梧桐叶・普天乐','李唐宾','元','元曲','yuanqu','','[]','玉娉婷，新梳掠，曲弯弯柳眉青浅，香馥馥桃脸红娇。',97,'元曲/yuanqu.json','["玉娉婷，新梳掠，曲弯弯柳眉青浅，香馥馥桃脸红娇。", "腰肢一捻轻，举止十分俏，便似画真儿描不成如花貌。", "有三般儿比并妖娆，(卜儿云)是那三般儿？(正旦唱)若耶溪西施戏瓢，九龙池玉环斗草，凤凰台秦女吹箫。"]'),
('yuanqu-364','李云英风送梧桐叶・上小楼','李唐宾','元','元曲','yuanqu','','[]','这彩偻百尺其高，势压着南山北岳。',87,'元曲/yuanqu.json','["这彩偻百尺其高，势压着南山北岳。", "六曲阑干，四面帘栊，一片旌旄。", "彩扇交，锦帐飘，余珠错落，盼望他娇滴滴袅香风玉人来到。", "(小旦云)姐姐。", "你扶我上彩楼去来。", "(做上楼科)(正旦唱)。"]'),
('yuanqu-365','李云英风送梧桐叶・脱布衫','李唐宾','元','元曲','yuanqu','','[]','喷香风扑鼻葡萄，揭青天聒耳笙箫。',32,'元曲/yuanqu.json','["喷香风扑鼻葡萄，揭青天聒耳笙箫。", "列翠袖金钗两行，光绰绰从人争导。"]'),
('yuanqu-366','李云英风送梧桐叶・小梁州','李唐宾','元','元曲','yuanqu','','[]','烟袅金炉宝篆烧，傍云锦衣飘，群仙引领下青霄。',32,'元曲/yuanqu.json','["烟袅金炉宝篆烧，傍云锦衣飘，群仙引领下青霄。", "忙传报，蹀躞马蹄遥。"]'),
('yuanqu-367','李云英风送梧桐叶・幺篇','李唐宾','元','元曲','yuanqu','','[]','雀屏银烛相辉耀，隐芙蓉绣褥光摇。',67,'元曲/yuanqu.json','["雀屏银烛相辉耀，隐芙蓉绣褥光摇。", "重奏乐，人欢笑，六街喧闹，春色醉仙桃。", "(任做见正旦掉眼科)(正旦云)你看这状元，赴了琼林宴也。", "(唱)。"]'),
('yuanqu-368','李云英风送梧桐叶・石榴花','李唐宾','元','元曲','yuanqu','','[]','状元微醉据鞍轿，猩血锦宫袍。',119,'元曲/yuanqu.json','["状元微醉据鞍轿，猩血锦宫袍。", "嘶风缓辔玉骢骄，猛抬头觑着多娇。", "(小旦抛绣球下科)(正旦云)看绣球哩！(任继图云)山妻未知下落，若贪富贵，乃不义之人也。", "(做不接科)(正旦唱)见状元高点玉鞭梢，似踌躇待接还抛。", "既然他有意来推凋，又索别打那英豪。"]'),
('yuanqu-369','李云英风送梧桐叶・斗鹌鹑','李唐宾','元','元曲','yuanqu','','[]','再寻个凤友鸾交，分甚么文强武弱。',110,'元曲/yuanqu.json','["再寻个凤友鸾交，分甚么文强武弱。", "(正旦看外科)(唱)只要得女貌郎才，不枉了一双两好。", "有福分先夺春风翡翠巢，(小旦打着花状元递丝鞭科)(正旦云)妹子，后面状元接了丝鞭也。", "(唱)美姻缘天凑巧。", "成就了锦片前程，常则是同欢到老。"]'),
('yuanqu-370','李云英风送梧桐叶・耍孩儿','李唐宾','元','元曲','yuanqu','','[]','欢声鼎沸长安道，得志当今贵豪。',66,'元曲/yuanqu.json','["欢声鼎沸长安道，得志当今贵豪。", "小登科接着大登科，播荣名喧满皇朝。", "始知学乃身之宝，惟有读书人最高。", "宫花斜插乌纱帽，紫袍称体，金带垂腰。"]'),
('yuanqu-371','李云英风送梧桐叶・三煞','李唐宾','元','元曲','yuanqu','','[]','那状元意迟迟点着玉鞭，不转睛厮觑着。',101,'元曲/yuanqu.json','["那状元意迟迟点着玉鞭，不转睛厮觑着。", "(带云)这状元是俺男儿也呵！(唱)扑簌簌泪点儿腮边落。", "他形容好似俺亲夫婿，欲待相亲又恐错认了。", "不敢分明道，知他真心儿认我，莫不是有意儿相调？(各做意儿科)(正旦唱)。"]'),
('yuanqu-372','李云英风送梧桐叶・煞尾','李唐宾','元','元曲','yuanqu','','[]','一星星告与父母，好共歹从他窨约。',39,'元曲/yuanqu.json','["一星星告与父母，好共歹从他窨约。", "那状元多是张京兆，若得相逢把黛眉扫。", "(同下)。"]'),
('yuanqu-373','李云英风送梧桐叶・双调/新水令','李唐宾','元','元曲','yuanqu','','[]','华堂褥隐绣芙蓉。',49,'元曲/yuanqu.json','["华堂褥隐绣芙蓉。", "似锦妆成桃源仙洞。", "这状元簪花在玉殿前，那状元折桂在月宫中。", "孔雀屏风，今日个已高中。"]'),
('yuanqu-374','李云英风送梧桐叶・驻马听','李唐宾','元','元曲','yuanqu','','[]','和羽流宫，一派笙歌彻太空；烹龙炮凤，满堂罗绮霭香风。',90,'元曲/yuanqu.json','["和羽流宫，一派笙歌彻太空；烹龙炮凤，满堂罗绮霭香风。", "想当初云英不利广寒宫，裴航空作游仙梦。", "只今日蓝桥路不通，玄霜玉杵成何用？(正旦与任见科)(背云)这个状元，好似俺男儿也。", "(唱)。"]'),
('yuanqu-375','李云英风送梧桐叶・乔牌儿','李唐宾','元','元曲','yuanqu','','[]','都只在嫣然笑一中，偷把幽情送。',31,'元曲/yuanqu.json','["都只在嫣然笑一中，偷把幽情送。", "他含颦不语把肩儿竦，推将宝带松。"]'),
('yuanqu-376','李云英风送梧桐叶・沉醉东风','李唐宾','元','元曲','yuanqu','','[]','为兵戈担惊受恐，折夫妻断梗飘蓬。',49,'元曲/yuanqu.json','["为兵戈担惊受恐，折夫妻断梗飘蓬。", "泣枕鸳，悲衾凤，谁知道这搭儿重逢。", "犹道相看是梦中，捱了些凄凉万种。"]'),
('yuanqu-377','李云英风送梧桐叶・川拨棹','李唐宾','元','元曲','yuanqu','','[]','想当日恨冲冲，乱离间家业空。',40,'元曲/yuanqu.json','["想当日恨冲冲，乱离间家业空。", "浪迹浮踪，水远山重。", "逃命出枪尖剑锋，谢大恩人厮敬重。"]'),
('yuanqu-378','李云英风送梧桐叶・梅花酒','李唐宾','元','元曲','yuanqu','','[]','倚栏杆数断鸿，起阵狂风，吹落梧桐，飘入帘栊。',71,'元曲/yuanqu.json','["倚栏杆数断鸿，起阵狂风，吹落梧桐，飘入帘栊。", "手亲题一首诗，写离恨在其中。", "为家乡信未通，题待罢告天公，替雁帖当鱼封。", "风卷起入长空，任南北与西东。"]'),
('yuanqu-379','李云英风送梧桐叶・收江南','李唐宾','元','元曲','yuanqu','','[]','呀！我则道风吹一去杳无踪，似题红叶出深宫，泪痕相映墨痕浓。',44,'元曲/yuanqu.json','["呀！我则道风吹一去杳无踪，似题红叶出深宫，泪痕相映墨痕浓。", "喜今朝再逢，想昨宵魂梦与君同。"]'),
('yuanqu-380','李云英风送梧桐叶・鸳鸯煞','李唐宾','元','元曲','yuanqu','','[]','我则道凉宵衾枕无人共，谁承望洞房花烛笙歌送。',120,'元曲/yuanqu.json','["我则道凉宵衾枕无人共，谁承望洞房花烛笙歌送。", "乐事重重，喜气融融。", "畅道人月团圆，鱼水和同，依旧的举案齐眉，到老相陪奉。", "若不是这一叶梧桐，险些儿失落了半世夫妻旧恩宠。", "(任继图诗云)夫妻守节事堪怜，仗义施恩宰相贤。", "金榜挂名双及第，洞房花烛两团圆。"]'),
('yuanqu-381','庞涓夜走马陵道・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','想着咱转笔抄书几度春，常则是刺股悬梁不厌勤。',47,'元曲/yuanqu.json','["想着咱转笔抄书几度春，常则是刺股悬梁不厌勤。", "你今日践红尘，只愿你此去呵功名有准，早开阁画麒麟。"]'),
('yuanqu-382','庞涓夜走马陵道・幺篇','无名氏','元','元曲','yuanqu','','[]','抵多少西出阳关无故人，一种离愁两断魂。',67,'元曲/yuanqu.json','["抵多少西出阳关无故人，一种离愁两断魂。", "我越送越关亲，好割不断弟兄的义分，(带云)兄弟，你稳登前程。", "(唱)早过了五里这坐杏花村。", "(下)。"]'),
('yuanqu-383','庞涓夜走马陵道・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','遮莫他盖世英雄，驱兵拥众，你可也休惊恐。',39,'元曲/yuanqu.json','["遮莫他盖世英雄，驱兵拥众，你可也休惊恐。", "若是和俺孙膑交锋，只当似掌股上婴儿弄。"]'),
('yuanqu-384','庞涓夜走马陵道・油葫芦','无名氏','元','元曲','yuanqu','','[]','我这里布网张罗打大虫，谁着你将军校冲，早沙场上杀的血染马蹄红。',187,'元曲/yuanqu.json','["我这里布网张罗打大虫，谁着你将军校冲，早沙场上杀的血染马蹄红。", "(郑安平打阵科，云)哥也，到的这阵里面，可怎生东西南北都不省的了也？(正末云)是甚么人？快与我拿将来。", "(卒子拿郑安平科)(正末唱)则你那三更不应君王梦，可兀的一身枉请皇家俸。", "我将你捉在马前，你今日落在彀中。", "谁着你不明白撞入我这迷魂洞，不由我忿气欲填胸。", "(郑安平云)师父可怜见，不干我事，都是庞元帅来。", "(正末唱)。"]'),
('yuanqu-385','庞涓夜走马陵道・天下乐','无名氏','元','元曲','yuanqu','','[]','可不道将在谋不在勇，哎，只你个英也波雄，枉用功，我如今捉获你对咱妆懵懂。',121,'元曲/yuanqu.json','["可不道将在谋不在勇，哎，只你个英也波雄，枉用功，我如今捉获你对咱妆懵懂。", "(云)大小三军，将那厮夺下鞍马，剥去衣甲，休教走了也。", "(郑安平云)将我鞍马衣甲都收了，教我怎么回去见元帅？(正末唱)一壁厢扯了锦袍，一壁厢牵了玉骢，我看你怎生还本阵中？。"]'),
('yuanqu-386','庞涓夜走马陵道・后庭花','无名氏','元','元曲','yuanqu','','[]','我喜的是弟兄每两意同，你则待执轮竿作钓翁。',348,'元曲/yuanqu.json','["我喜的是弟兄每两意同，你则待执轮竿作钓翁。", "哀告这掌军权的燕孙膑。", "(带云)兄弟请起。", "(唱)请起你个梦非熊的姜太公。", "若到那殿庭中，怎忘了弟兄的情重，(庞涓云)哥也，若公子问呵，休说哥哥好、兄弟歹，则说俺两个摆阵势是一般儿的。", "(正末云)兄弟，我知道了也。", "(唱)我对大人行会脱空。", "(庞涓云)哥哥，这都是兄弟的不是了，只愿哥哥想咱旧日契交朋友。", "今日举荐为官，也是不忘盟誓之意。", "假若公子问呵，谁输谁赢，哥哥您则善言咱。", "(正末云)兄弟，你放心者。", "我和你见公子去来。", "(公子云)孙先生。", "我问你，两家摆阵势，谁输谁赢？你从头实说咱。", "(正末云)公子，贫道与元帅都是鬼谷先生弟子。", "虽同传授，各用心机。", "便是元帅也有不知贫道演习的去处，贫道也有不知元帅的去处，总之一般。", "(公子云)虽然如此，好歹岂没个赢没个输的？(正末唱)。"]'),
('yuanqu-387','庞涓夜走马陵道・金盏儿','无名氏','元','元曲','yuanqu','','[]','他那里一一问行踪，俺兄弟悄悄的嘶过从。',148,'元曲/yuanqu.json','["他那里一一问行踪，俺兄弟悄悄的嘶过从。", "好教我意踌躇，两下里可兀的难趋奉。", "我待不说呵，怎生支对主人公；待说呵，我和他书窗曾最密。", "怎宦路个不相容。", "(公子云)孙先生，你怎生不言语？(正末唱)我正是满怀心腹事，尽在不言中。", "(公子云)孙先生，你恰才摆阵时毕竟是谁输谁赢？(正末云)公子，听贫道说咱。", "(唱)。"]'),
('yuanqu-388','庞涓夜走马陵道・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','我如今奉敕蒙宣统士卒，则为这荧惑离宫失位所。',51,'元曲/yuanqu.json','["我如今奉敕蒙宣统士卒，则为这荧惑离宫失位所。", "我望帝阙近皇都连发了三枝箭羽，早没半霎儿将火星除。", "(下)。"]'),
('yuanqu-389','庞涓夜走马陵道・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','祸临头，谁人救，则我这泼残生眼见的千死千休。',49,'元曲/yuanqu.json','["祸临头，谁人救，则我这泼残生眼见的千死千休。", "谁着你把箭三枝连射三更后，哎！你也合将那传令的人追究。"]'),
('yuanqu-390','庞涓夜走马陵道・滚绣球','无名氏','元','元曲','yuanqu','','[]','我可也为国愁，为国忧，为知心数年交厚，我恨不的并吞了六国诸侯。',99,'元曲/yuanqu.json','["我可也为国愁，为国忧，为知心数年交厚，我恨不的并吞了六国诸侯。", "这江山和宇宙，士女共军州，都待着俺邦情受，怎知道运拙也志愿难酬。", "哎，孙膑也！不争你谗言谮语遭人构，直感的野草闲花满地愁。", "那里也正首孤丘。"]'),
('yuanqu-391','庞涓夜走马陵道・倘秀才','无名氏','元','元曲','yuanqu','','[]','哎！我说一句钢刀豁口，觑一觑金瓜碎首，我可甚一旦无常万事休。',69,'元曲/yuanqu.json','["哎！我说一句钢刀豁口，觑一觑金瓜碎首，我可甚一旦无常万事休。", "我不合鸣金鼓、统戈矛，(带云)我本无罪过，怎要杀坏我也？(唱)这便的是我犯由。"]'),
('yuanqu-392','庞涓夜走马陵道・滚绣球','无名氏','元','元曲','yuanqu','','[]','这法场近御沟，对凤楼，(带云)冤屈也！(唱)我这里叫尽屈有谁来分剖。',491,'元曲/yuanqu.json','["这法场近御沟，对凤楼，(带云)冤屈也！(唱)我这里叫尽屈有谁来分剖。", "送的我眼睁睁有国难投。", "强缚住我这调羹补衮的手，掩住我这衔冤负屈的口。", "这都是我自作自受，也不专为那人怨人仇。", "哀哉故国难回首。", "可正是烦恼皆因强出头，便死何求！(宠涓上，云)我教郑安平代做监斩官，起建法场，杀坏孙膑。", "如今往法场上过，我则推不知道。", "摆开头躇，慢慢的行。", "我是个朝中有功之人，今日敕赐与我十瓶黄封御酒，我多饮了几杯，我好快活也。", "(做唱科)(唱)今宵酒醒伺处。", "杨柳岸晓风残月。", "(正末云)兀的不是宠涓过来也！我明知道他杀坏我，我着他救我咱。", "我临行时师父曾与我一计，若遇祸难临头。", "有人唱道：今宵酒醒何处，杨柳岸晓风残月。", "你可诉出心间之事，就得不死。", "我如今不说，等待何时！两街百姓，我死不紧，只可惜我腹中有卷《六甲》天书。", "不曾传授与人。", "若有人救了我的性命。", "我情愿传写与他，决无隐讳。", "(宠涓惊私，云)嗨！师父好歹也！将这《六甲》天书倒传与他。", "传与我的天书，原来是假的。", "我如今独霸六国，料无对手，若再得这天书呵，还有谁人近的我？当日他摆出阵来。", "我不认的那个阵势，可知道他在天书里面摘下来的。", "我若杀了这厮，便是绝了这天书也。"]'),
('yuanqu-393','庞涓夜走马陵道・白鹤子','无名氏','元','元曲','yuanqu','','[]','他对着我急煎煎的忙问取。',79,'元曲/yuanqu.json','["他对着我急煎煎的忙问取。", "我对着他悄促促的说情由。", "(庞涓云)哥也。", "我若知情呵，唾是命随灯而灭。", "(正末唱)只道他含着泪苦滴滴的假慈悲，却原来指着灯碜可可的言盟咒。"]'),
('yuanqu-394','庞涓夜走马陵道・脱布衫','无名氏','元','元曲','yuanqu','','[]','我道你搜寻出百样机谋，翻惹下千种闲愁。',42,'元曲/yuanqu.json','["我道你搜寻出百样机谋，翻惹下千种闲愁。", "则你个为昔日同堂故友，怎惜得这殷勤尽心儿搭救。"]'),
('yuanqu-395','庞涓夜走马陵道・滚绣球','无名氏','元','元曲','yuanqu','','[]','你休那里信口诌，(刽子云)我不说谎。',128,'元曲/yuanqu.json','["你休那里信口诌，(刽子云)我不说谎。", "(正末唱)则管里无了收，这言语你也合三思然后，俺兄弟怎肯道东涧东流。", "(带云)俺两个说誓来，(唱)他亏我似猪狗。", "我亏他似马牛，俺两个曾对天说咒，俺兄弟他怎肯火上浇油。", "俺两个胜如管鲍分金义，休猜做孙庞刖足仇，枉惹得万代名留。"]'),
('yuanqu-396','庞涓夜走马陵道・二煞','无名氏','元','元曲','yuanqu','','[]','我饮过这香喷喷三盏儿安魂酒，则被你闪杀我也血渌渌一双脚指头。',96,'元曲/yuanqu.json','["我饮过这香喷喷三盏儿安魂酒，则被你闪杀我也血渌渌一双脚指头。", "刀落处鼻痛心酸，皮开肉绽，筋骨相离，鲜血浇流。", "哎，可怎生神嚎鬼哭，雾惨云昏，白日为幽。", "耳边厢只听得半空中风吼，莫不是相天地替人愁！。"]'),
('yuanqu-397','庞涓夜走马陵道・煞尾','无名氏','元','元曲','yuanqu','','[]','兄弟，则这功名成就合成就，我得好休时便好休。',138,'元曲/yuanqu.json','["兄弟，则这功名成就合成就，我得好休时便好休。", "养可疮海上游，洗了耳觅许由，学太公把钓钩，逐范蠡一叶舟。", "想荣华风内烛，富贵如水上沤，将利名一笔勾，再不向杀人场揽祸尤，白白的将性命丢。", "攒住眉头懒转眸，咬定牙儿且忍羞。", "打熬着足上浸浸血水流。", "哎，你个行刃的哥哥，你畅好是下的手。", "(下)。"]'),
('yuanqu-398','庞涓夜走马陵道・双调/新水令','无名氏','元','元曲','yuanqu','','[]','打独磨来到画桥四，恰便似出笼鹰剪折厂我这双翼。',53,'元曲/yuanqu.json','["打独磨来到画桥四，恰便似出笼鹰剪折厂我这双翼。", "自知毛羽短，怎敢扑天飞。", "我则索做哑妆痴，儿回家阁不住眼中泪。"]'),
('yuanqu-399','庞涓夜走马陵道・步步娇','无名氏','元','元曲','yuanqu','','[]','想当初在云梦山中把天书习，定道是取将相能容易。',68,'元曲/yuanqu.json','["想当初在云梦山中把天书习，定道是取将相能容易。", "谁知有这日，生把俺七尺长躯打灭的无存济。", "哎哟！天那！甚日得遂风雷？也吐出俺这三千丈虹霓气。"]'),
('yuanqu-400','庞涓夜走马陵道・搅筝琶','无名氏','元','元曲','yuanqu','','[]','见一个狠公吏，叫一声似春雷，唬的那几个作耍顽童，都一时间潜在那里。',252,'元曲/yuanqu.json','["见一个狠公吏，叫一声似春雷，唬的那几个作耍顽童，都一时间潜在那里。", "(卒子云)兀那风子，你脚上疮疤疼痛，如今可好了么？(正末唱)起动你问我疮疾，我可也皱定双眉。", "(做悲科，云)我好疼哩！我好疼哩！(唱)堪悲！休则管絮絮聒聒，扯扯拽拽，痛不痛我足下须自知，索甚猜疑。", "(卒子云)兀那风子，你看我这手里拿的甚么？(正末云)是馒头。", "(卒子云)这个是甚么？(正末云)这个你则道我不知哩，这个是糕糜。", "(卒子云)你吃馒头好，吃糕糜好？(正末云)我则吃糕糜。", "(卒子云)你吃糕糜，要发病伤人也。", "(正末云)我则要吃糕糜。", "(唱)。"]'),
('yuanqu-401','庞涓夜走马陵道・雁儿落','无名氏','元','元曲','yuanqu','','[]','我常担着空肚皮，(卒子云)你几曾见这等好茶饭来？(正末唱)好茶饭几曾道尝滋味。',81,'元曲/yuanqu.json','["我常担着空肚皮，(卒子云)你几曾见这等好茶饭来？(正末唱)好茶饭几曾道尝滋味。", "虽然我脚尖上有病疾，(卒子云)你休吃，则怕发了你的疮。", "(正末唱)我心儿里倒也无闲气。"]'),
('yuanqu-402','庞涓夜走马陵道・挂玉钩','无名氏','元','元曲','yuanqu','','[]','我这里吐胆倾心说与伊，难道你不解其中意？(卜商云)先生何不跟我馆驿中去来。',168,'元曲/yuanqu.json','["我这里吐胆倾心说与伊，难道你不解其中意？(卜商云)先生何不跟我馆驿中去来。", "(正末云)你先行，我随后便到也。", "(卜商云)你不与我同去。", "可是为何？(正末唱)我则怕路上行人口胜碑，(卜商云)先生，我须不是故意来赚你的。", "(正末唱)咱两个都心会。", "(卜商云)小官此一来。", "专为先生，别无他干。", "(正末唱)既然是你为我来，须回避。", "且做个面北眉南，你东咱西。"]'),
('yuanqu-403','庞涓夜走马陵道・殿前欢','无名氏','元','元曲','yuanqu','','[]','那唤我的却为谁？(卜商云)先生，你在那里来？(正末唱)在那摘星楼上我便做筵席。',188,'元曲/yuanqu.json','["那唤我的却为谁？(卜商云)先生，你在那里来？(正末唱)在那摘星楼上我便做筵席。", "安排下脱壳金蝉计，我则索躲是逃非。", "(卜商云)庞涓贼，你好狠也。", "(正末唱)这的是他下的我也下的。", "(卜商云)先生，庞涓又来了也。", "(正末唱)哎！缠杀我也天魔祟，我便似小鬼般合扑地。", "(卜商云)你躲时节谁知道来？(正末唱)这公事则除天知地知，(带云)庞涓。", "你怎知我在这里吃茶饭哩。", "(唱)只半合儿使碎我这心机。"]'),
('yuanqu-404','庞涓夜走马陵道・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','打一轮皂盖轻车，按天书把三军摆设，谁识俺这阵似长蛇。',62,'元曲/yuanqu.json','["打一轮皂盖轻车，按天书把三军摆设，谁识俺这阵似长蛇。", "端的个角生风，旗掣电，弓弯秋月。", "喊一声海沸山裂，管杀的他众儿郎不能相借。"]'),
('yuanqu-405','庞涓夜走马陵道・醉春风','无名氏','元','元曲','yuanqu','','[]','我将这乌龙墨恰研浓，我将这紫兔毫深蘸彻。',124,'元曲/yuanqu.json','["我将这乌龙墨恰研浓，我将这紫兔毫深蘸彻。", "(写科)(诗云)白杨树下白杨峪，正是庞涓合死处。", "今夜不斩魏人头，孙膑不还齐国去。", "(公子云)你看写着甚么哩？(正末唱)道不离此处斩庞涓，我亲自的写、写。", "一来是孙膑的计谋：二来是主公的福分，第三来单注着那人合灭。"]'),
('yuanqu-406','庞涓夜走马陵道・石榴花','无名氏','元','元曲','yuanqu','','[]','笑庞涓敢逞尽十分劣，逐定咱不相撇。',76,'元曲/yuanqu.json','["笑庞涓敢逞尽十分劣，逐定咱不相撇。", "争知这马陵道上有拦截，山崖一斗绝，树林稠叠。", "万张强弩齐攒射，敢立化了一堆鲜血。", "总便有三头六臂天生别，到其间那里好藏遮。"]'),
('yuanqu-407','庞涓夜走马陵道・斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','俺和他同堂友至契至交，须不是被傍人厮间厮渫。',86,'元曲/yuanqu.json','["俺和他同堂友至契至交，须不是被傍人厮间厮渫。", "俺可也为甚么相贼相残，都是他平日里自作自孽。", "他把切骨的冤仇死也似结，怎教俺便忘了者。", "俺如今拚的个不做不休，这就是至诚心为人为彻。"]'),
('yuanqu-408','庞涓夜走马陵道・幺篇','无名氏','元','元曲','yuanqu','','[]','他那里语未绝，俺这里箭早拽。',246,'元曲/yuanqu.json','["他那里语未绝，俺这里箭早拽。", "则见他蓦涧穿林，钻天入地，急切难迭。", "脚趔趄，眼乜斜，恰便似酒酣时节，庞涓也休猜做杨柳岸晓风残月。", "(庞涓云)此处莫不有埋伏的军马么？不中，我只索倒回干戈，领军去也。", "(孙膑云)庞涓，你那里去？大小三军，与我围定了峪口者。", "休教走了庞涓！(庞涓云)兀的不唬杀我也！高阜处说话，好似我孙膑哥哥。", "我是叫他一声咱。", "孙膑哥哥！(正末云)叫我的是谁？(庞涓云)是您兄弟庞涓。", "(正末云)你叫我怎么？(庞涓云)多时不见哥哥，我心中好生想你也！(正末云)你那贼，却元来也有今日哩！(唱)。"]'),
('yuanqu-409','庞涓夜走马陵道・快活三','无名氏','元','元曲','yuanqu','','[]','俺把心中事明诉说，您把诗中句细披阅。',62,'元曲/yuanqu.json','["俺把心中事明诉说，您把诗中句细披阅。", "大古来有甚费周折，多咱是您勾魂帖。", "(庞涓云)哥哥可怜见！是您兄弟的不是了也。", "(正末唱)。"]'),
('yuanqu-410','庞涓夜走马陵道・朝天子','无名氏','元','元曲','yuanqu','','[]','我可也不为别，是你亲曾把誓设，(庞涓云)兀的不灭了这盏灯也，(正末唱)正应着唾是命随灯灭。',144,'元曲/yuanqu.json','["我可也不为别，是你亲曾把誓设，(庞涓云)兀的不灭了这盏灯也，(正末唱)正应着唾是命随灯灭。", "(庞涓做拜科，云)哥哥可怜见，只饶过您兄弟咱。", "(正末唱)庞涓你既做了这业又何必恁怯，枉了也参拜无休歇。", "哎！则你个脸儿假热，心儿似铁，忍下的眼睁睁把我双足刖。", "你如今死也，再休想放舍，恰便似水底捞明月。"]'),
('yuanqu-411','庞涓夜走马陵道・十二月','无名氏','元','元曲','yuanqu','','[]','他那里自推自跌，从今后义断恩绝。',81,'元曲/yuanqu.json','["他那里自推自跌，从今后义断恩绝。", "(庞涓云)哥哥。", "咱和你是同心共胆的好朋友，饶过我者！(正末唱)你道是同心共胆，还待要骗口张舌。", "我问你三回两歇，怎送的我二足双瘸？。"]'),
('yuanqu-412','庞涓夜走马陵道・尧民歌','无名氏','元','元曲','yuanqu','','[]','你道是若拿住活剁做两三截，(庞涓云)哥哥，旧话休题。',235,'元曲/yuanqu.json','["你道是若拿住活剁做两三截，(庞涓云)哥哥，旧话休题。", "(正末唱)今日个马陵道上把大冤雪。", "我剑锋亲把树皮揭，写着道今夜里此处斩豪杰。", "伤也波嵯，我和你从今便永决，(带云)庞涓，您要不死呵，(唱)则除是半空中飞下滴溜溜一纸郊天赦。", "(公子云)军师，则管和他说到几时。", "先把这厮刖了双足，切下了驴头，然后将尸首分开做六段，散与六国去罢。", "(孙膑云)小校，将铜钅算斤来先刖了这厮双足者！(庞涓云)罢、罢、罢，大丈夫睁着眼做，合着眼受。", "这也不必说了，只可惜那六甲天书还不曾传授。", "(正末唱)。"]'),
('yuanqu-413','庞涓夜走马陵道・煞尾','无名氏','元','元曲','yuanqu','','[]','再言语豁了这厮口，再言语截了这厮舌。',42,'元曲/yuanqu.json','["再言语豁了这厮口，再言语截了这厮舌。", "将那一颗驴头慢慢钢刀切。", "才把我刖足的冤仇报了也。"]'),
('yuanqu-414','中吕・阳春曲别情','王伯成','元','元曲','yuanqu','','[]','多情去后香留枕，好梦回时冷透衾，闷愁山重海来深。',34,'元曲/yuanqu.json','["多情去后香留枕，好梦回时冷透衾，闷愁山重海来深。", "独自寝，夜雨百年心。"]'),
('yuanqu-415','仙吕・春从天上来闺怨','王伯成','元','元曲','yuanqu','','[]','巡官算我，道我命运乖，教奴镇日无精彩。',80,'元曲/yuanqu.json','["巡官算我，道我命运乖，教奴镇日无精彩。", "为想佳期不敢傍妆台，又恐怕爹娘做猜，把容颜只恁改。", "漏永更长，不由人泪满腮。", "他情是歹，咱心且捱，终须也要还满了相思债。", "套数。"]'),
('yuanqu-416','般涉调・哨遍项羽自刎','王伯成','元','元曲','yuanqu','','[]','虎视鲸吞相并，灭强秦已换炎刘姓。',102,'元曲/yuanqu.json','["虎视鲸吞相并，灭强秦已换炎刘姓。", "数年逐鹿走中原，创图基祚隆兴。", "各驰骋，布衣学剑，陇亩兴师，霸业特昌盛。", "今日悉皆扫荡，上合天统，下应民情。", "睢河岸外勇难施，广武山前血犹腥。", "恨错放高皇，懊失追韩信，悔不从范增。"]'),
('yuanqu-417','幺・行走行迎，故然怒激刚强性。迤逗向垓心，预埋伏掩映山形，猛围定。','王伯成','元','元曲','yuanqu','','[]','涧溪沟壑，列介胄寒光莹，昼夜攻催劫掠，爪牙脱落，羽翼雕零。',59,'元曲/yuanqu.json','["涧溪沟壑，列介胄寒光莹，昼夜攻催劫掠，爪牙脱落，羽翼雕零。", "一个向五云乡里贺升平，一个向八卦图中竞残生，更那堪时月严凝。"]'),
('yuanqu-418','麻婆子・汉祖胜乘威势，上苍助显号令。四野布层阴重，六花飞万片轻。','王伯成','元','元曲','yuanqu','','[]','不添和气报丰年，特呈凶兆害生灵。',30,'元曲/yuanqu.json','["不添和气报丰年，特呈凶兆害生灵。", "手拘束难施展，足滑擦岂暂停。"]'),
('yuanqu-419','幺・自清晓彻终日，从黄昏睚五更。趁水泽身难到，夺樵路力不能。旋消','王伯成','元','元曲','yuanqu','','[]','冰雪润枯肠，冻烧器械焰荒荆。',28,'元曲/yuanqu.json','["冰雪润枯肠，冻烧器械焰荒荆。", "马无草人无饭，立不安坐不宁。"]'),
('yuanqu-420','墙头花・军收雪霁，起凛冽严风劲，汗湿征衣背似冰。战欣欣火灭烟消，','王伯成','元','元曲','yuanqu','','[]','干剥剥天寒地冷。',8,'元曲/yuanqu.json','["干剥剥天寒地冷。"]'),
('yuanqu-421','幺・征夫梦寐清，深夜疆场静，四面悲歌忍泪听。便不思败国亡家，皆子','王伯成','元','元曲','yuanqu','','[]','想离乡背井。',6,'元曲/yuanqu.json','["想离乡背井。"]'),
('yuanqu-422','急曲子・帐周回立故壁，阵东南破去程。众儿郎已杳然，总安眠睡未惊。','王伯成','元','元曲','yuanqu','','[]','忽闻嘶困乏征碗，猛唤回凄凉梦境。',16,'元曲/yuanqu.json','["忽闻嘶困乏征碗，猛唤回凄凉梦境。"]'),
('yuanqu-423','耍孩儿・唯除个植楚怀忠政，错认做奸人暗等。误截一臂不任疼，猛魂飘','王伯成','元','元曲','yuanqu','','[]','已赴幽冥。',40,'元曲/yuanqu.json','["已赴幽冥。", "碧澄澄万里天如水，明朗朗十分月满营。", "马首立虞姬氏，翠蛾低敛，粉泪双擎。"]'),
('yuanqu-424','幺・绝疑的宝剑挥圆颈，不二色的刚肠痛。怎教暴露在效墟，惜香肌难入','王伯成','元','元曲','yuanqu','','[]','山陵。',35,'元曲/yuanqu.json','["山陵。", "望碧云芳草封高冢，对黄土寒沙赴浅坑。", "伤情兴，须臾天晓，仿佛平明。"]'),
('yuanqu-425','三煞・衡路九条，山垓九层，区区纵堑奔荒径。开基创业时皆尽，争帝图','王伯成','元','元曲','yuanqu','','[]','王势已倾。',18,'元曲/yuanqu.json','["王势已倾。", "军逐，因寻江路，误入阴陵。"]'),
('yuanqu-426','二・付能归船路开，却懒将踏板登，丧八千子弟无踪影。羞归西楚亲求救，','王伯成','元','元曲','yuanqu','','[]','耻向东吴再起兵。',25,'元曲/yuanqu.json','["耻向东吴再起兵。", "辞了枪骑，伏霜锋闪烁，从二足奔腾。"]'),
('yuanqu-427','一・杀五侯虽惧怯，奈只身枉战争，自知此地绝天命。壮怀已丧英雄气，','王伯成','元','元曲','yuanqu','','[]','巨口全无叱咤声。',21,'元曲/yuanqu.json','["巨口全无叱咤声。", "寻思到一场长叹，百战衰形。"]'),
('yuanqu-428','尾・解委颔把顿项推，举太阿将咽颈称。子见红飘飘光的的绛缨先偏侧了','王伯成','元','元曲','yuanqu','','[]','金盔顶，碜可可湿浸浸鲜血早淋漓了战袍领。',127,'元曲/yuanqu.json','["金盔顶，碜可可湿浸浸鲜血早淋漓了战袍领。", "赠长春宫雪庵学士过隙驹难留时暂，百年几度聪明暗。", "尘事饱经谙，叹狙公暮四朝三。", "抵自惭，远投苍海，平步风波，空擘骊龙颔。", "谩赢得此身良苦，家私分外，活计尴尬。", "寝食玉锁紧牵连，行坐金枷自披担。", "世累相萦，阴行难修，业缘未减。"]'),
('yuanqu-429','幺・因见无常，谩劳供养看经忏。虽有六亲人，谁能替入棺函。劝省咱，','王伯成','元','元曲','yuanqu','','[]','从今白甚，则管教人，吃粉羹餐酸馅，皮骨这回绝却。',58,'元曲/yuanqu.json','["从今白甚，则管教人，吃粉羹餐酸馅，皮骨这回绝却。", "三年乳哺，十月怀耽，长春有景闷时游，大道无极静中参。", "出凡笼再不争搀。"]'),
('yuanqu-430','幺・浮云世态将人赚，识破也诚何以堪。布袍独驾九天风，玩无穷绿水青','王伯成','元','元曲','yuanqu','','[]','东游瀛海思徐福，西度流沙慕老聃。',29,'元曲/yuanqu.json','["东游瀛海思徐福，西度流沙慕老聃。", "抛持尽雀巢燕垒，虎窟龙潭。"]'),
('yuanqu-431','一煞・从释缚，自脱监，纸鸢无线舟无缆。风寒暑湿非吾患，昧色声香莫','王伯成','元','元曲','yuanqu','','[]','我贪。',17,'元曲/yuanqu.json','["我贪。", "休只待，船中满载，水低俱淹。"]'),
('yuanqu-432','三煞・衣锦裘，乘骏骖，与朋共敝虽无憾。箪瓢自乐颜回巷，版筑谁亲傅','王伯成','元','元曲','yuanqu','','[]','说岩。',17,'元曲/yuanqu.json','["说岩。", "君不见，花飞树底，日转天南。"]'),
('yuanqu-433','五煞・饭已熟，睡正酣，尽他世味无如淡。诗囊经卷随藜杖，苍木黄菁满','王伯成','元','元曲','yuanqu','','[]','药篮。',17,'元曲/yuanqu.json','["药篮。", "回头笑，青钱拍板，乌帽蓝衫。"]'),
('yuanqu-434','六煞・耳若聋，口似缄，有人来问佯妆憨。胡芦提了全无闷，皮袋肥来最','王伯成','元','元曲','yuanqu','','[]','不憨。',17,'元曲/yuanqu.json','["不憨。", "渔樵伴，山声野调，阔论高谈。"]'),
('yuanqu-435','七煞・不动心，已丧胆，丹田饱养难摇撼。身欺古柏衰中旺，味胜青瓜苦','王伯成','元','元曲','yuanqu','','[]','后甘。',17,'元曲/yuanqu.json','["后甘。", "功成处，脸同莲萼，头类松杉。"]'),
('yuanqu-437','越调・斗鹌鹑','王伯成','元','元曲','yuanqu','','[]','酒力禁持，诗魔唤起。',48,'元曲/yuanqu.json','["酒力禁持，诗魔唤起。", "紫燕喧喧，黄莺呖呖。", "红杏香中，绿杨影里。", "丽日迟，节序催。", "柳线摇金，桃花泛水。"]'),
('yuanqu-438','紫花儿序・香馥馥花开满路，碧粼粼水绕孤村，绿茸茸芳草烟迷。扬鞭指','王伯成','元','元曲','yuanqu','','[]','处，堪画堪题。',34,'元曲/yuanqu.json','["处，堪画堪题。", "更那堪，竹坞人家傍不溪。", "彩绳高系，春色飘零，花事狼藉。"]'),
('yuanqu-439','小桃红・一帘红雨落花飞，酝酿蜂儿蜜。跨蹇携壶醒还醉，草凄凄，融融','王伯成','元','元曲','yuanqu','','[]','沙暖鸳鸯睡。',22,'元曲/yuanqu.json','["沙暖鸳鸯睡。", "韶光景美，和风暖日，惹起杜鹃啼。"]'),
('yuanqu-440','秃厮儿・凝眸处黄莺子规，动情的绿暗红稀。莺慵燕懒蝶倦飞，冷落了芳','王伯成','元','元曲','yuanqu','','[]','菲，春归。',5,'元曲/yuanqu.json','["菲，春归。"]'),
('yuanqu-441','圣药王・醉似泥，仆从随，见小桥流水隔花溪。柳岸西，近古堤，数枝红','王伯成','元','元曲','yuanqu','','[]','杏出疏篱，墙外舞青旗。',11,'元曲/yuanqu.json','["杏出疏篱，墙外舞青旗。"]'),
('yuanqu-442','尾・四围绵绣繁华地，车马喧天闹起。看了这红紫翠乡中，堪写在丹青画','王伯成','元','元曲','yuanqu','','[]','图里。',3,'元曲/yuanqu.json','["图里。"]'),
('yuanqu-443','双调・折桂令赠千金奴','孔文升','元','元曲','yuanqu','','[]','杏桃腮杨柳纤腰，占断他风月排场，鸾凤窝巢。',77,'元曲/yuanqu.json','["杏桃腮杨柳纤腰，占断他风月排场，鸾凤窝巢。", "宜笑宜颦，倾国倾城，百媚千娇。", "一个可喜娘身材儿是小，便做天来大福也难消。", "檀板轻敲，银烛高烧，万两黄金，一刻春宵。"]'),
('yuanqu-444','汉钟离度脱蓝采和・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','俺将这古本相传，路歧礼面，习行院，打诨通禅，穷薄艺知深浅。',29,'元曲/yuanqu.json','["俺将这古本相传，路歧礼面，习行院，打诨通禅，穷薄艺知深浅。"]'),
('yuanqu-445','汉钟离度脱蓝采和・混江龙','无名氏','元','元曲','yuanqu','','[]','试看我行针步线，俺在这梁园城一交却又早二十年。',370,'元曲/yuanqu.json','["试看我行针步线，俺在这梁园城一交却又早二十年。", "常则是与人方便，会客周全。", "做一段有憎爱劝贤孝新院本，觅几文济饥寒得温暖养家钱。", "俺这里不比别州县。", "学这几分薄艺，胜似千顷良田。", "(云)来到这勾栏里也。", "兄弟有看的人么？好时候也，上紧收拾。", "(净云)我方才开了勾栏门，有一个先生坐在乐床上。", "我便道：先生，你去神楼上或是腰棚上那里坐，这里是妇女每做排场的坐处。", "他倒骂俺。", "(正末云)好歹你每冲撞着他来。", "我自看去。", "(做见科，云)稽首，老师父。", "(钟云)你那里散诞去来？(正末云)这先生你与我贴招牌。", "老先生不知，街市上有几个士夫，请我吃了一杯茶。", "因此上来迟。", "(钟云)我在这勾栏里坐了一日，你这早晚才来。", "宁可乐待于宾，不可宾待于乐。", "我特来看你做杂剧，你做一段甚么杂剧我看。", "(正末云)师父要做甚么杂剧？(钟云)但是你记的，数来我听。", "(正末云)我数几段师父听咱。", "(唱)。"]'),
('yuanqu-446','汉钟离度脱蓝采和・天下乐','无名氏','元','元曲','yuanqu','','[]','或是做雪拥蓝关马不前。',145,'元曲/yuanqu.json','["或是做雪拥蓝关马不前。", "(钟云)别做一段。", "(正末唱)小人其实本事浅，感谢看官相可怜。", "(云)王把色，你将旗牌。", "帐额、神峥、靠背都与我挂了者。", "(净云)我都挂了。", "(正末唱)一壁将牌额题，一壁将靠背悬。", "(云)有那边方来看的见了呵，传出去说，梁园棚勾栏里末尼蓝采和做场哩。", "(唱)我则待天下将我的名姓显。"]'),
('yuanqu-447','汉钟离度脱蓝采和・那吒令','无名氏','元','元曲','yuanqu','','[]','据着你那口食离糟麸膳缘，身遇着薄藤冠驾轩，我则道稳跨着仙鹤上天。',81,'元曲/yuanqu.json','["据着你那口食离糟麸膳缘，身遇着薄藤冠驾轩，我则道稳跨着仙鹤上天。", "(钟云)我游遍天下，不曾见你这个末尼。", "(正末唱)太平身插入市楼，将天下都游遍，一对脚背地坚叫声冤。"]'),
('yuanqu-448','汉钟离度脱蓝采和・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','你道我谎人钱，胡将这传奇扮。',139,'元曲/yuanqu.json','["你道我谎人钱，胡将这传奇扮。", "(云)则许官员上户财主看勾栏散闷，我世不会见个先生看勾栏。", "(唱)几曾见歌舞丛中，出了个大罗神仙。", "(云)沿门儿乞化，又无那好的与你。", "(唱)指大众抄化些郎头絮茧。", "(云)那化缘处攒令各整集攒凑上来，见那钱物多也，利心又早动也。", "(唱)你又不纳常住自趱做家缘。"]'),
('yuanqu-449','汉钟离度脱蓝采和・赚煞','无名氏','元','元曲','yuanqu','','[]','你合不着圣贤机，我觑不的他人面。',122,'元曲/yuanqu.json','["你合不着圣贤机，我觑不的他人面。", "我看你几时到蓬莱阆苑，则你那六道轮回怎脱免？使不的你九伯风颠。", "(云)我锁了勾栏门，看你怎生出的去。", "(唱)遮莫你驾云轩，白日升天，怎敢相饶到面前。", "(云)你若恼了我，十日不开门，我直饿杀你。", "(唱)则你那身躯不坚，折。"]'),
('yuanqu-450','汉钟离度脱蓝采和・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','白莲插玉瓶，黄篆焚金鼎，斟一杯长寿酒，挂一幅老人星，来贺长生。',66,'元曲/yuanqu.json','["白莲插玉瓶，黄篆焚金鼎，斟一杯长寿酒，挂一幅老人星，来贺长生。", "感承你相钦敬，量小人有甚么能，动劳你火伴邻里街坊，谢承你亲眷相知弟兄。"]'),
('yuanqu-451','汉钟离度脱蓝采和・梁州','无名氏','元','元曲','yuanqu','','[]','直吃的簌簌的红轮西坠，焱焱的玉兔东生。',288,'元曲/yuanqu.json','["直吃的簌簌的红轮西坠，焱焱的玉兔东生。", "常言五十而后知天命，我年过半百，诸事曾经。", "人有灵性，鸟有飞腾，常言道蠢动含灵，做场处谁敢消停。", "(云)咱行院打识水势(唱)俺、俺、俺做场处见景生情，你、你、你上高处舍身拚命，咱、咱、咱但去处夺利争名。", "若逢，对棚，怎生来妆点的排场盛，倚仗看粉鼻凹五七并，依着这书会社恩官求些好本令。", "(云)君子务本，本立而道生。", "(唱)那的愁甚么前程。", "(净把盏科云)哥哥饮一杯寿酒。", "(钟离上云)今日是蓝采和生辰之日，度脱他走一遭去，早来到门首去。", "(做哭三声、笑三声科，正末云)王把色是听的么，谁人在门首唱叫？(净云)哥哥也闲管事，知他是谁。", "俺则吃酒。", "(正末唱)。"]'),
('yuanqu-452','汉钟离度脱蓝采和・贺新郎','无名氏','元','元曲','yuanqu','','[]','是谁人啼天哭地两三声。',454,'元曲/yuanqu.json','["是谁人啼天哭地两三声。", "(云)我开开这门，原来是这泼先生，好无道理也呵！(唱)可做的魇镇俺家私，你端的是扇摇百姓。", "(钟云)你去告我去，我不怕你。", "(正末唱)咱告去来到官司呵和你敢无干净。", "(云)我待告你去呵，着老的便道你是个上戏台的末尼，和他那风魔先生一般见识。", "(唱)看着我生辰面不和你相执挣。", "(云)今日我生辰，我是寿星，不和你计较。", "(钟云)谁是寿星？(正末云)我是寿星。", "(钟云)你今日是寿星，明日敢做了灾星也。", "(正末云)这先生好无礼也，说这等不吉利的话。", "(唱)你休这般胡做胡称。", "(钟云)这句话又不曾伤着你。", "(正末唱)这言语也不中使，这言语也不中听。", "你敢化些淡齑汤且把你那皮囊撑。", "(钟云)我见你受用。", "(正末唱)可知可知俺吃的是大馒头阔片粉，你吃的是菜饺馅淡齑羹。", "(云)这泼先生打搅俺吃酒。", "王把色闭上门者。", "众弟兄每坐着，则管里吃酒。", "(钟云)他那里肯省悟，他若不见恶境头，他不肯出家。", "兀那许坚，你若跟贫道出家去呵，逍遥散诞，清闲快乐，倒大来幽哉！(正末云)我知你做神仙的道路。", "(钟云)你既知道，你说来我听。", "(正末唱)。"]'),
('yuanqu-453','汉钟离度脱蓝采和・斗虾蟆','无名氏','元','元曲','yuanqu','','[]','见人家排斋供，请先生念忏经。',149,'元曲/yuanqu.json','["见人家排斋供，请先生念忏经。", "正面儿挂下一幅三清，檀越人家念经。", "荒忙准备斋供，见放一轴老君，挂下十王神幅，待诏他也世情，说着的便决应，画的十分可碜。", "怎觑那般行径，我则见城狱里画何真，油镬油铛，里头札定，偌多生灵，都是俺俗人，元来无一个和尚，先生徐神翁。", "道无干净，这句话不觑听，我这等末尼你这等先生！。"]'),
('yuanqu-454','汉钟离度脱蓝采和・乌夜啼','无名氏','元','元曲','yuanqu','','[]','这先生言语真实信，果然道寿星做了灾星。',96,'元曲/yuanqu.json','["这先生言语真实信，果然道寿星做了灾星。", "眼睁睁不敢往前进，不敢明闻。", "谁敢道是弹筝。", "想咱人是仲尼行，怎道是犯着萧何令。", "(云)想圣人的言语说着都不信。", "(唱)一个个，难凭信，都做了狂言诈语，信口胡喷。"]'),
('yuanqu-455','汉钟离度脱蓝采和・尾声','无名氏','元','元曲','yuanqu','','[]','再不将百十口火伴相将领，从今后十二瑶台独自行。',91,'元曲/yuanqu.json','["再不将百十口火伴相将领，从今后十二瑶台独自行。", "我那时财散人离陪下情，打喝处动乐声，戏台上呼我乐名。", "我如今浑不浑浊不浊醒不醒，蓝采和泼声名贯满州城，几曾见那扮杂剧乐官头得悟醒。", "(下)。"]'),
('yuanqu-456','汉钟离度脱蓝采和・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','腰间将百钱拖，头上把唐巾裹，舞绿衫拍板高歌，逐朝走向街头过。',40,'元曲/yuanqu.json','["腰间将百钱拖，头上把唐巾裹，舞绿衫拍板高歌，逐朝走向街头过。", "有几个把我相着么？。"]'),
('yuanqu-457','汉钟离度脱蓝采和・倘秀才','无名氏','元','元曲','yuanqu','','[]','再不听耳边厢焦焦聒聒，儿女是金枷玉锁，道不的儿女多来冤业多。',52,'元曲/yuanqu.json','["再不听耳边厢焦焦聒聒，儿女是金枷玉锁，道不的儿女多来冤业多。", "闲时节手执着板，闷来时口扬着歌。", "谁似我快活。"]'),
('yuanqu-458','汉钟离度脱蓝采和・滚绣球','无名氏','元','元曲','yuanqu','','[]','从今后我独自个，休想我做过活。',164,'元曲/yuanqu.json','["从今后我独自个，休想我做过活。", "再不去乔妆扮打拍撺掇，再不去戏台上信口开合。", "(云)你又着我做场处唤王把色李薄头快疾快疾。", "(唱)又着俺媳妇每，那一火。", "快疾忙去梳裹，不争我又做场又索央众父老每妆喝。", "(净云)自从哥哥去了，勾栏里就没人看。", "(正末唱)为甚么勾栏里看的十分少，则你那话不投机一句多。", "(净云)你说风话哩。", "(正末唱)不是我风魔。"]'),
('yuanqu-459','汉钟离度脱蓝采和・快活三','无名氏','元','元曲','yuanqu','','[]','假若是无常到怎奈何。',49,'元曲/yuanqu.json','["假若是无常到怎奈何。", "(云)婆婆，你去波。", "(唱)我如今得磨跎处且磨跎，待学庄子鼓盆歌，误了我亡身祸。"]'),
('yuanqu-460','汉钟离度脱蓝采和・朝天子','无名氏','元','元曲','yuanqu','','[]','行院每趱家私过活。',287,'元曲/yuanqu.json','["行院每趱家私过活。", "(旦云)都是一般行院，你多拿了几文钱出来，我务要平分。", "(正末唱)问甚么你死我活。", "(云)见别人朝来暮去，干家做活，瞒心昧己。", "(唱)那一个肯依本分随缘过。", "(云)我如今闲来看一卷道德经，困来睡一觉。", "(唱)但得合处把我这眼皮儿合，得卧处和衣儿卧。", "(旦云)都摆着你看，你那兄弟幼子娇妻许多家眷，怎下的撇了俺去出家！(正末唱)摆列着幼子娇妻，儿孙许多。", "(云)则听得误了官身那一日，扣厅要打四十。", "若不是师父救了我呵！(唱)假若是我无常谁替我。", "(旦云)：既是这等，你也度脱我出家去。", "(正末唱)你待着，不合把你来度脱。", "(旦云)你回去罢，不济事。", "(正末唱)赤紧的我也在壕中坐。"]'),
('yuanqu-461','汉钟离度脱蓝采和・尾声','无名氏','元','元曲','yuanqu','','[]','虽然俺便不得正果，把你个贤妻度脱。',48,'元曲/yuanqu.json','["虽然俺便不得正果，把你个贤妻度脱。", "你且与我安乐守分随缘过，只落得一日清闲兀的不快活杀我。", "(下)。"]'),
('yuanqu-462','汉钟离度脱蓝采和・双调/新水令','无名氏','元','元曲','yuanqu','','[]','道门中法礼炼修持，俺师父度了个乐官徒弟。',52,'元曲/yuanqu.json','["道门中法礼炼修持，俺师父度了个乐官徒弟。", "俺师父明明的使道法，暗暗的说禅机，待和我同赴瑶池。", "怎承望有今日。"]'),
('yuanqu-463','汉钟离度脱蓝采和・庆东园','无名氏','元','元曲','yuanqu','','[]','那里每人烟闹。',70,'元曲/yuanqu.json','["那里每人烟闹。", "(云)是乐声响哩。", "(唱)是一火君路歧，料应在那公科地，持着些枪刀剑戟，锣板和鼓笛。", "更有那帐额牌旗，行院每是谁家，多管是无名器。"]'),
('yuanqu-464','汉钟离度脱蓝采和・沽美酒','无名氏','元','元曲','yuanqu','','[]','叹光阴忒紧急，嗟岁月苦奔驰。',35,'元曲/yuanqu.json','["叹光阴忒紧急，嗟岁月苦奔驰。", "重惜浮生如梦里。", "我如今省得，无生死绝名列。"]'),
('yuanqu-465','汉钟离度脱蓝采和・太平令','无名氏','元','元曲','yuanqu','','[]','咱须是吾兄我弟，幼年间逐队相随。',165,'元曲/yuanqu.json','["咱须是吾兄我弟，幼年间逐队相随。", "止不过逢场学艺，出来的偌大小年纪，这个道七十，那个道八十，婆婆道九十，这厮淡则淡到长命百岁。", "(净云)你是谁？(正末云)则我就是蓝采和。", "(净云)你去了三十年，还不老。", "只是这等模样。", "(正末云)我去了只三年光景，你怎生都老了？(净云)我们都是老人家，你正是中年，还去勾栏里做几日杂剧，却不好？(正末唱)。"]'),
('yuanqu-466','汉钟离度脱蓝采和・川拨棹','无名氏','元','元曲','yuanqu','','[]','你待着我做杂剧，扮兴亡贪是非，待着我擂鼓吹笛，打拍收拾。',43,'元曲/yuanqu.json','["你待着我做杂剧，扮兴亡贪是非，待着我擂鼓吹笛，打拍收拾。", "莫消停殷勤在意，快疾忙莫迟疑。"]'),
('yuanqu-467','汉钟离度脱蓝采和・七弟兄','无名氏','元','元曲','yuanqu','','[]','那时，我对敌，不是我说嘴，我着他笑嘻嘻将衣服花帽全新置。',47,'元曲/yuanqu.json','["那时，我对敌，不是我说嘴，我着他笑嘻嘻将衣服花帽全新置。", "旧么麽院本我须知，论同场本事我般般会。"]'),
('yuanqu-468','汉钟离度脱蓝采和・梅花酒','无名氏','元','元曲','yuanqu','','[]','他每都怎到的，论指点谁及，做手儿无敌，识紧慢迟疾。',153,'元曲/yuanqu.json','["他每都怎到的，论指点谁及，做手儿无敌，识紧慢迟疾。", "(净云)哥哥，你那做杂剧的衣服等件，不曾坏了。", "哥哥，你揭起帐幔试看咱；(正末唱)听言罢心内喜，不由我笑微微，我揭开帐幔则。", "(做揭科)(钟离洞宾在内坐科，钟云)许坚，你凡心不退哩那！(正末唱)唬的我悠悠魂魄飞，我则道我哥哥我兄弟，我姊妹我姨姨，似南柯梦惊回。"]'),
('yuanqu-469','汉钟离度脱蓝采和・收江南','无名氏','元','元曲','yuanqu','','[]','呀，原来是开坛阐教汉钟离，有洞宾师父紧相随。',47,'元曲/yuanqu.json','["呀，原来是开坛阐教汉钟离，有洞宾师父紧相随。", "我这里云阳板撒上阶基，你都来这里，八仙相引赴瑶池。"]'),
('yuanqu-470','董秀英花月东墙记・仙吕/赏花时','白朴','元','元曲','yuanqu','','[]','文质彬彬一丈夫，千里寻师为学谋。',34,'元曲/yuanqu.json','["文质彬彬一丈夫，千里寻师为学谋。", "今日个践路途，单身独步，云外雁声孤。"]'),
('yuanqu-471','董秀英花月东墙记・幺篇','白朴','元','元曲','yuanqu','','[]','我如今赤手空拳百事无，父丧家贫不似初，囊箧尽消疏。',369,'元曲/yuanqu.json','["我如今赤手空拳百事无，父丧家贫不似初，囊箧尽消疏。", "鹏程有路，何日赴皇都？(云)行了个月期程，到得松江府。", "家童，你寻个客店安下。", "(童云)理会的。", "兀那就是一所店房。", "店主在家么？(净上，云)谁叫，谁叫？(童云)老者，俺家长来此投宿。", "(做见科，云)小生动问老公公，此处董府尹在否？(净云)府尹下世去了。", "(生云)他宅子在何处？(净云)隔壁就是。", "足下与府尹甚亲？(生云)先父与府尹相交契厚。", "自先父下世，一向间阔，不曾问候。", "(净云)足下如今那里去？(生云)小生儒业进身，游学至此，将赴诏选。", "敢问公公，有房舍借一间小生借居，待来春赴试。", "(净云)足下既要安住，老夫有一小顽，名曰山寿，就托足下教训攻书。", "老夫东墙下有一花木堂，先生就在其中设馆，如何？(生云)如此多谢！(净云)院公，疾忙收拾洁净者。", "(院公云)已停当了。", "(净云)先生，请往花木堂安歇。", "(同下)。"]'),
('yuanqu-472','董秀英花月东墙记・吕仙/点绛唇','白朴','元','元曲','yuanqu','','[]','万物乘春，落花成阵，莺声嫩。',26,'元曲/yuanqu.json','["万物乘春，落花成阵，莺声嫩。", "垂柳黄匀，越引起心间闷。"]'),
('yuanqu-473','董秀英花月东墙记・混江龙','白朴','元','元曲','yuanqu','','[]','三春时分，南园草木一时新。',94,'元曲/yuanqu.json','["三春时分，南园草木一时新。", "清和天气，淑景良辰。", "紫陌游人嫌日短，青闺素女怕黄昏。", "寻芳俊士，拾翠佳人。", "千红万紫，花柳分春。", "对韶光半晌不开言，一天愁都结做心间恨。", "憔悴了玉肌金粉，瘦损了窈窕精神。"]'),
('yuanqu-474','董秀英花月东墙记・油葫芦','白朴','元','元曲','yuanqu','','[]','杏朵桃枝似绛唇，柳絮纷，春光偏闪断肠人。',63,'元曲/yuanqu.json','["杏朵桃枝似绛唇，柳絮纷，春光偏闪断肠人。", "微风细雨催花信，闲愁万种心间印。", "罗帏绣被，孤寒欲断魂。", "掩重门尽日无人问，情不遂越伤神。"]'),
('yuanqu-475','董秀英花月东墙记・天下乐','白朴','元','元曲','yuanqu','','[]','我只见杨柳横墙易得春，欢欣，可意人，一见了心下如何忍。',50,'元曲/yuanqu.json','["我只见杨柳横墙易得春，欢欣，可意人，一见了心下如何忍。", "送秋波眼角情，近东墙住左邻，觑了可憎才有就因。"]'),
('yuanqu-476','董秀英花月东墙记・那吒令','白朴','元','元曲','yuanqu','','[]','一见了那人，不由我断魂；思量起这人，有韩文柳文；他是个俏人，读齐论鲁论。',59,'元曲/yuanqu.json','["一见了那人，不由我断魂；思量起这人，有韩文柳文；他是个俏人，读齐论鲁论。", "想的咱不下怀，几时得成秦晋，甚何年一处温存？。"]'),
('yuanqu-477','董秀英花月东墙记・鹊踏枝','白朴','元','元曲','yuanqu','','[]','好教我闷昏昏，泪纷纷，都只为美貌潘安，仁者能仁。',40,'元曲/yuanqu.json','["好教我闷昏昏，泪纷纷，都只为美貌潘安，仁者能仁。", "一会家心中自忖，谁与俺通个殷勤。"]'),
('yuanqu-478','董秀英花月东墙记・寄生草','白朴','元','元曲','yuanqu','','[]','怕的是黄昏后，入罗帏愁越狠。',137,'元曲/yuanqu.json','["怕的是黄昏后，入罗帏愁越狠。", "孤眠独枕教人闷，愁潘病沈教人恨，行迟力顿教人困。", "似这等含情掩卧象牙床，几时得阳台上遇着多才俊。", "(梅云)姐姐，我猜着你，敢待和昨日那秀才说话。", "他在那壁，你在这壁，如何得会？(旦云)想当初卓文君怎生私奔相如来？(梅云)他两个缘何便得成就来？(旦唱)。"]'),
('yuanqu-479','董秀英花月东墙记・幺篇','白朴','元','元曲','yuanqu','','[]','汉相如在寒窗下，卓氏女配做婚。',66,'元曲/yuanqu.json','["汉相如在寒窗下，卓氏女配做婚。", "都只为我情你意相投顺，姻缘自把佳期问，郎才女貌皆相趁。", "你道是阻东墙难会碧纱厨，似俺这干荷叶那讨灵犀润。"]'),
('yuanqu-480','董秀英花月东墙记・后庭花','白朴','元','元曲','yuanqu','','[]','似这等害相思怎地忍？不由人上心来雨泪频。',93,'元曲/yuanqu.json','["似这等害相思怎地忍？不由人上心来雨泪频。", "避不的老母将将怪，好教我留连心上人。", "枉劳魂，不觉的罗衣宽褪。", "被生寒怎地温？看看的憔悴了身，厌厌的害杀人。", "唤梅香掩上门，把沉檀炉内焚，志诚心祷告神。"]'),
('yuanqu-481','董秀英花月东墙记・柳叶儿','白朴','元','元曲','yuanqu','','[]','呀，愁锁定眉尖春恨，怎不教心怀忧闷？见如今人远天涯近，难勾引，怎相交？越加上鬼病三分。',43,'元曲/yuanqu.json','["呀，愁锁定眉尖春恨，怎不教心怀忧闷？见如今人远天涯近，难勾引，怎相交？越加上鬼病三分。"]'),
('yuanqu-482','董秀英花月东墙记・青哥儿','白朴','元','元曲','yuanqu','','[]','对人前一言难尽，老夫人治家严训，怨俺那火性如雷老母亲。',213,'元曲/yuanqu.json','["对人前一言难尽，老夫人治家严训，怨俺那火性如雷老母亲。", "谨慎闺门，昼夜追巡，坐守行跟，恐失人伦。", "但若离了半时辰，来相问。", "(梅云)姐姐，似你今春多病，可以自己调理，莫费神思。", "不争你这等念想，倘若其身有失，如何是了？休休，莫要护病成疾，自损其身。", "姐姐自当思之。", "(旦云)梅香，你可知我心间的事？(梅云)妾虽不知，见姐姐身体不快，以此谏劝，自可调理。", "(旦云)似这等病，如何治度？我一会家不想起来便罢，一会家想将起，好是凄凉人也！(唱)。"]'),
('yuanqu-483','董秀英花月东墙记・赚煞','白朴','元','元曲','yuanqu','','[]','合晚至黄昏，独宿心间闷。',73,'元曲/yuanqu.json','["合晚至黄昏，独宿心间闷。", "苦厌厌忧愁自忖。", "便有铁石心肠也断魂。", "串香焚被冷谁温，引入多情梦里人。", "窗儿外月华正新，玉人儿在方寸，我将这海棠花分付与东君。"]'),
('yuanqu-484','董秀英花月东墙记・正宫/端正好','白朴','元','元曲','yuanqu','','[]','下香阶，踏芳径，步苍苔月影当庭。',32,'元曲/yuanqu.json','["下香阶，踏芳径，步苍苔月影当庭。", "过回廊一弄凄凉景，好教我添悲兴。"]'),
('yuanqu-485','董秀英花月东墙记・滚绣球','白朴','元','元曲','yuanqu','','[]','垂杨宿鸟惊，绣鞋不待行。',101,'元曲/yuanqu.json','["垂杨宿鸟惊，绣鞋不待行。", "降明香问天求聘，志诚心祷告神灵。", "相思病渐成，看看瘦损形，受寂寞事关前定，盼佳期井底银瓶。", "似这等栖迟误了奴家命，强打精神拜斗星，何日安宁？(梅云)姐姐，你听那里冰弦之声。", "(旦唱)。"]'),
('yuanqu-486','董秀英花月东墙记・倘秀才','白朴','元','元曲','yuanqu','','[]','则道是半空中神仙胜境，却元来东墙下把丝桐慢整，你听他款抚冰弦音韵清。',55,'元曲/yuanqu.json','["则道是半空中神仙胜境，却元来东墙下把丝桐慢整，你听他款抚冰弦音韵清。", "夜阑人静，情悲戚，话丁宁，怎不教人动情？。"]'),
('yuanqu-487','董秀英花月东墙记・滚绣球','白朴','元','元曲','yuanqu','','[]','我向这东墙仔细听。',91,'元曲/yuanqu.json','["我向这东墙仔细听。", "凤求鸾曲未成，怎不教想的人成病，今日个聪明的遇着聪明。", "这琴陶潜膝上横，蔡邕爨下生。", "断肠人这答儿孤另，一句句诉你飘零。", "几时得同衾共枕销金帐，满斗焚香说誓盟，愿足平生。"]'),
('yuanqu-488','董秀英花月东墙记・倘秀才','白朴','元','元曲','yuanqu','','[]','他在那东墙下诗和了一声，我这里近亭轩把绣鞋立定，好教我兜上心来意不宁。',54,'元曲/yuanqu.json','["他在那东墙下诗和了一声，我这里近亭轩把绣鞋立定，好教我兜上心来意不宁。", "愁攒眉角上，忽的动伤情，知他是怎生？。"]'),
('yuanqu-489','董秀英花月东墙记・呆骨朵','白朴','元','元曲','yuanqu','','[]','我这里闷厌厌锁不住疏狂性，怎禁的独自伤情？孤帏里翠减香消，花稍上蜂喧蝶并。',68,'元曲/yuanqu.json','["我这里闷厌厌锁不住疏狂性，怎禁的独自伤情？孤帏里翠减香消，花稍上蜂喧蝶并。", "少年人辜负了三春景，身体也无康盛。", "自思量怎奈何，渐染出风流病。"]'),
('yuanqu-490','董秀英花月东墙记・脱布衫','白朴','元','元曲','yuanqu','','[]','思量起俊俏书生，今日个显姓通名。',31,'元曲/yuanqu.json','["思量起俊俏书生，今日个显姓通名。", "海棠花权为信行，姻缘事该前定。"]'),
('yuanqu-491','董秀英花月东墙记・小梁州','白朴','元','元曲','yuanqu','','[]','谁想是旧日刘郎到武陵，听说罢怎不伤情。',37,'元曲/yuanqu.json','["谁想是旧日刘郎到武陵，听说罢怎不伤情。", "孤鸾寡凤几时成？人孤另，长叹两三声。"]'),
('yuanqu-492','董秀英花月东墙记・幺篇','白朴','元','元曲','yuanqu','','[]','黄昏一盏孤灯映，困腾腾闷倚帏屏。',424,'元曲/yuanqu.json','["黄昏一盏孤灯映，困腾腾闷倚帏屏。", "鼓二更，人初静，更添愁兴，照不到天明。", "(旦云)我常记得，俺父亲在日，曾与俺母亲说，在朝之日，曾与三原县令马昂为交，次后，半我许与他儿子马文辅为妻。", "我那时年幼，也不曾成得；后来音信不通，因此上不曾成合这亲事。", "我那日在后花园中，只见山寿家东墙上，有一秀才，往这壁望着。", "我一见那生，发黑眉青，唇红齿白，教我放心不下。", "我前日在海棠亭下烧夜香，又遇着他弹琴，专诉失其佳配。", "昨日使山寿来问我讨花，我因问他，你师父是谁；山寿说，姓马名彬字文辅。", "我就想起俺父亲的言语，莫不就是这生？我两日前写下了一个简帖儿，今日着梅香送与他去。", "梅香，你送这简帖儿与那秀才去。", "(梅云)将来，我送去。", "(旦与简科)(梅云)我送简帖儿去来。", "(同下)(生上，云)自从见了秀英小姐，着我神魂飘荡，茶饭懒尝。", "昨日着山寿讨花去，小姐与了一朵海棠花，不知主何意？似这等音信不通，如何是了？(梅云)先生万福。", "(生云)小娘子，来有何事？(梅云)你不知，听我说咱。", "(唱)。"]'),
('yuanqu-493','董秀英花月东墙记・上小楼','白朴','元','元曲','yuanqu','','[]','只因你青春后生，俺小姐心肠不硬。',226,'元曲/yuanqu.json','["只因你青春后生，俺小姐心肠不硬。", "想前夜月下鸣琴，韵和新诗，福至心灵。", "音韵轻，声律清，精通理性，多管是暗中传两情相应。", "(云)俺姐姐与了这个简帖儿，教送与先生，不知是甚么言语？(生云)将来我看。", "(生看科，云)小娘子，这一首诗是谁写的？(梅云)俺姐姐亲笔写的，你试念与我听。", "(生云)\"潇洒月明中，潜身墙角东。", "鸣琴离恨积，入夜绣帏空。", "梦绕三千界，云迷十二峰。", "仙郎休负我，我意若春浓。", "\"好高才也！既小姐有顾恋小生之心，我如今备办礼物，使媒人说去，如何？(梅唱)。"]'),
('yuanqu-494','董秀英花月东墙记・幺篇','白朴','元','元曲','yuanqu','','[]','你待教媒人偶成，老夫人天生劣性。',144,'元曲/yuanqu.json','["你待教媒人偶成，老夫人天生劣性。", "不争你走透消息，泄漏风声，误了前程。", "俺姐姐念旧盟，想旧情，何须媒证，不用你半星儿绛罗为定。", "(生云)既蒙小姐垂念，小生也写一简，烦小娘子捎去。", "(梅云)你写来。", "(生写科，云)小娘子，你道我多多上复小姐来。", "(梅下)(生云)小姐若见了这简帖儿，好事必成也。", "(下)。"]'),
('yuanqu-495','董秀英花月东墙记・满庭芳','白朴','元','元曲','yuanqu','','[]','恰便似龙蛇弄影，才过子建，笔扫千兵。',65,'元曲/yuanqu.json','["恰便似龙蛇弄影，才过子建，笔扫千兵。", "温柔软款多才性，忒煞聪明。", "据相貌容颜齐整，论文学海宇传名，堪人敬。", "都只为更长漏永，伤感泪盈盈。"]'),
('yuanqu-496','董秀英花月东墙记・耍孩儿','白朴','元','元曲','yuanqu','','[]','似这等空房静悄人孤另，却又早香消金鼎。',67,'元曲/yuanqu.json','["似这等空房静悄人孤另，却又早香消金鼎。", "何时害彻相思病，卜金钱祷告神灵。", "生前禽演分明判，八卦详推莫顺情。", "四柱安排定，都来增下，祸福分明。"]'),
('yuanqu-497','董秀英花月东墙记・四煞','白朴','元','元曲','yuanqu','','[]','画檐铁马喧，纱窗梦不成，佳人才子何时娉？他是个异乡背井飘零客，我便是孤枕独眠董秀英。',64,'元曲/yuanqu.json','["画檐铁马喧，纱窗梦不成，佳人才子何时娉？他是个异乡背井飘零客，我便是孤枕独眠董秀英。", "都薄幸，一个在东墙下烦恼，一个在锦帐里伤情。"]'),
('yuanqu-498','董秀英花月东墙记・三煞','白朴','元','元曲','yuanqu','','[]','叹鸳鸯绣被空，满怀愁为那生，只因他新诗和的声相应。',66,'元曲/yuanqu.json','["叹鸳鸯绣被空，满怀愁为那生，只因他新诗和的声相应。", "更把那瑶琴拨出艰难调，彩凤求凰指下鸣。", "都是相思令，听了他凄凉惨切，好教我寸步难行。"]'),
('yuanqu-499','董秀英花月东墙记・二煞','白朴','元','元曲','yuanqu','','[]','婚姻配偶迟，难挨更漏永，画蛾眉懒去临妆镜。',57,'元曲/yuanqu.json','["婚姻配偶迟，难挨更漏永，画蛾眉懒去临妆镜。", "老天不管人憔翠，一派黄河九遍清。", "贞烈性，也只是粉墙一堵，似隔着百座连城。"]'),
('yuanqu-500','董秀英花月东墙记・尾煞','白朴','元','元曲','yuanqu','','[]','相思愁越添，凄凉恶梦境。',37,'元曲/yuanqu.json','["相思愁越添，凄凉恶梦境。", "便做道铁石般只恁心肠硬，都写入愁怀唤不省。", "(下)。"]'),
('yuanqu-501','董秀英花月东墙记・中吕/粉蝶儿','白朴','元','元曲','yuanqu','','[]','睡眼难开，锁愁眉如何担待？恨相思昼夜难挨。',51,'元曲/yuanqu.json','["睡眼难开，锁愁眉如何担待？恨相思昼夜难挨。", "则俺这异乡人，如风絮，飘零在外。", "愁满心怀，何时得否极生泰？。"]'),
('yuanqu-502','董秀英花月东墙记・醉春风','白朴','元','元曲','yuanqu','','[]','只因遇着可憎才，引的我熬煎深似海。',53,'元曲/yuanqu.json','["只因遇着可憎才，引的我熬煎深似海。", "害的我须臾咫尺难移挨，你好是歹，歹！一会家倒枕捶床，长吁短叹，教咱无奈。"]'),
('yuanqu-503','董秀英花月东墙记・脱布衫','白朴','元','元曲','yuanqu','','[]','病潘安瘦损形骸，杜韦娘憔悴香腮。',32,'元曲/yuanqu.json','["病潘安瘦损形骸，杜韦娘憔悴香腮。", "你两个恩情似海，没来由把咱禁害。"]'),
('yuanqu-504','董秀英花月东墙记・小梁州','白朴','元','元曲','yuanqu','','[]','你只要搂带同心结不开，都只待鱼水和谐。',37,'元曲/yuanqu.json','["你只要搂带同心结不开，都只待鱼水和谐。", "旷夫怨女命安排，心无奈，盼杀楚阳台。"]'),
('yuanqu-505','董秀英花月东墙记・幺篇','白朴','元','元曲','yuanqu','','[]','这便是才郎有意佳人爱，两下里怎不伤怀？好意挨，舒心害，粉墙为界，镜破两分钗。',59,'元曲/yuanqu.json','["这便是才郎有意佳人爱，两下里怎不伤怀？好意挨，舒心害，粉墙为界，镜破两分钗。", "(云)早来到也，我隔这窗儿试瞧咱。", "(唱)。"]'),
('yuanqu-506','董秀英花月东墙记・上小楼','白朴','元','元曲','yuanqu','','[]','我把这窗儿润开，觑一觑何妨何碍。',177,'元曲/yuanqu.json','["我把这窗儿润开，觑一觑何妨何碍。", "只见他东倒西歪，倚床靠枕，身体斜挨。", "叫一声马秀才，头不抬，相思苦害，问你个病襄王在也不在。", "(梅见科，云)先生万福。", "(生起，跪科，云)呀、呀、呀！小娘子，怎生就不来了？(梅云)夫人严谨，仆妾岂敢轻出？(生云)小娘子，今日小姐有何话说？(梅云)俺姐姐写了一简，教我送来，不知上面写着甚么。", "(生云)将来我看。", "(做接科)(梅唱)。"]'),
('yuanqu-507','董秀英花月东墙记・幺篇','白朴','元','元曲','yuanqu','','[]','俺小姐亲封一策，向你这东君叩拜。',57,'元曲/yuanqu.json','["俺小姐亲封一策，向你这东君叩拜。", "不知他有甚衷肠，道甚言词，诉甚情杯。", "试取开，看内才，中间梗概，比那吓蛮书赛也不赛。"]'),
('yuanqu-508','董秀英花月东墙记・贺圣朝','白朴','元','元曲','yuanqu','','[]','似这般子建才学，埋没书斋，愁肠一似东洋海。',48,'元曲/yuanqu.json','["似这般子建才学，埋没书斋，愁肠一似东洋海。", "生的相貌堂堂，见了开怀。", "心中自猜，怎生教他昼去昏来？。"]'),
('yuanqu-509','董秀英花月东墙记・满庭芳','白朴','元','元曲','yuanqu','','[]','姻缘合该，今朝相待，鱼水和谐。',73,'元曲/yuanqu.json','["姻缘合该，今朝相待，鱼水和谐。", "似这等不枉了教人害，苦尽甘来。", "古人言知过必改，不由人兜在心怀。", "一见了相亲爱，便休道贤贤易色，非是我放在狂乖。", "(下)。"]'),
('yuanqu-510','董秀英花月东墙记・耍孩儿','白朴','元','元曲','yuanqu','','[]','看了你桃腮杏脸花无寒，星眼朦胧不开。',71,'元曲/yuanqu.json','["看了你桃腮杏脸花无寒，星眼朦胧不开。", "魂灵儿飞在五云端，只将这玉体相挨。", "安排定共宿鸳鸯枕，准备下双飞鸾凤台。", "今日得同欢爱，把湘裙皱损，宝髻斜歪。"]'),
('yuanqu-511','董秀英花月东墙记・五煞','白朴','元','元曲','yuanqu','','[]','衫儿扭扣松，裙儿搂带解，酥胸粉腕天然态。',59,'元曲/yuanqu.json','["衫儿扭扣松，裙儿搂带解，酥胸粉腕天然态。", "楚腰似柳娇尤软，未吐桃花露润开。", "完成了恩和爱，今日个良姻匹配，便死呵一穴同埋。"]'),
('yuanqu-512','董秀英花月东墙记・三煞','白朴','元','元曲','yuanqu','','[]','娇羞力不加，低垂颈怕抬，风流彻骨遗香在。',52,'元曲/yuanqu.json','["娇羞力不加，低垂颈怕抬，风流彻骨遗香在。", "相偎玉体轻轻按，粉汗溶溶湿杏腮。", "似这等偷香窃玉，几时得一发明白。"]'),
('yuanqu-513','董秀英花月东墙记・二煞','白朴','元','元曲','yuanqu','','[]','澄澄夜气清，低低月转阶，枝枝花影横窗外。',59,'元曲/yuanqu.json','["澄澄夜气清，低低月转阶，枝枝花影横窗外。", "灯前试把香罗看，点点猩红映莹白。", "则见他羞无奈，困腾腾倚墙靠壁，急忙忙重整金钗。"]'),
('yuanqu-514','董秀英花月东墙记・尾煞','白朴','元','元曲','yuanqu','','[]','相思一笔勾，姻缘前世该。',33,'元曲/yuanqu.json','["相思一笔勾，姻缘前世该。", "好教人撇不下恩和爱，几时得再把同心带儿解。"]'),
('yuanqu-515','董秀英花月东墙记・越调/斗鹌鹑','白朴','元','元曲','yuanqu','','[]','眼见的枕剩衾空，怎挨这更长漏永？桃蕊飘霞，杨花弄风。',60,'元曲/yuanqu.json','["眼见的枕剩衾空，怎挨这更长漏永？桃蕊飘霞，杨花弄风。", "翠袖生寒，乌云不拢。", "恰成了鸾凤交，眼见的各西东。", "离恨千般，闲愁万种。"]'),
('yuanqu-516','董秀英花月东墙记・紫花儿序','白朴','元','元曲','yuanqu','','[]','见如今亭前分袂，目下离别，多应是梦里相逢。',120,'元曲/yuanqu.json','["见如今亭前分袂，目下离别，多应是梦里相逢。", "忍不住长吁短叹，难割舍意重情浓。", "枉教我埋怨天公，莫不是美满姻缘不得终！好教人伤悲切痛，霎时间去马回车，都做了往雁归鸿。", "(云)自从文辅去后，今经半载有余，杳无音信，教我身心不安。", "好是烦恼人也！(唱)。"]'),
('yuanqu-517','董秀英花月东墙记・小桃红','白朴','元','元曲','yuanqu','','[]','腰肢纤细减芳容，似带雨梨花重。',53,'元曲/yuanqu.json','["腰肢纤细减芳容，似带雨梨花重。", "翠被香消谁共，思无穷，音书写下无人送。", "鱼沉雁杳，枕剩衾空，因此上泪滴满酥胸。"]'),
('yuanqu-518','董秀英花月东墙记・天净纱','白朴','元','元曲','yuanqu','','[]','害的人病厌厌瘦了形容，宽绰绰带慢衣松，俏身儿往日难同。',40,'元曲/yuanqu.json','["害的人病厌厌瘦了形容，宽绰绰带慢衣松，俏身儿往日难同。", "越添悲痛，倚帏屏星眼朦胧。"]'),
('yuanqu-519','董秀英花月东墙记・调笑令','白朴','元','元曲','yuanqu','','[]','好教我气冲，怨天公，闪的我独宿孤眠锦帐中。',64,'元曲/yuanqu.json','["好教我气冲，怨天公，闪的我独宿孤眠锦帐中。", "珠帘不卷金钩控，怕的是南楼上画鼓冬冬。", "我这里好梦初成，又成墙东，怎生般梦中鱼水也难同。"]'),
('yuanqu-520','董秀英花月东墙记・秃厮儿','白朴','元','元曲','yuanqu','','[]','恨人，画檐间铁马丁东；恨人，寒山野寺鸣钟。',47,'元曲/yuanqu.json','["恨人，画檐间铁马丁东；恨人，寒山野寺鸣钟。", "恨人，把美爱幽欢好梦惊；恨人，又见花梢儿窗影下重重。"]'),
('yuanqu-521','董秀英花月东墙记・圣药王','白朴','元','元曲','yuanqu','','[]','想旧境，一梦中，海棠亭下正欢浓。',38,'元曲/yuanqu.json','["想旧境，一梦中，海棠亭下正欢浓。", "宝髻松，绣被重，觉来犹在画屏东，无语泪溶溶。"]'),
('yuanqu-522','董秀英花月东墙记・麻郎儿','白朴','元','元曲','yuanqu','','[]','恨相思病浓，转思量泪重。',27,'元曲/yuanqu.json','["恨相思病浓，转思量泪重。", "眉蹙损春山闷萦，显的凄凉一弄。"]'),
('yuanqu-523','董秀英花月东墙记・幺篇','白朴','元','元曲','yuanqu','','[]','这病攻、泪浓、闷重，都只为满腹愁衷，都只为鱼水难同，都只为孤鸾寡凤。',34,'元曲/yuanqu.json','["这病攻、泪浓、闷重，都只为满腹愁衷，都只为鱼水难同，都只为孤鸾寡凤。"]'),
('yuanqu-524','董秀英花月东墙记・络丝娘','白朴','元','元曲','yuanqu','','[]','粉花笺写下更长漏永，专诉着瘦减香肌玉容。',488,'元曲/yuanqu.json','["粉花笺写下更长漏永，专诉着瘦减香肌玉容。", "写罢了眉尖一纵，更教人悲痛。", "(云)自马生去后，教我朝思暮想，疾病转加，如之奈何！梅香，你来。", "(梅云)姐姐，怎么说？(旦云)我这几天身子不快，我待请医调理，你请母亲来商量。", "(梅云)老夫人，有请。", "(卜上，云)有甚事？(旦云)平亲，你孩儿身体不快，如何治之？(卜云)孩儿，快请个良医来，服些药饵就好了。", "梅香，你快请去。", "(梅背云)除是马秀才来，我就好了。", "(做请科，云)李郎中，在家不在家？(净上，云)小子李郎中是也。", "别无买卖营生，专靠我这药上盘费。", "我这妙用，有神仙之法，手到病除。", "家传一样妙药，专治男女伤春之病。", "恰才董府尹家来请，须索走一遭去。", "(行科，见梅科，云)小娘子，报复去。", "(梅报云)奶奶，请将医士来了。", "(卜云)请进来。", "(见科，卜云)小女有些不快，特请先生调治。", "(净云)请出来诊脉。", "(旦出见科)(诊脉科，净云)此脉沉细。", "(卜云)如何调治？(净云)小人专治伤春之病，岂可无药？不瞒老夫人说，我这药费本钱。", "(卜云)老身怎肯少了药资。", "(净云)我便攒药。", "(旦云)此药何名？(净云)不当受，小人回去也。", "(下)(卜云)梅香，你教孩儿睡一会儿，我回去。"]'),
('yuanqu-525','董秀英花月东墙记・东原乐','白朴','元','元曲','yuanqu','','[]','这厮是哄人机见，他说来的不通，越教人添沉重。',48,'元曲/yuanqu.json','["这厮是哄人机见，他说来的不通，越教人添沉重。", "他一片胡言都是空，无些儿效功，他正是说真方把咱做弄。"]'),
('yuanqu-526','董秀英花月东墙记・绵打絮','白朴','元','元曲','yuanqu','','[]','深闱静悄，幽僻庭空。',54,'元曲/yuanqu.json','["深闱静悄，幽僻庭空。", "月轮展纸，几扇屏风。", "似海棠半醉春睡重，鲛绡上绿鬓拥。", "有情人何日相逢，几时得赴高唐梦中？。"]'),
('yuanqu-527','董秀英花月东墙记・拙鲁速','白朴','元','元曲','yuanqu','','[]','花落去绿丛丛，怎不教人泪盈盈？愁锁眉尖万种，清夜悠悠谁共？画檐下摇曳帘栊，不想把离人断送，鹧鸪啼惊觉巫山梦。',54,'元曲/yuanqu.json','["花落去绿丛丛，怎不教人泪盈盈？愁锁眉尖万种，清夜悠悠谁共？画檐下摇曳帘栊，不想把离人断送，鹧鸪啼惊觉巫山梦。"]'),
('yuanqu-528','董秀英花月东墙记・尾声','白朴','元','元曲','yuanqu','','[]','鱼沉雁杳音难送，阻隔着千里关山万重。',39,'元曲/yuanqu.json','["鱼沉雁杳音难送，阻隔着千里关山万重。", "埋怨俺狠毒娘，走将来分开了鸾凤种。", "(下)。"]'),
('yuanqu-529','董秀英花月东墙记・双调/新水令','白朴','元','元曲','yuanqu','','[]','春雷揭地震青天，平步上广寒宫殿。',43,'元曲/yuanqu.json','["春雷揭地震青天，平步上广寒宫殿。", "风吹乌帽整，日照锦袍鲜。", "拜宴开筵，这其间方称了丈夫愿。"]'),
('yuanqu-530','董秀英花月东墙记・驻马听','白朴','元','元曲','yuanqu','','[]','十载心坚，酬志了金屋银屏紫府仙。',303,'元曲/yuanqu.json','["十载心坚，酬志了金屋银屏紫府仙。", "当时贫贱，怎忘了箪瓢陋巷在穷檐。", "官高犹记武陵源，身荣怎忘前亲眷。", "才中选，今朝又把程途践。", "(云)行了数日，早到松江府了。", "趱动马，径奔宅上去者。", "(做到科，云)左右，报的老夫人知道。", "(做报科)(夫人上，云)马文辅得了头名状元，今日回来，我须迎他进来者。", "(生做见科)(卜云)儿鞍马劳困。", "梅香，叫你姐姐来见学士者。", "(梅走上，云)姐姐在那里？(旦上，云)小贱人，你管我怎么？(梅云)俺姐夫做了官回来，在堂上，老夫人着我请你相见哩。", "(旦云)是真个？(梅云)你待不见哩。", "(旦云)不想有今日也！(做相见叙礼科)(旦云)才郎及第，官拜何职？(生云)托祖宗福荫，叨中状元，小生喜不自胜。", "(旦唱)。"]'),
('yuanqu-531','董秀英花月东墙记・雁儿落','白朴','元','元曲','yuanqu','','[]','谁想你入科场艺在先，金榜上名堪羡。',31,'元曲/yuanqu.json','["谁想你入科场艺在先，金榜上名堪羡。", "脱却了旧布衣，直走上金銮殿。"]'),
('yuanqu-532','董秀英花月东墙记・得胜令','白朴','元','元曲','yuanqu','','[]','你如今束带立朝前，得志受皇宣。',85,'元曲/yuanqu.json','["你如今束带立朝前，得志受皇宣。", "列翰苑为学士，插金花饮玉筵。", "标写在凌烟，宝匣内方显出龙泉剑。", "享富贵绵绵，立芳名见大贤。", "(生云)小生别后一载有余，多亏小姐持家养德。", "(旦唱)。"]'),
('yuanqu-533','董秀英花月东墙记・水仙子','白朴','元','元曲','yuanqu','','[]','今朝一日笑声喧，又得才郎叙旧缘，相逢诉不尽心中怨。',62,'元曲/yuanqu.json','["今朝一日笑声喧，又得才郎叙旧缘，相逢诉不尽心中怨。", "那时节意惨然，自别来动是经年。", "我只怕恩情断，盼归期天样远，谁知道今日团圆。"]'),
('yuanqu-534','董秀英花月东墙记・折桂令','白朴','元','元曲','yuanqu','','[]','喜今朝又得团圆，夫妇相逢，前世姻缘。',75,'元曲/yuanqu.json','["喜今朝又得团圆，夫妇相逢，前世姻缘。", "携手相将，花前月下，笑语甜言。", "旧日的恩情不浅，还记得海棠亭誓对婵娟。", "你如今黄榜名悬，翰苑超迁，愿足平生，尽在神天。"]'),
('yuanqu-535','董秀英花月东墙记・沽美酒','白朴','元','元曲','yuanqu','','[]','降明香，接诏宣，拜天使，喜开颜。',37,'元曲/yuanqu.json','["降明香，接诏宣，拜天使，喜开颜。", "圣主恩波遍九天，坐金銮宝殿，四海内都朝见。"]'),
('yuanqu-536','董秀英花月东墙记・太平令','白朴','元','元曲','yuanqu','','[]','托皇朝文能武羡，养德性道重名传。',151,'元曲/yuanqu.json','["托皇朝文能武羡，养德性道重名传。", "姓列在金章宝篆，普天下黎民方便。", "只愿的万千，永远，保天恩圣贤，端的是威镇了四方八面。", "(生云)使臣，请筵宴。", "(使臣云)不必了，就此告回。", "(下)(生上，云)贤妻，如今有圣旨，教即便赴京上任，你心下如何？(旦云)妾身岂敢抗拒？(生云)既如此，弓兵快收拾车马，赴任去来。", "(唱)。"]'),
('yuanqu-537','董秀英花月东墙记・川拨棹','白朴','元','元曲','yuanqu','','[]','列头搭在马前，把香车帘半卷。',58,'元曲/yuanqu.json','["列头搭在马前，把香车帘半卷。", "只见官诰新鲜，翠袖花钿，宝髻云偏，疑是天仙。", "只见他喜孜孜俏脸儿笑拈，敢见我紫罗袍体间穿。"]'),
('yuanqu-538','董秀英花月东墙记・七弟兄','白朴','元','元曲','yuanqu','','[]','我这里向前，谢得完全，今日个夫妻称了平生愿。',40,'元曲/yuanqu.json','["我这里向前，谢得完全，今日个夫妻称了平生愿。", "身荣休忘了海棠轩，东墙下私约成姻眷。"]'),
('yuanqu-539','董秀英花月东墙记・梅花酒','白朴','元','元曲','yuanqu','','[]','俺如今践登程，路途沿，几时到八水三川，西洛中原。',88,'元曲/yuanqu.json','["俺如今践登程，路途沿，几时到八水三川，西洛中原。", "莫得俄延，摔碎丝鞭。", "马蹄儿践香尘，钿车儿古道穿。", "今日个，来赴选；来赴选，到金銮；到金銮，日月边；日月边，受皇宣；受皇宣，古今传。"]'),
('yuanqu-540','董秀英花月东墙记・收江南','白朴','元','元曲','yuanqu','','[]','想当初五言诗和得句儿联，七条弦弹就旧姻缘，想着那海棠亭下设盟言。',46,'元曲/yuanqu.json','["想当初五言诗和得句儿联，七条弦弹就旧姻缘，想着那海棠亭下设盟言。", "今日个两全，夫妻敕赐再团圆。"]'),
('yuanqu-541','董秀英花月东墙记・鸳鸯煞','白朴','元','元曲','yuanqu','','[]','佳人才子心留恋，东墙花下成姻眷，标写青编，唱道一举登科将名姓显。',62,'元曲/yuanqu.json','["佳人才子心留恋，东墙花下成姻眷，标写青编，唱道一举登科将名姓显。", "男儿得志共赏在琼林宴，玉堂中千古名贤。", "似这等金榜题名万代显。"]'),
('yuanqu-542','仙吕・忆王孙寻梅','赵善庆','元','元曲','yuanqu','','[]','寻香曾到葛仙台，踏雪今临和靖宅，横斜数枝僧寺侧。',74,'元曲/yuanqu.json','["寻香曾到葛仙台，踏雪今临和靖宅，横斜数枝僧寺侧。", "动吟怀，一半衔春一半开。", "述忆太平楼馆醉金钗，老迈情怀悲倦客，吟笔未成贾谊策。", "鬓毛衰，一半苍苍一半白。"]'),
('yuanqu-543','南吕・四块玉雪湖和人韵','赵善庆','元','元曲','yuanqu','','[]','近水堤，临山寺，竹外横斜两三枝，樽前谈咏无多事。',36,'元曲/yuanqu.json','["近水堤，临山寺，竹外横斜两三枝，樽前谈咏无多事。", "白战诗，白苎词，白玉卮。"]'),
('yuanqu-544','中吕・朝天子送春','赵善庆','元','元曲','yuanqu','','[]','剑蒲，翠芜，雨过添新绿。',56,'元曲/yuanqu.json','["剑蒲，翠芜，雨过添新绿。", "药栏春事已结局，无计留春住。", "堤上芳尘，桥边飞絮，树头红一片无。", "布谷，杜宇，犹斗唤春归去。"]'),
('yuanqu-545','中吕・普天乐江头秋行','赵善庆','元','元曲','yuanqu','','[]','稻梁肥，蒹葭秀。',118,'元曲/yuanqu.json','["稻梁肥，蒹葭秀。", "黄添篱落，绿淡汀洲。", "木叶空，山容瘦。", "沙鸟翻风知潮候，望烟江万顷沉秋。", "半竿落日，一声过雁，几处危楼。", "秋江忆别晚天长，秋水苍。", "山腰落日，雁背斜阳。", "璧月词，朱唇唱。", "犹记当年兰舟上，洒洒风泪湿罗裳。", "钗分凤凰，杯斟鹦鹉，人拆鸳鸯。"]'),
('yuanqu-546','中吕・山坡羊燕子','赵善庆','元','元曲','yuanqu','','[]','来时春社，去时秋社，年年来去搬寒热。',112,'元曲/yuanqu.json','["来时春社，去时秋社，年年来去搬寒热。", "语喃喃，忙劫劫，春风堂上寻王谢，巷陌乌衣夕照斜。", "兴，多见些，亡，都尽说。", "长安怀古骊山横岫，渭河环秀，山河百二还如旧。", "狐兔悲，草木秋，秦宫隋苑徒遗臭，唐阙汉陵何处有？山，空自愁；河，空自流。"]'),
('yuanqu-547','商调・梧叶儿隐居','赵善庆','元','元曲','yuanqu','','[]','绝荣辱，无是非，忘世亦忘机。',34,'元曲/yuanqu.json','["绝荣辱，无是非，忘世亦忘机。", "藏鸳渚，浮雁溪，钓鱼矶，稳当似麒麟画里。"]'),
('yuanqu-548','越调・寨儿令早春湖游','赵善庆','元','元曲','yuanqu','','[]','景物新，艳晨昏，山气张天成绿云。',280,'元曲/yuanqu.json','["景物新，艳晨昏，山气张天成绿云。", "画舫红裙，紫陌游人，香软马蹄尘。", "棹涟漪水皱罗纹，破韶华桃露朱唇。", "湖风肥柳线，堤雨厚莎茵。", "春，又早二三分。", "春情愁冉冉，病恹恹，红窗睡起不甚タ。", "墨淡眉尖，风冷牙签，象管怕重拈。", "倦梳云懒对妆奁，怕愁春不卷珠帘。", "落红堆翠径，飞絮拥雕檐。", "嫌，楼外雨帘纤。", "泊潭洲忆旧游，叹迟留，情似汉江不断头。", "暮霭西收，楚水东流，烟草替人愁。", "鹭分沙接岸沧州，鱼惊饵晒网轻舟。", "风闲沽酒旆，月淡挂帘钩。", "秋，尽在雁边楼。", "美妓舞态轻，曲声清，生香玉骨粉扌若成。", "娇眼珠星，指甲春冰，云鬓剪鸦翎。", "记沉香火里调笙，忆砑罗裙上弹筝。", "轻颦欺燕燕，浅笑妒莺莺。", "挣，那更性胡伶。"]'),
('yuanqu-549','越调・凭栏人春日怀古','赵善庆','元','元曲','yuanqu','','[]','铜雀台空锁暮云，金谷园荒成路尘。',29,'元曲/yuanqu.json','["铜雀台空锁暮云，金谷园荒成路尘。", "转头千载春，断肠几辈人？。"]'),
('yuanqu-550','双调・沉醉东风秋日湘阴道中','赵善庆','元','元曲','yuanqu','','[]','山对面蓝堆翠岫，草齐腰绿染沙洲。',110,'元曲/yuanqu.json','["山对面蓝堆翠岫，草齐腰绿染沙洲。", "傲霜橘柚青，濯雨蒹葭秀。", "隔沧波隐隐江楼，点破萧湘万顷秋，是几叶儿傅黄败柳？昭君出塞图毡帐冷柔情挽挽，黑河秋塞草斑斑。", "丹青误写情，环佩难归汉。", "抱琵琶怨杀和番，比似丹青旧玉颜，又越添愁眉泪眼。"]'),
('yuanqu-551','双调・折桂令西湖','赵善庆','元','元曲','yuanqu','','[]','问六桥何处堪夸？十里晴湖，二月韶华。',139,'元曲/yuanqu.json','["问六桥何处堪夸？十里晴湖，二月韶华。", "浓淡峰恋，高低杨柳，远近桃花。", "临水临山寺塔，半村半郭人家。", "杯泛流霞，板撒红牙，紫陌游人，画舫娇娃。", "湖山堂八窗开水月交光，诗酒坛台，莺燕排场。", "歌扇摇风，梨云飘雪，粉黛生香。", "红袖台已更旧邦，白头民犹说新堂。", "花妒幽芳，人换宫妆，惟有湖山，不管兴亡。"]'),
('yuanqu-552','双调・落梅风太乙宫探梅','赵善庆','元','元曲','yuanqu','','[]','冰花艳，水月魂，斗诗坛醉翁笔阵。',141,'元曲/yuanqu.json','["冰花艳，水月魂，斗诗坛醉翁笔阵。", "自南枝漏泄了湖上春，问东风几番花信？江楼晚眺枫枯叶，柳瘦丝，夕阳闲画阑十二。", "望晴空莹然如片纸，一行雁一行愁字。", "秋晴秋声定，微雨歇，透疏棂纸窗风裂。", "孤灯儿似知愁恨切，照离人半明半灭。", "暮春寻芳宴，拾翠游，杏花寒禁烟时候。", "叫春山杜鹃何太愁，直啼得绿肥红瘦。"]'),
('yuanqu-553','双调・水仙子仲春湖上','赵善庆','元','元曲','yuanqu','','[]','雨痕著物润如酥，草色和烟近似无，岚光罩日浓如雾。',169,'元曲/yuanqu.json','["雨痕著物润如酥，草色和烟近似无，岚光罩日浓如雾。", "正春风啼鹧鸪，斗娇羞粉女琼奴。", "六桥锦绣，十里画图，二月西湖。", "渡瓜州渚莲花脱锦衣收，风蓼青雕红穗秋，堤柳绿灭长条瘦。", "系行人来去愁，别离情今古悠悠。", "南徐城下，西津渡口，北固山头。", "客乡秋夜梧桐一叶弄秋晴，砧杵千家捣月明，关山万里增归兴。", "隔嵯峨白帝城，捱长宵何处销凝？寒灯一檠，孤雁数声，断梦三更。"]'),
('yuanqu-554','双调・庆东原泊罗阳驿','赵善庆','元','元曲','yuanqu','','[]','砧声住，蛩韵切，静寥寥门掩清秋夜。',92,'元曲/yuanqu.json','["砧声住，蛩韵切，静寥寥门掩清秋夜。", "秋心凤阙，秋愁雁堞，秋梦胡蝶。", "十载故乡心，一夜邮亭月。", "晚春杂兴烟中寺，柳外楼，乱随风雪絮飘晴昼。", "游人陌头，残红树头，流水溪头。", "百六楚风酸，三月吴姬瘦。"]'),
('yuanqu-555','双调・雁儿落过德胜令天竺寺','赵善庆','元','元曲','yuanqu','','[]','旃檀古道场，水月白衣相。',66,'元曲/yuanqu.json','["旃檀古道场，水月白衣相。", "真珠般若林，多宝如来藏。", "梵相四天王，唐塑八金刚。", "佛隐松间塔，僧推云外窗。", "虚堂，法鼓惊天上；长廊，游人惹御香。"]'),
('yuanqu-556','山神庙裴度还带・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','我如今匣剑尘埋，壁琴土盖，三十载。',37,'元曲/yuanqu.json','["我如今匣剑尘埋，壁琴土盖，三十载。", "忧愁的髭鬓斑白，尚兀自还不彻他这穷途债。"]'),
('yuanqu-557','山神庙裴度还带・混江龙','关汉卿','元','元曲','yuanqu','','[]','几时得否极生泰？看别人青云独步立瑶阶，摆三千珠履，列十二金钗。',88,'元曲/yuanqu.json','["几时得否极生泰？看别人青云独步立瑶阶，摆三千珠履，列十二金钗。", "我不能勾丹凤楼前春中选，伴着这蒺藜沙上野花开。", "则我这运不至，我也则索宁心儿耐。", "久淹在桑枢瓮牖，几时能勾画阁楼台？。"]'),
('yuanqu-558','山神庙裴度还带・油葫芦','关汉卿','元','元曲','yuanqu','','[]','我则待安乐窝中且避乖，争奈我便时未来！想着这红尘万丈困贤才，那个似那鲁大夫亲赠他这千斛麦？那个似那庞居士可便肯放做来生债？自无了田孟尝，有谁人养剑客？待着我折腰',99,'元曲/yuanqu.json','["我则待安乐窝中且避乖，争奈我便时未来！想着这红尘万丈困贤才，那个似那鲁大夫亲赠他这千斛麦？那个似那庞居士可便肯放做来生债？自无了田孟尝，有谁人养剑客？待着我折腰屈脊的将诗卖，怕不待要寻故友、访吾侪。"]'),
('yuanqu-559','山神庙裴度还带・天下乐','关汉卿','元','元曲','yuanqu','','[]','好教我"十谒朱门九不开"，我可便难也波禁，难禁那等朽木材：一个个铺眉苫眼妆些像态，他肚肠细，胸次狭，眼皮薄，局量窄。',368,'元曲/yuanqu.json','["好教我\"十谒朱门九不开\"，我可便难也波禁，难禁那等朽木材：一个个铺眉苫眼妆些像态，他肚肠细，胸次狭，眼皮薄，局量窄。", "（云）此等人本性难移，（唱）可不道他山河容易改？（正末云）可早来到也。", "报复去，道有裴中立在门首。", "（家童云）你则在这里，我报复去。", "员外，有裴中立在门首。", "（员外云）着他过来。", "（家童云）理会的。", "员外着你过去。", "（正末见科，云）姨夫、姨娘请坐，受您侄儿几拜。", "（旦儿云）裴度，想你父母身亡之后，你不成半器，不肯寻些买卖营生做，你每日则是读书。", "我想来：你那读书的穷酸饿醋有甚么好处，几时能勾发迹也！（正末云）姨娘不知，圣人云：\"富家不用买良田，书中自有千钟粟。", "\"小生我虽居贫贱，我身贫志不贫。", "（员外云）大嫂，人说他胸次高傲，果然如此！我虽不通古今，你是读书人，你说那为人的道理，我试听咱。", "（旦儿云）谁听你那\"之乎者也\"的！（正末唱）。"]'),
('yuanqu-560','山神庙裴度还带・那吒令','关汉卿','元','元曲','yuanqu','','[]','正人伦，传道统，有尧之君大哉；理纲常，训典谟，是孔之贤圣哉；邦反坫，树塞门，敢管之器小哉。',67,'元曲/yuanqu.json','["正人伦，传道统，有尧之君大哉；理纲常，训典谟，是孔之贤圣哉；邦反坫，树塞门，敢管之器小哉。", "整风俗遗后人，立洪范承先代，养情性抱德怀才。"]'),
('yuanqu-561','山神庙裴度还带・后庭花','关汉卿','元','元曲','yuanqu','','[]','你教我休读书，做买卖；你着我去酸寒，可便有些气概。',112,'元曲/yuanqu.json','["你教我休读书，做买卖；你着我去酸寒，可便有些气概。", "你正是那得道夸经纪，我正是成人不自在。", "（旦儿云）你穷则穷，则是胸次高傲。", "(正末唱）我胸次卷江淮，志已在青霄云外。", "叹穷途年少客，一时间命运乖！有一日显威风出浅埃，起云雷变气色。"]'),
('yuanqu-562','山神庙裴度还带・青哥儿','关汉卿','元','元曲','yuanqu','','[]','我稳情取登坛、登坛为帅，我扫妖氛息平蛮貊，你看我立国安邦为相宰。',223,'元曲/yuanqu.json','["我稳情取登坛、登坛为帅，我扫妖氛息平蛮貊，你看我立国安邦为相宰。", "那其间日转千阶，喜笑盈腮，挂印悬牌，坐金鼎莲花碧油幢，骨刺刺的绣旗开。", "恁时节您看我敢青史内标名载！（旦儿云）我本待与你顿饭吃；你这等说大言，我也无那饭也无那钱钞与你，你出去！（正末云）小生但得片云遮顶，不在他人之下。", "（旦儿云）看了你这般嘴脸，一世不能勾发迹，出去！（正末云）好无礼也！你数番教人来请我，来到这里，将这等言语轻慢小生！罢、罢、罢！我冻死饿死，再也不上你家门来！（唱）。"]'),
('yuanqu-563','山神庙裴度还带・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','恰便似梅花遍地开，柳絮因风起。',65,'元曲/yuanqu.json','["恰便似梅花遍地开，柳絮因风起。", "有山皆瘦岭，无处不花飞。", "凛冽风吹，风缠雪银鹅戏，雪缠风玉马垂。", "采樵人荷担空回，更和那钓鱼叟披蓑倦起。"]'),
('yuanqu-564','山神庙裴度还带・梁州','关汉卿','元','元曲','yuanqu','','[]','看路径行人绝迹，我可便听园林冻鸟时啼。',184,'元曲/yuanqu.json','["看路径行人绝迹，我可便听园林冻鸟时啼。", "这其间袁安高卧将门闭。", "这其间寻梅的意懒，访戴的心灰，烹茶的得趣，映雪的伤悲。", "冰雪堂冻苏秦懒谒张仪，蓝关下孝韩湘喜遇昌黎。", "我、我、我，飘的这眼眩耀，认不的个来往回归；是、是、是，我可便心恍惚，辨不的个东西南北；呀、呀、呀，屯的这路弥漫，分不的个远近高低。", "琼姬素衣，纷纷巧剪鹅毛细；战八百万玉龙退败，鳞甲纵横上下飞。", "可端的羡杀冯夷！。"]'),
('yuanqu-565','山神庙裴度还带・隔尾','关汉卿','元','元曲','yuanqu','','[]','这其间正乱飘僧舍茶烟湿，密洒歌楼酒力微，青山也白头老了尘世。',55,'元曲/yuanqu.json','["这其间正乱飘僧舍茶烟湿，密洒歌楼酒力微，青山也白头老了尘世。", "都不到一时半刻，可又早周围四壁，添我在冰壶画图里。"]'),
('yuanqu-566','山神庙裴度还带・牧羊关','关汉卿','元','元曲','yuanqu','','[]','念小生居在白屋，处于布衣，多感谢长老慈悲！为小生缘薄，承吾师厚礼；见一日无空过，整三顿饱斋食。',66,'元曲/yuanqu.json','["念小生居在白屋，处于布衣，多感谢长老慈悲！为小生缘薄，承吾师厚礼；见一日无空过，整三顿饱斋食。", "你今日患难哀怜我，久以后得峥嵘答报你。"]'),
('yuanqu-567','山神庙裴度还带・骂玉郎','关汉卿','元','元曲','yuanqu','','[]','有那等嫌贫爱富的儿曹辈，将俺这贫傲慢，把他那富追陪，那个肯恤孤念寡存仁义？有那一等靠着富贵，有干万乔所为，有那等夸强会。',87,'元曲/yuanqu.json','["有那等嫌贫爱富的儿曹辈，将俺这贫傲慢，把他那富追陪，那个肯恤孤念寡存仁义？有那一等靠着富贵，有干万乔所为，有那等夸强会。", "（长老云）秀才真乃英才之辈，比他人不同也。", "（正末唱）。"]'),
('yuanqu-568','山神庙裴度还带・感皇恩','关汉卿','元','元曲','yuanqu','','[]','他显耀些饱暖衣食，卖弄些精细伶俐。',84,'元曲/yuanqu.json','["他显耀些饱暖衣食，卖弄些精细伶俐。", "怎听他假文谈，胡答应，强支持！出身于市井，便显耀雄威；则待要邀些名誉，施些小惠，要些便宜。", "（长老云）真乃君子、小人不同也！（正末唱）。"]'),
('yuanqu-569','山神庙裴度还带・采茶歌','关汉卿','元','元曲','yuanqu','','[]','无才学有权势，有文章受驱驰，长老，这的是鹤长凫短不能齐！比小生剩趱浮财润自己，比吾师身穿几件虼虫两皮。',51,'元曲/yuanqu.json','["无才学有权势，有文章受驱驰，长老，这的是鹤长凫短不能齐！比小生剩趱浮财润自己，比吾师身穿几件虼虫两皮。"]'),
('yuanqu-570','山神庙裴度还带・贺新郎','关汉卿','元','元曲','yuanqu','','[]','通神的许负细详推，地阁天仓，兰台廷尉测他那山根印堂人中贵，五露三停六极，龙角鱼尾伏犀；肉眼藏天地理，风鉴隐鬼神机。',155,'元曲/yuanqu.json','["通神的许负细详推，地阁天仓，兰台廷尉测他那山根印堂人中贵，五露三停六极，龙角鱼尾伏犀；肉眼藏天地理，风鉴隐鬼神机。", "断祸福、观气色、占凶吉，这厮好世情看冷暖，人面逐高低！（野鹤云）秀才，你休怪小子。", "我敢断人生死无差，生则便生，死则便死，相法中无有不准．江湖上谁不知道肉眼通神相！人皆称呼我做无虚道人。", "（正末唱）。"]'),
('yuanqu-571','山神庙裴度还带・乌夜啼','关汉卿','元','元曲','yuanqu','','[]','稳情取禹门三级登鳌背，振天关平地一声雷。',153,'元曲/yuanqu.json','["稳情取禹门三级登鳌背，振天关平地一声雷。", "看堂堂图相麒麟内，有一日列鼎而食，衣锦而回。", "那其间青霄独步上天梯，看姓名亚等呼先辈；攀龙鳞，附凤翼，显五陵豪气，吐万丈虹霓。", "（野鹤云）相法所断，何故大怒？（长老云）裴中立，虽然相法中如此断，也看人心上所积，可不道：人有可延之寿也。", "（野鹤云）小子无虚言也。", "（正未唱）。"]'),
('yuanqu-572','山神庙裴度还带・煞','关汉卿','元','元曲','yuanqu','','[]','噤声！我则理会的"先生之道斯为美"；正是"不患人之不己知"。',125,'元曲/yuanqu.json','["噤声！我则理会的\"先生之道斯为美\"；正是\"不患人之不己知\"。", "则是你个巧言令色打家贼，不辨个贵贱高低！按不住浩然之气，你看我登科甲便及第。", "若是我金榜无名誓不回，有一日我独步丹墀。", "（长老云）秀才，再答话一回去波。", "（正末不辞出门科，云）罢、罢、罢！（唱）。"]'),
('yuanqu-573','山神庙裴度还带・正宫/端正好','关汉卿','元','元曲','yuanqu','','[]','我愁见古松林，我这里便怕到兀那崩摧庙。',55,'元曲/yuanqu.json','["我愁见古松林，我这里便怕到兀那崩摧庙。", "我可便叹吾生久困蓬蒿，看别人\"青霄有路终须到\"，知他我何日\"朝闻道\"？。"]'),
('yuanqu-574','山神庙裴度还带・滚绣球','关汉卿','元','元曲','yuanqu','','[]','今日见那赵野鹤，他观了我相貌；他道冻饿纹耳连着口角，横死纹鬓接着眉梢；他道我主福禄薄，更寿夭。',154,'元曲/yuanqu.json','["今日见那赵野鹤，他观了我相貌；他道冻饿纹耳连着口角，横死纹鬓接着眉梢；他道我主福禄薄，更寿夭。", "则他那相法中无他那半星儿差错，他道：\"我断的准也不差分毫。", "\"我平生正直无私曲，一任天公饶不饶！这的是\"善与人交\"。", "（正末云）来到这山神庙也。", "我与你拂了这头上雪，入的这庙来。", "这庙如此疏漏，又待倒也，如之奈何？（唱）。"]'),
('yuanqu-575','山神庙裴度还带・醉太平','关汉卿','元','元曲','yuanqu','','[]','我则见泥脱下些仰托。',79,'元曲/yuanqu.json','["我则见泥脱下些仰托。", "更和这水浸过这笆箔。", "我则见梁漕椽烂柱根糟，这的是欠九分来待倒。", "这一座十疏九漏山神庙，如十花九裂寒冰窖，似十摧九塌草团瓢，比着那漏星堂较少。"]'),
('yuanqu-576','山神庙裴度还带・倘秀才','关汉卿','元','元曲','yuanqu','','[]','水头巾供桌上控着，泥脚靴土墙边晾着。',65,'元曲/yuanqu.json','["水头巾供桌上控着，泥脚靴土墙边晾着。", "（正末云）裴中立也！（唱）我可甚\"买卖归来汗未消\"！凄凉愁今夜，犹自想来朝，藁荐上和衣儿睡倒。"]'),
('yuanqu-577','山神庙裴度还带・呆骨朵','关汉卿','元','元曲','yuanqu','','[]','我恰才待盘膝裹脚向亭柱上靠。',119,'元曲/yuanqu.json','["我恰才待盘膝裹脚向亭柱上靠。", "这藁荐下垫的来偌高！我这里悄悄量度，好着我暗暗的暗约。", "（正末云）我试抹藁荐下咱。", "（做拿起带科，云）是一条带！（唱）不由我小胆儿心中怕，唬的我小鹿儿心头跳；那一个富豪家失忘了？天呵！天呵！把我这穷魂灵儿险唬了！。"]'),
('yuanqu-578','山神庙裴度还带・倘秀才','关汉卿','元','元曲','yuanqu','','[]','我辨认的分分晓晓，我可便惹一场烦烦恼恼，我今夜索思量计万条。',52,'元曲/yuanqu.json','["我辨认的分分晓晓，我可便惹一场烦烦恼恼，我今夜索思量计万条。", "若有人来寻觅，我权与他且收着，我两只手捧托。"]'),
('yuanqu-579','山神庙裴度还带・小梁州','关汉卿','元','元曲','yuanqu','','[]','借问你个老妪缘由，女艳娇，你因甚事细说根苗。',651,'元曲/yuanqu.json','["借问你个老妪缘由，女艳娇，你因甚事细说根苗。", "（云）你有甚么冤枉，在此觅死？你从头至尾说一遍咱。", "（旦儿云）我看来这个人必是个儒人秀士。", "哥哥不嫌絮烦，听妾从头至尾说一遍咱。", "妾身乃洛阳韩太守的女孩儿，这个是我母亲，嫡亲的三口儿家属。", "父亲在此为理，与人秋毫无犯。", "为因上司差傅彬来河南点检钱粮，傅彬到此洛阳。", "问我父要上马钱下马钱，我父不肯与他；后来傅彬为侵使过官钱，追赃赔纳，不想傅彬贼子怀挟前仇，指下家父三千贯赃。", "奏闻行移至本府，提下家父，下于缧绁，赔赃三千贯。", "事以不明，难为伸诉；下情不能上达，何须分辩！不能越朝廷法例，舒心赔纳。", "家中收拾止勾送饭日用而已。", "父母面上亲戚处助一千贯。", "父母止生妾身一个，因父祖名家，老母家训，教妾读书吟诗写字。", "在城里外，妾身怀羞搠笔题诗救父难，得市户乡民恻隐，一则为父清廉，二则因妾孝道，半年中抄化了一千贯。", "陆续纳入官，前后二千贯。", "尚有一千贯未完，父亲未能脱禁。", "则见一日城市中有人对妾言说：\"小姐，这城中关厢里外，人事上也絮繁了。", "近日朝廷差一公子，来此歇马，今日说往城东去，有人见在邮亭赏雪饮酒哩，若到那里，一则提笔卖诗，二则诉父冤枉，但得些滋润，勾你赔赃也。", "\"听的说罢急走出城，来至邮亭，正见公子赏雪饮酒。", "见妾，问其缘故；妾将前事尽诉其情，公子甚是怜念。", "又命妾题诗，妾随做诗数首。", "公子甚喜，就赐腰间玉带一条，价值千金，与妾身救父脱禁。", "妾欲要回城中，到此半路风紧雪大，妾在此庙中歇脚避雪，不觉身体困倦，在此歇息，我将玉带放在藁荐下。", "猛然省来，诚恐天晚母亲在家悬望，妾身慌走出庙来。"]'),
('yuanqu-580','山神庙裴度还带・幺篇','关汉卿','元','元曲','yuanqu','','[]','你道是从来养小防备老，都一般哀哀父母劬劳。',544,'元曲/yuanqu.json','["你道是从来养小防备老，都一般哀哀父母劬劳。", "（带云）先圣有言：\"身体发肤，受之父母，不敢毁伤，孝之始也。", "\"（唱）你便怎生舍性命寻自吊？（带云）\"扬名于后世，以显父母，孝之终也。", "\"（唱）这的可也方为全孝。", "（云）\"父母全而生之，子全而归之，可为孝也。", "\"（唱）则这的是为人子立的根苗。", "（夫人云）据先生说呵，也说的是；争夺我夫主无辜受禁，眼睁睁不得脱难，则觑着这条玉带救夫主；不见了，似此这般，一千贯赃几时纳的了也！（正末云）夫人、小娘子，假若有这玉带呵呢？（夫人云）若是有这玉带呵，便是救了俺一家性命也。", "（正末云）假若无了这玉带呵呢？（夫人云）俺一家儿便是死的，都不得活也。", "（正末云）老夫人、小娘子放心，玉带我替你收着哩！（旦儿云）先生勿戏言！（正未云）孔子门徒，岂有戏言！（正末做取带科，云）娘子，兀的不是带，还你！（旦儿接科，云）兀的不正是此带！索是谢了先生。", "（夫人云）孩儿也，俺娘儿两个一齐的拜谢先生咱。", "（正末云）不敢！不敢！（夫人云）先生救活我一家之恩，此义非轻也！世间似先生者世之罕有。", "处于布衣窘暴之中，千金不改其志，端的是仁人君子也！（正末云）不敢！不敢！世间似小娘子贞孝之女--自古孝子多，孝女少--女子中只有两三个人也。", "（夫人云）是那两三个？先生试说，老身洗耳愿闻咱。", "（正末唱）。"]'),
('yuanqu-581','山神庙裴度还带・叨叨令','关汉卿','元','元曲','yuanqu','','[]','当日个贾氏为父屠龙孝，杨香为父跨虎曾行孝，曹蛾为父嚎江孝；今日个琼英为父题诗孝。',76,'元曲/yuanqu.json','["当日个贾氏为父屠龙孝，杨香为父跨虎曾行孝，曹蛾为父嚎江孝；今日个琼英为父题诗孝。", "端的可便感天地也波哥，端的可便感天地也波哥！为父母呵，男女皆可尽人之孝。"]'),
('yuanqu-582','山神庙裴度还带・塞鸿秋','关汉卿','元','元曲','yuanqu','','[]','我则待粗衣淡饭从吾乐，我一心待要固穷守分天之道，我则待存心谨守先王教。',133,'元曲/yuanqu.json','["我则待粗衣淡饭从吾乐，我一心待要固穷守分天之道，我则待存心谨守先王教。", "（旦儿云）先生恰才不与此带，无计所奈也！（正末唱）可不道\"君子不夺人之好\"？（夫人云）老身一家处于患难，先生也在窘迫，故使先生救我一家性命。", "（正末唱）夫人处患难，小生甘穷暴，咱正是摇鞭举棹休相笑。"]'),
('yuanqu-583','山神庙裴度还带・倘秀才','关汉卿','元','元曲','yuanqu','','[]','出庙门送下涩道，近行径转过墙角，这的是贫不忧愁富不骄。',202,'元曲/yuanqu.json','["出庙门送下涩道，近行径转过墙角，这的是贫不忧愁富不骄。", "（旦儿云）妾身看了秀才，若非古之君子，岂有如此局量！此还带之意．异日必当重报于足下。", "《毛诗》云：\"投之以木桃，报之以琼瑶。", "\"焉敢忘恩人之大德也！（正末唱）你道是\"投之以木桃，报之以琼瑶\"，小人怎敢比古人量作！（旦儿云）此时世俗，惟先生之一人；礼义廉耻道德之风--余者俗子，受不明之物，取不义之财--有几人也？（正末云）\"皇天无私，惟德是辅\"。", "（唱）。"]'),
('yuanqu-584','山神庙裴度还带・滚绣球','关汉卿','元','元曲','yuanqu','','[]','咱人命里有呵福禄增，（云）暗室亏心，神目如电。',175,'元曲/yuanqu.json','["咱人命里有呵福禄增，（云）暗室亏心，神目如电。", "（唱）命里无时灾祸招。", "（云）近之不逊，远之又怨。", "（唱）受不明物呵不合神道，（云）\"不义而富且贵，于我如浮云\"！（唱）取不义财呵枉物难消。", "（见儿云）据先生如此大量，当来发达于世，岂不壮哉！（正未唱）有一日蛰龙奋头角，风云醉碧桃；酬志也五陵年少，轩昂也当发英豪；伴旌旗日暖龙蛇动，看宫殿风微燕雀高，雁塔名标。"]'),
('yuanqu-585','山神庙裴度还带・煞','关汉卿','元','元曲','yuanqu','','[]','阴阳有准无虚道，好一个肉眼通神赵野鹤！咱人这祸福难逃，吉凶怎避，莫得执迷，枉了徒劳！判断在昨日，分已定前生，果应于今朝。',240,'元曲/yuanqu.json','["阴阳有准无虚道，好一个肉眼通神赵野鹤！咱人这祸福难逃，吉凶怎避，莫得执迷，枉了徒劳！判断在昨日，分已定前生，果应于今朝。", "若是碎砖瓦里命终得这身夭，险些儿白骨卧荒郊！（夫人云）先生为何如此惊叹？必有其情，乞请知之。", "（正末云）老夫人不知。", "小生昨日在白马寺中遇一相士，说小生今日不过午，一命掩泉土，今日午前死于碎砖瓦之下。", "今日果应其言！小生若不为还此带，送出老夫人、小姐来呵，小生正遭此一死也！（夫人云）皆是先生阴德大重，救我一家之命，因此遇大难不死；必有后程，准定发迹也！（正末唱）。"]'),
('yuanqu-586','山神庙裴度还带・尾声','关汉卿','元','元曲','yuanqu','','[]','我但得一朝冠盖向长安道，趁着这万里风头鹤背高。',146,'元曲/yuanqu.json','["我但得一朝冠盖向长安道，趁着这万里风头鹤背高。", "有一日享荣华、受官爵，早则不居无安，食无饱。", "（旦儿云）此恩此德，时刻未忘。", "（夫人云）我记着先生这个模样，请个良工写像传真，侍奉终日，烧香供养先生也。", "（正末唱）你道是这恩临决然报，常记着休忘了，命良工写像传真，点烛烧香，你将我来供养。", "到老。", "（下）。"]'),
('yuanqu-587','山神庙裴度还带・双调/新水令','关汉卿','元','元曲','yuanqu','','[]','想着我二十年埋没洛阳尘，今日个起蛰龙一声雷震；一来文章好立身，二来是天子重贤臣。',70,'元曲/yuanqu.json','["想着我二十年埋没洛阳尘，今日个起蛰龙一声雷震；一来文章好立身，二来是天子重贤臣。", "好德亲仁，束带冠巾，演武修文，温故知新，咱人要修天爵正方寸。"]'),
('yuanqu-588','山神庙裴度还带・庆东原','关汉卿','元','元曲','yuanqu','','[]','居廊庙，当缙绅，习《诗》《书》，学《礼》《易》，从先进君子务本。',109,'元曲/yuanqu.json','["居廊庙，当缙绅，习《诗》《书》，学《礼》《易》，从先进君子务本。", "忘身发愤，能正其身。", "酬志了白玉带紫朝服，茶褐伞黄金印。", "（媒人云）瑶池降谪三天仙，今夜高门招状元。", "琼酿金杯长寿酒，新郎舒手接丝鞭。", "请状元接丝鞭！（正末唱）。"]'),
('yuanqu-589','山神庙裴度还带・川拨棹','关汉卿','元','元曲','yuanqu','','[]','展图像挂高门，彩楼新接着绛云。',69,'元曲/yuanqu.json','["展图像挂高门，彩楼新接着绛云。", "我自见皓齿朱唇，翠袖红裙，簇捧个雾鬓云鬟的美人。", "见官媒将导引，他道招状元为婿君，不邀媒不问肯，惊丝鞭捧玉樽。"]'),
('yuanqu-590','山神庙裴度还带・殿前欢','关汉卿','元','元曲','yuanqu','','[]','你道是擢新人，今宵花浊洞房春。',149,'元曲/yuanqu.json','["你道是擢新人，今宵花浊洞房春。", "绣球儿抛得风团顺，肯分的正中吾身。", "（媒人云）请状元下马就亲！（正末唱）硬逼临便就亲。", "（媒人云）状元下马就亲，洞房花烛，燕尔新婚。", "（正末唱）噤声！你那里无谦逊。", "（媒人云）《毛诗》去：\"淑女可配君子。", "\"（正末唱）那里是正押《毛诗》韵？你道做了有伤风化，谁就你那燕尔新婚！。"]'),
('yuanqu-591','山神庙裴度还带・乔牌儿','关汉卿','元','元曲','yuanqu','','[]','几曾见酩子里两对门！（媒人云）系是五百年前宿缘仙契。',95,'元曲/yuanqu.json','["几曾见酩子里两对门！（媒人云）系是五百年前宿缘仙契。", "（正末唱）你道是五百年宿缘分，（媒人云）请状元拜岳父岳母，相见礼毕成亲，有圣旨在此。", "（正末唱）他道是奉君王圣旨为盟信，终不我为媳妇拜丈人。"]'),
('yuanqu-592','山神庙裴度还带・水仙子','关汉卿','元','元曲','yuanqu','','[]','想起他那芙蓉娇貌蕙兰魂，杨柳纤腰红杏春，海棠颜色江梅韵；他恨不的上青山变化身，这其间卖登科寻觅回文。',78,'元曲/yuanqu.json','["想起他那芙蓉娇貌蕙兰魂，杨柳纤腰红杏春，海棠颜色江梅韵；他恨不的上青山变化身，这其间卖登科寻觅回文。", "这裴中立身荣贵，那韩琼英守志真，我怎背着别人做了夫人！。"]'),
('yuanqu-593','山神庙裴度还带・雁儿落','关汉卿','元','元曲','yuanqu','','[]','谁承望楚阳台做眷姻，蓝桥驿相亲近，武陵溪寻配偶，桃源洞成秦晋！。',32,'元曲/yuanqu.json','["谁承望楚阳台做眷姻，蓝桥驿相亲近，武陵溪寻配偶，桃源洞成秦晋！。"]'),
('yuanqu-594','山神庙裴度还带・得胜令','关汉卿','元','元曲','yuanqu','','[]','"敬亲者不敢慢于人"。',170,'元曲/yuanqu.json','["\"敬亲者不敢慢于人\"。", "（韩公云）状元，今日酬志，如此轩昂！（正末唱）享富贵必有异于人。", "（旦儿云）还带之恩，配合姻眷，两意俱完，各遂其心矣。", "（正末唱）小生我怀旧意无私志，小姐白玉带知恩必报恩。", "（韩公云）老夫蒙恩骤迁，夫人三月齑盐小女甘贫行孝，今日一家富贵。", "谁想有今日也！（正未唱）为岳丈公勤，掌都省三台印，老夫人忠贞，小姐守一百日齑盐清淡贫。"]'),
('yuanqu-595','南吕・一枝花廷仪公子实当代都督李公之家嗣也。器宇宏达，才华瞻敏，','沈禧','元','元曲','yuanqu','','[]','百氏之书，靡不该浃；至于龙韬虎略，不待言而可知也。',277,'元曲/yuanqu.json','["百氏之书，靡不该浃；至于龙韬虎略，不待言而可知也。", "及乎礼贤下士，彬彬然诚有儒者之风，不以富贵而骄慢于人，以是人皆景仰而乐与之游。", "今年冬适过吴门，解鞍旅馆，予得获见，遂即倾盖，欢若平生。", "于是宿留，命酌于小楼之上，鸣琴赋诗，放歌剧饮，以罄一时之欢。", "既而出诸名公所赠词章乐府以示予且咏然，其辞气雄伟，风调清越，不觉使人技痒。", "愧予无似，曷克窥其阃奥而闯其藩篱哉。", "兹不自揣，勉述〔南吕〕一阕以呈。", "校诸杰作，固不能模楷其万一，然于期望之私，庶几有在焉。", "瑶台上品仙，麟阁中人物。", "胸襟开宇宙，器量溢江湖。", "声振寰区，会见悬鱼袋，行看佩虎符。", "锦みま人跨凤侣，金蹀躞马骤龙驹。"]'),
('yuanqu-596','余音・玉鞭骄马游荆楚，锦缆牙樯下汴吴，解垢琴书客窗遇。学能周鲁，','沈禧','元','元曲','yuanqu','','[]','才兼文武，伫看袭爵封侯快陛补。',264,'元曲/yuanqu.json','["才兼文武，伫看袭爵封侯快陛补。", "题张思恭“望云思亲卷”时父母已殁矣（并序）吾乡张思恭尝持“望云思亲诗卷”征予诗。", "予嘉思恭之意，遂赋五言古诗一首，已归之矣。", "兹复请余词，将欲揭者座隅而朝夕歌咏之，以示不忘亲之故也。", "大唐梁公仁杰为并州法曹时，登太行见白去孤飞，因指曰：“吾亲舍在其下。", "”云移乃去。", "此梁公思亲于在堂之日。", "矧今思恭望云思亲于既殁之后，其孝也为何如哉！予益嘉恭之孝且纯也，故不辞而复述〔南吕〕词一阕以贻之。", "人为万物灵，孝乃一身本。", "贤愚均化育，今古重彝伦。", "敬祖尊亲，晨昏宜定省，冬夏问寒温。", "看古来孝诸贤俊，到如今青史流芳世不湮。"]'),
('yuanqu-597','梁州・且休说唐时仁杰专前美，谁知道晋代张翰有远孙。家居积祖松陵隐。','沈禧','元','元曲','yuanqu','','[]','双亲沦殁，一念犹存。',109,'元曲/yuanqu.json','["双亲沦殁，一念犹存。", "既归黄壤，望断白云。", "我则见卷舒触石生肤寸，我则见变化从龙出厚坤。", "云来时好着我搅断柔肠，云聚处好着我结愁成阵，云飞时好着我飘散心神。", "泪痕，满巾。", "恨无羽翼能飞奋，越思忖越愁闷。", "怎得吾亲更返魂，报答深恩。"]'),
('yuanqu-598','余音・云横岭岫连丘陇，云锁松揪掩墓门。云来云往何时尽？孝心未伸，','沈禧','元','元曲','yuanqu','','[]','孝思怎忍？留取个孝行名儿做标准。',83,'元曲/yuanqu.json','["孝思怎忍？留取个孝行名儿做标准。", "七月初六日为施以和寿长生境上仙，仁寿乡中叟。", "七贤林下客，九老会中俦。", "绀发青眸，适兴娱诗酒，忘情狎鹭鸥。", "拣林泉胜处遨游，乐桑榆晚景优游。"]'),
('yuanqu-599','余音・溪南剩把茅堂构，深隐烟霞傲列侯，闲来时抚孤松看尽云横岫。利','沈禧','元','元曲','yuanqu','','[]','名不求，是非总休，似这般五福俱全世希有。',84,'元曲/yuanqu.json','["名不求，是非总休，似这般五福俱全世希有。", "赠妓桂香秀马氏不同桃李芳，自历风霜久。", "幽姿超万卉，素质压凡流。", "品异名优，素娥为伴侣，青女结绸缪。", "古香飘玉宇银沟，清影蔽绿窗朱牖。"]'),
('yuanqu-600','梁州・银蟾影里孤根瘦，玉兔光中万粟稠。占高秋骨与繁华斗。狂蜂难觅，','沈禧','元','元曲','yuanqu','','[]','粉蝶谁搜。',96,'元曲/yuanqu.json','["粉蝶谁搜。", "别许那状元攀折，仙客雕搜。", "品题一出骚人手，声价平增了五百筹。", "你看他吐新词胸藏锦绣，舞霓裳步撒香钩，整金钗指露纤柔。", "莫愁，见羞。", "紫云红拂皆居后。", "□□□更清秀。", "总有千金未许酬，名擅青楼。"]'),
('yuanqu-601','梁州・秦台夜月乘鸾凤，谢馆春风醉管弦。千金拣得如花面。腰肢袅娜，','沈禧','元','元曲','yuanqu','','[]','体态婵娟。',94,'元曲/yuanqu.json','["体态婵娟。", "文禽翼比，瑞木枝连。", "仰见他舞霓裳风摇翠柳，临鸾镜水映红莲。", "则这捧霞觞翠袖殷勤，按银筝珠玑错落，歌白雪金玉相宣。", "百年，业冤。", "姑苏台下重相见，意绸缪情眷恋。", "山海深盟胶漆坚，永保团圆。"]'),
('yuanqu-602','余音・毫分不惜蝇头利，十万曾缠鹤背钱，红景乡中姿欢宴。行携素手，','沈禧','元','元曲','yuanqu','','[]','坐并香肩，似这般美满恩情世间鲜。',79,'元曲/yuanqu.json','["坐并香肩，似这般美满恩情世间鲜。", "咏雪景千山鸟罢飞，四野云同螟。", "九天敷上瑞，万国贺升平。", "积素堆琼，幻出冰壶镜，妆成白玉京。", "那时节拥蓝关马足难行，临蔡地兵威越整。"]'),
('yuanqu-603','梁州・这其间江头有客寻归艇，我这里醉里题诗漫送程。你看他溯澄江下','沈禧','元','元曲','yuanqu','','[]','不减王猷兴。',108,'元曲/yuanqu.json','["不减王猷兴。", "冲开鹭序，荡散鸥盟。", "梨花乱撒，柳絮飘零。", "那时节酒停斟听唱阳春，人将别重歌古郢。", "想当初钓鱼人击冻敲冰，骑驴客冲寒忍冷，牧羊徒守节持旌。", "美名，擅称。", "辉光照耀终难泯，他每志坚贞秉忠正。", "一片丹衷贯日星，流播芳馨。"]'),
('yuanqu-604','余音・香缣貌得三冬景，彩笔吟成万古情，临行持此为相赠。则愿你艺超','沈禧','元','元曲','yuanqu','','[]','薛谭，才压秦青，那时节声价超迁迈夷等。',80,'元曲/yuanqu.json','["薛谭，才压秦青，那时节声价超迁迈夷等。", "寿人八十南山颂载歌，北海樽频敬。", "西池桃并结，东土佛重生。", "八秩初登，伫见膺三聘，行看受七征。", "享期颐松柏遐龄，宜受用桑榆晚景。"]'),
('yuanqu-605','梁州・我则见碧天边一点孤星现，陆地上千枝火树明。正生甲却值元宵景。','沈禧','元','元曲','yuanqu','','[]','欢声涌沸，弦管铿锵。',102,'元曲/yuanqu.json','["欢声涌沸，弦管铿锵。", "高开绮筵，胜会宾朋。", "捧遐觞翠袖殷勤，歌白雪金钗列整。", "人都道降长生蓬岛仙乡，跻寿考香山老宿，东升平洛社耆英。", "本是个德星，寿星。", "从今五福都兼并，顺天时乐天性。", "见尽黄河几浅清，则愿寿等岗陵。"]'),
('yuanqu-606','余音・庄庭椿老枝偏盛，海屋筹添数倍增，看来年渭水风云庆。名流汗青，','沈禧','元','元曲','yuanqu','','[]','功莲良平，那时节爵位高崇列台鼎。',81,'元曲/yuanqu.json','["功莲良平，那时节爵位高崇列台鼎。", "咏白牡丹不将脂粉施，自有天然态。", "羊脂轻捻就，酥乳砌成来。", "夹叶重台，妖红冶艳都难赛。", "素质檀心可喜煞，水晶球无贬无褒，白玉瓣不宽不窄。"]'),
('yuanqu-607','梁州・彻赚得寻芳客争探斗买，勾引得惜花人浅耨深埋。冠群不入凡流派。','沈禧','元','元曲','yuanqu','','[]','沉香亭馆，碧玉台阶，黄蜂难觅，粉蝶难猜。',106,'元曲/yuanqu.json','["沉香亭馆，碧玉台阶，黄蜂难觅，粉蝶难猜。", "倚东风连理争开，迎晚日并蒂相偕。", "我则道紫麝脐调合就天香，白凤翎铺排着国色，玉梅英妆点出容额。", "洁白，莹白。", "涅难缁标格堪人爱，困雕阑脉脉犹黄你。", "卯酒才消晕粉腮，那时节笑靥微开。"]'),
('yuanqu-608','余音・歌钟到处携欢约，舞袖飘时压善才，博得个能是的名儿自多赖。再','沈禧','元','元曲','yuanqu','','[]','休去迷花恋色，再休去惹垢沾埃。',29,'元曲/yuanqu.json','["休去迷花恋色，再休去惹垢沾埃。", "他本是个救苦难的观音离南海。"]'),
('yuanqu-609','江州司马青衫泪・仙吕/点绛唇','马致远','元','元曲','yuanqu','','[]','从天未拔白，酒旗挑在歌楼外。',27,'元曲/yuanqu.json','["从天未拔白，酒旗挑在歌楼外。", "呀地门开，早送旧客迎新客。"]'),
('yuanqu-610','江州司马青衫泪・天下乐','马致远','元','元曲','yuanqu','','[]','则索倚定门儿手托腮，想别人家奴胎，也得个自在；轮到我根脚里，都世袭了烟月牌。',203,'元曲/yuanqu.json','["则索倚定门儿手托腮，想别人家奴胎，也得个自在；轮到我根脚里，都世袭了烟月牌。", "他管甚桃李开，风雨筛，更问甚青春不再来。", "(白乐天同贾、孟上，云)走了这半日，人说道这是裴妈妈家。", "不好进去，我咳嗽一声。", "(卜儿云)是谁在外边？(出见科)原来是三位进士公，请里面坐。", "(白乐天同贾、孟云)妈妈祗揖。", "(卜儿云)兴奴孩儿，来陪三位进士公。", "快抬桌儿，看酒来！(正旦觑科，云)好是奇怪，娘见了三个秀才踏门，怎生便教看酒？(唱)。"]'),
('yuanqu-611','江州司马青衫泪・醉扶归','马致远','元','元曲','yuanqu','','[]','送了几辈儿茶员外，都是这一副儿酒船台。',116,'元曲/yuanqu.json','["送了几辈儿茶员外，都是这一副儿酒船台。", "俺娘吃不的荤腥教酒肉搋，待觅厌饫的新黄菜。", "他手里怎容得这几个酸寒秀才？(带云)我知道了也。", "(唱)俺娘八分里又看上他那条乌犀带。", "(正旦出见科)三位万福。", "(白乐天同贾、孟云)大姐祗揖了。", "(正旦唱)。"]'),
('yuanqu-612','江州司马青衫泪・后庭花','马致远','元','元曲','yuanqu','','[]','这里是风尘花柳街，又不是王侯宰相宅。',258,'元曲/yuanqu.json','["这里是风尘花柳街，又不是王侯宰相宅。", "我忙着笑脸儿迎将去，学士是甚风儿吹到来？(白乐天云)我等久慕高名，特来一拜。", "(正旦唱)是几个俊秀才，偏他还咱一拜，怎做的内心儿不敬色。", "(云)敢问官人尊姓大名？(白乐天云)小生是侍郎白居易。", "这二位是学士贾浪仙、孟浩然。", "因此春日，公衙无事，换了衣服来街市闲行。", "久慕大姐德容，一径的来拜望。", "(正旦云)不敢不敢。", "学士大人不弃下贱，小酌三杯如何？(白乐天云)好便好，只是不敢取扰。", "(正旦把酒科)(贾浪仙云)今日幸遇大姐，咱多饮几杯。", "(孟浩然云)我还有人求的几首诗未了，少吃醉些。", "(正旦唱)。"]'),
('yuanqu-613','江州司马青衫泪・后庭花','马致远','元','元曲','yuanqu','','[]','你待赚鳌鱼钓颊腮，怎想与刘伶装布袋？我这怪脸儿奸如鬼，你酒肠宽似海。',151,'元曲/yuanqu.json','["你待赚鳌鱼钓颊腮，怎想与刘伶装布袋？我这怪脸儿奸如鬼，你酒肠宽似海。", "(贾、孟云)我们都已醉了，不要过了酒戒，不吃罢。", "(正旦唱)畅开怀，都似你朦胧酒戒，那醉乡侯安在哉？(卜儿云)二位学士醉了，侍郎再坐一坐。", "(贾、孟云)乐天侍郎，咱且回去，明日再来。", "(白乐天云)平白里打扰了一日，怎生就空去了？(正旦唱)。"]'),
('yuanqu-614','江州司马青衫泪・金盏儿','马致远','元','元曲','yuanqu','','[]','我不曾流水出天台，你怎么走马到章台。',98,'元曲/yuanqu.json','["我不曾流水出天台，你怎么走马到章台。", "(乐天云)定害了你这一日。", "(正旦唱)更待要秦楼夜访金钗客，索甚么恶叉白赖闹了洛阳街。", "兀那酒丧门临本命，饿太岁犯家宅。", "虽是我管待这两个穷秀士，权当一百日血光灾！。"]'),
('yuanqu-615','江州司马青衫泪・赚煞','马致远','元','元曲','yuanqu','','[]','稍似间有些钱，抵死里无多债，权做这场折本买卖。',114,'元曲/yuanqu.json','["稍似间有些钱，抵死里无多债，权做这场折本买卖。", "若信着俺当家老奶奶，把惜花心七事儿分开。", "哎，你个俏多才，不是我相择，你更怕辱没着俺门前下马台！俺娘山河易改，解元每少怪。", "(带云)侍郎记者，(唱)怕你再行踏，休引外人来。", "(同下)楔子。"]'),
('yuanqu-616','江州司马青衫泪・正宫/端正好','马致远','元','元曲','yuanqu','','[]','命轻薄，身微贱，好人死万万千。',57,'元曲/yuanqu.json','["命轻薄，身微贱，好人死万万千。", "世间儿女别离遍，也敷不上俺那阳关怨！(带云)侍郎，不争你去了，教我倚靠何人？(唱)。"]'),
('yuanqu-617','江州司马青衫泪・滚绣球','马致远','元','元曲','yuanqu','','[]','你好下得白解元，闪下我女少年。',369,'元曲/yuanqu.json','["你好下得白解元，闪下我女少年。", "道不得可怜而见，他又不曾故违着天子三宣。", "(云)人说白侍郎吟诗吃酒误了政事，前人也有这等的。", "(唱)只那长安市李谪仙，他向酒里卧酒里眠，尚古自得贵妃捧砚，常走马在五凤楼前。", "偏教他江州迭配三千里，可不道吏部文章二百年，甚些的纳士招贤？(见卜科，云)母亲，叫你孩儿怎么？(卜儿云)白侍郎一去杳无音信，咱家柴没米没，怎生过活？如今浮梁刘官人有三千引茶，又标致又肯使钱。", "你留下他，赚些钱养家。", "(正旦云)母亲，我与白侍郎有约在前，我再不留人了。", "(卜儿云)我说你也不信，请刘官人自家来和你说。", "(净见旦科，云)大姐拜揖，小人久慕大名，拿着三千引茶来与大姐焐脚，先送白银五十两做见面钱。", "(正旦云)过一边去！好不知高低。", "我做了白侍郎之妻，休来缠我！(卜儿云)你不肯陪我刘员外，好个白侍郎夫人！如今白侍郎那里敢颓气了也。", "(正旦唱)。"]'),
('yuanqu-618','江州司马青衫泪・倘秀才','马致远','元','元曲','yuanqu','','[]','这姻缘成不成在天，你休见兔儿起呵漾砖。',100,'元曲/yuanqu.json','["这姻缘成不成在天，你休见兔儿起呵漾砖。", "情知普天下虔婆那一个不爱钱。", "(带云)刘员外呵，(唱)他便是贵公子、赵平原，你也要过遣。", "(净云)你家是卖俏门庭，我来做一程子弟，你不留我，如何倒拒绝我？(正旦唱)。"]'),
('yuanqu-619','江州司马青衫泪・滚绣球','马致远','元','元曲','yuanqu','','[]','这的是我逆耳言，休厮缠、厮缠着舞裙歌扇，这两般儿曾风流断没了家缘。',99,'元曲/yuanqu.json','["这的是我逆耳言，休厮缠、厮缠着舞裙歌扇，这两般儿曾风流断没了家缘。", "刘员外你若识空便，早动转，倒落得满门良贱。", "休觑着我这陷人坑，似误入桃源；我怕你两尖担脱了孤馆思乡客，三不归翻了风帆下水船，枉受熬煎。"]'),
('yuanqu-620','江州司马青衫泪・倘秀才','马致远','元','元曲','yuanqu','','[]','这些时但合眼早怀儿里梦见，则是俺吃倒赚江州乐天。',133,'元曲/yuanqu.json','["这些时但合眼早怀儿里梦见，则是俺吃倒赚江州乐天。", "(卜儿云)见钟不打，更去炼铜。", "乐天乐天，在那里？(净云)小子也看的过，咱做一程夫妻，怕做甚么？(正旦唱)谁教你闷向秦楼列管弦？(带云)刘员外，(唱)休信我，醉中言，说则说在前。", "(云)天那！怎生教我陪伴这样人也！(唱)。"]'),
('yuanqu-621','江州司马青衫泪・叨叨令','马致远','元','元曲','yuanqu','','[]','我这两日上西楼，盼望三十遍；空存得故人书，不见离人面。',91,'元曲/yuanqu.json','["我这两日上西楼，盼望三十遍；空存得故人书，不见离人面。", "听的行雁来也，我立尽吹箫院；闻得声马嘶也，目断垂杨线。", "相公呵，你原来死了也么哥？你原来死了也么哥？从今后越思量越想的冤魂儿现！。"]'),
('yuanqu-622','江州司马青衫泪・倘秀才','马致远','元','元曲','yuanqu','','[]','侍郎呵，你往常出入在皇宫内院，只合生死在京师帝辇，也落得个金水河边好墓田。',64,'元曲/yuanqu.json','["侍郎呵，你往常出入在皇宫内院，只合生死在京师帝辇，也落得个金水河边好墓田。", "(带云)刘员外，(唱)你且离了我跟前，他从来有些腼腆。"]'),
('yuanqu-623','江州司马青衫泪・滚绣球','马致远','元','元曲','yuanqu','','[]','你文章胜贾浪仙，诗篇压孟浩然。',113,'元曲/yuanqu.json','["你文章胜贾浪仙，诗篇压孟浩然。", "不能够侍君王在九间朝殿，怎想他短卒律命似颜渊。", "今日扑通的瓶坠井，支楞的琴断弦，怎能够眼前面死魂活现？你若有灵圣，显形影向月下星前。", "则这半提淡水招魂纸，侍郎也，当得你一盏阴司买酒钱。", "止不住雨泪涟涟。"]'),
('yuanqu-624','江州司马青衫泪・醉太平','马致远','元','元曲','yuanqu','','[]','烧一陌纸儿钱，叙几句儿衷言。',115,'元曲/yuanqu.json','["烧一陌纸儿钱，叙几句儿衷言。", "待不啼哭，夫乃妇之天，抛闪杀我也少年！只见一个来来往往旋风足律即留转，吓的我慌慌张张手脚滴羞笃速战。", "一个俏魂灵不离了我打盘旋，我做人的解元。", "(净云)大姐，纸也烧了，夫妇之情也尽了，请上船罢。", "(正旦唱)。"]'),
('yuanqu-625','江州司马青衫泪・一煞','马致远','元','元曲','yuanqu','','[]','兴奴也，你早则不满梳绀发挑灯剪，一炷心香对月燃。',108,'元曲/yuanqu.json','["兴奴也，你早则不满梳绀发挑灯剪，一炷心香对月燃。", "我心下情绝，上船恩断；怎舍他临去时舌奸，至死也心坚。", "到如今鹤归华表，人老长沙，海变桑田。", "别无些挂恋，须索何红蓼岸绿杨川。", "(净云)大姐去罢。", "这等哭，哭到几时？(正旦唱)。"]'),
('yuanqu-626','江州司马青衫泪・二煞','马致远','元','元曲','yuanqu','','[]','少不的听那惊回客梦黄昏犬，聒碎人心落日蝉。',103,'元曲/yuanqu.json','["少不的听那惊回客梦黄昏犬，聒碎人心落日蝉。", "止不过临万顷苍波，落几双白鹭；对千里青山，闻两岸啼猿。", "愁的是三秋雁字，一夏蚊雷，二月芦烟。", "不见他青灯黄卷，却索共渔火对愁眠。", "(卜儿云)员外等久了，云罢。", "(正旦唱)。"]'),
('yuanqu-627','江州司马青衫泪・四煞','马致远','元','元曲','yuanqu','','[]','怎想他能捱磨扇似风车转，更合着梦见槐花要黄袄儿穿。',91,'元曲/yuanqu.json','["怎想他能捱磨扇似风车转，更合着梦见槐花要黄袄儿穿。", "我虚度三旬，是这婆娘亲女；受用了十年，是这赵妈妈金莲。", "我也曾有厅上待客，后阁内留宾，只不曾坐车上当辕。", "偌来大穷坑火院，只央我一身填。"]'),
('yuanqu-628','江州司马青衫泪・双调/新水令','马致远','元','元曲','yuanqu','','[]','正夕阳天阔暮江迷，倚晴空楚山叠翠。',42,'元曲/yuanqu.json','["正夕阳天阔暮江迷，倚晴空楚山叠翠。", "冰壶天上下，云锦树高低。", "谁倩王维，写愁入画图内？。"]'),
('yuanqu-629','江州司马青衫泪・驻马听','马致远','元','元曲','yuanqu','','[]','常教他尽醉方归，是他拂茶客青山沽酒旗；伴着我死心搭地，是兀那隐离人望眼钓鱼矶。',92,'元曲/yuanqu.json','["常教他尽醉方归，是他拂茶客青山沽酒旗；伴着我死心搭地，是兀那隐离人望眼钓鱼矶。", "(带云)这江那里是江，(唱)则是递流花草武陵溪，幽囚风月蓝桥驿。", "直恁的天阔雁来稀，莫不是衡阳移在江州北？。"]'),
('yuanqu-630','江州司马青衫泪・步步娇','马致远','元','元曲','yuanqu','','[]','这个四幅罗衾初做起，本待招一个内流婿，怎知道如今命运低。',103,'元曲/yuanqu.json','["这个四幅罗衾初做起，本待招一个内流婿，怎知道如今命运低。", "长独自托冰鉴两头偎，恁的般受孤忄西，知他是谁唤你做鸳鸯被？(云)本待睡儿，怎生睡得着？梅香，将那琵琶过来，对此明月，写我愁怀咱。", "(做抱琵琶科)(唱)。"]'),
('yuanqu-631','江州司马青衫泪・搅筝琵','马致远','元','元曲','yuanqu','','[]','都是你个琵琶罪，少欢乐足别离。',74,'元曲/yuanqu.json','["都是你个琵琶罪，少欢乐足别离。", "为你引商妇到江南，送昭君出塞北。", "紫檀面拂金猊，越引的我伤悲。", "想故人何日回归，生被这四条弦拨俺在两下里，到不如清夜闻笛。"]'),
('yuanqu-632','江州司马青衫泪・雁儿落','马致远','元','元曲','yuanqu','','[]','我则道是听琴钟子期，错猜作待月张君瑞；又不是归湖的越范蠡，却原来是遭贬的白居易！。',41,'元曲/yuanqu.json','["我则道是听琴钟子期，错猜作待月张君瑞；又不是归湖的越范蠡，却原来是遭贬的白居易！。"]'),
('yuanqu-633','江州司马青衫泪・小将军','马致远','元','元曲','yuanqu','','[]','肯分的月色如白日，他不说，我的知道是鬼！相公呵，怕你要做好事，兴奴尽依得；你则休渐渐来跟底。',46,'元曲/yuanqu.json','["肯分的月色如白日，他不说，我的知道是鬼！相公呵，怕你要做好事，兴奴尽依得；你则休渐渐来跟底。"]'),
('yuanqu-634','江州司马青衫泪・沉醉东风','马致远','元','元曲','yuanqu','','[]','我观觑了衣服样势，审察了言语高低。',91,'元曲/yuanqu.json','["我观觑了衣服样势，审察了言语高低。", "你且自靠那边，俺须有生人气。", "远些儿个好生商议。", "（做取钱投水科）(白乐天云)你丢钱怎的？(正旦唱)我为甚将几陌黄钱漾在水里？便死呵，也博个团圆到底！。"]'),
('yuanqu-635','江州司马青衫泪・挂搭沽','马致远','元','元曲','yuanqu','','[]','恰打算别离苦况味，见小玉言端的，又惊散鸳鸯两处飞。',53,'元曲/yuanqu.json','["恰打算别离苦况味，见小玉言端的，又惊散鸳鸯两处飞。", "咱须索权回避。", "我这里淹粉泪，怀愁戚，忙蹙金莲，紧荡罗衣。"]'),
('yuanqu-636','江州司马青衫泪・七兄弟','马致远','元','元曲','yuanqu','','[]','从早至晚夕，知他在那里，咱是甚夫妻？撇得我孤另另难存济。',46,'元曲/yuanqu.json','["从早至晚夕，知他在那里，咱是甚夫妻？撇得我孤另另难存济。", "我凄凄楚楚告他谁，你朝朝日日醺醺地。"]'),
('yuanqu-637','江州司马青衫泪・收江南','马致远','元','元曲','yuanqu','','[]','我教他满船空载月明归，三更难拨棹歌齐。',47,'元曲/yuanqu.json','["我教他满船空载月明归，三更难拨棹歌齐。", "我把这画船权作望夫石，便去波莫迟，却不道五湖西子嫁鸱夷。"]'),
('yuanqu-638','江州司马青衫泪・水仙子','马致远','元','元曲','yuanqu','','[]','再不见洞庭秋月浸玻璃，再不见鸦噪渔村落照低；再不听晚钟烟寺催鸥起，再不愁平沙落雁悲；再不怕江天暮雪霏霏，再不爱山市晴岚翠；再不被潇湘暮雨催，再不盼远浦帆归。',78,'元曲/yuanqu.json','["再不见洞庭秋月浸玻璃，再不见鸦噪渔村落照低；再不听晚钟烟寺催鸥起，再不愁平沙落雁悲；再不怕江天暮雪霏霏，再不爱山市晴岚翠；再不被潇湘暮雨催，再不盼远浦帆归。"]'),
('yuanqu-639','江州司马青衫泪・太清歌','马致远','元','元曲','yuanqu','','[]','莫不是片帆饱得西风力，怎能够谢安携出东山坡？此行不为鲈鱼脍，成就了佳期，无个外人知。',77,'元曲/yuanqu.json','["莫不是片帆饱得西风力，怎能够谢安携出东山坡？此行不为鲈鱼脍，成就了佳期，无个外人知。", "那厮正茶船上和衣睡，黑娄娄地鼻息如雷。", "比及杨柳岸风唤起，人已过画桥西。"]'),
('yuanqu-640','江州司马青衫泪・二煞','马致远','元','元曲','yuanqu','','[]','咱两个离愁虽似茶烟湿，归心更比江流急。',66,'元曲/yuanqu.json','["咱两个离愁虽似茶烟湿，归心更比江流急。", "离江州谢天地，出烟波渔父国，遮莫他耳听春雷，茶吐枪旗。", "着那厮正赶到五岭三湘建溪，干相思九公里。"]'),
('yuanqu-641','江州司马青衫泪・鸳鸯煞','马致远','元','元曲','yuanqu','','[]','若不是浮梁茶客十分醉，怎奈何江州司马千行泪？早则你低首无言，仰面悲啼；畅道情血痕多，青衫泪湿。',77,'元曲/yuanqu.json','["若不是浮梁茶客十分醉，怎奈何江州司马千行泪？早则你低首无言，仰面悲啼；畅道情血痕多，青衫泪湿。", "不因这一曲琵琶成佳配，泪似把推，险添满浔阳半江水。", "(同下)。"]'),
('yuanqu-642','江州司马青衫泪・中吕/粉蝶儿','马致远','元','元曲','yuanqu','','[]','秋月春花，都出在侍郎门下。',76,'元曲/yuanqu.json','["秋月春花，都出在侍郎门下。", "比及我博的个富贵荣华，恰便似盼辰勾，逢大赦，得重回改嫁。", "今日里圣旨宣咱，吉和凶索问天买卦。", "(云)来到这朝门，好怕人也。", "(唱)。"]'),
('yuanqu-643','江州司马青衫泪・醉春风','马致远','元','元曲','yuanqu','','[]','又不比顺子弟意前行，就郎君心上打。',56,'元曲/yuanqu.json','["又不比顺子弟意前行，就郎君心上打。", "只见两行武士列金瓜，这里敢不是耍、耍。", "他教我与樊素齐肩，受小蛮节制，圣机难察。"]'),
('yuanqu-644','江州司马青衫泪・迎仙客','马致远','元','元曲','yuanqu','','[]','无礼法，妇人家，山呼委实不会他。',46,'元曲/yuanqu.json','["无礼法，妇人家，山呼委实不会他。", "只办得紧低头，忙跪下，愿陛下海量宽纳，听臣妾说一套儿伤心话。"]'),
('yuanqu-645','江州司马青衫泪・幺篇','马致远','元','元曲','yuanqu','','[]','从此日娘嗔女，妾爱他。',55,'元曲/yuanqu.json','["从此日娘嗔女，妾爱他。", "爱他那走笔题诗，出口成章，顶针续麻。", "是他百般地，奶奶行、过从不下，怎当那獠姨夫物抬高价。"]'),
('yuanqu-646','江州司马青衫泪・红芍药','马致远','元','元曲','yuanqu','','[]','那厮每贩的是紫草红花，蜜蜡香茶。',66,'元曲/yuanqu.json','["那厮每贩的是紫草红花，蜜蜡香茶。", "宜舞东风斗虾蟆，巾帻是青纱。", "听不得蛮声气死势煞，无过在客船上随波上下。", "那厮分不的两部鸣蛙，所事村沙。"]'),
('yuanqu-647','江州司马青衫泪・红绣鞋','马致远','元','元曲','yuanqu','','[]','他有数百块名高月峡，两三船玉屑金芽。',118,'元曲/yuanqu.json','["他有数百块名高月峡，两三船玉屑金芽。", "原来他准备下一场说谎天来大。", "本待要绿珠辞卫尉，则说道贾谊没长沙，可不这寄哀书的该万剐！(云)老虔婆与茶客设计，寄假书一封，说侍郎死了，使妾无倚，逼令嫁与茶客。", "(驾云)既有假书，你如何主张？(正旦唱)。"]'),
('yuanqu-648','江州司马青衫泪・喜春来','马致远','元','元曲','yuanqu','','[]','既道是江州亡化白司马，因此上飞入寻常百姓家。',54,'元曲/yuanqu.json','["既道是江州亡化白司马，因此上飞入寻常百姓家。", "俺那爱钱娘一日坐八番衙，不由妾不随顺他，有分看些个驼腰柳钓鱼槎。"]'),
('yuanqu-649','江州司马青衫泪・普天乐','马致远','元','元曲','yuanqu','','[]','到浔阳，无牵挂。',98,'元曲/yuanqu.json','["到浔阳，无牵挂。", "吊英魂何处，渡口残霞。", "思往事，空嗟呀。", "半夜灯前长吁罢，泪和愁付与琵琶。", "寒波漾漾，芳心脉脉，明月芦花。", "(驾云)原来你弹琵琶来？那白居易可在那里听见，得与你相会？你再说咱。", "(正旦唱)。"]'),
('yuanqu-650','江州司马青衫泪・快活三','马致远','元','元曲','yuanqu','','[]','俺本待兰舟看月华，见渔灯映蒹葭。',96,'元曲/yuanqu.json','["俺本待兰舟看月华，见渔灯映蒹葭。", "他便似莽张骞天上泛浮槎，可原来不曾到黄泉下。", "(云)那一夜茶客不在，妾身对月理琵琶。", "忽见别船上二客，细视之，乃是白侍郎。", "方知他不曾死，妾身就跟白侍郎来了。", "(唱)。"]'),
('yuanqu-651','江州司马青衫泪・鲍老儿','马致远','元','元曲','yuanqu','','[]','秀才每，八怪洞里妖精也觑上了他，那一个不色胆天来大？投到俺啼哭出烟村四五家，央及杀青衫袖香罗帕。',80,'元曲/yuanqu.json','["秀才每，八怪洞里妖精也觑上了他，那一个不色胆天来大？投到俺啼哭出烟村四五家，央及杀青衫袖香罗帕。", "故人见后，浔阳怕甚水地湫凹；今日个君王召也，长安避甚，道路兜搭。"]'),
('yuanqu-652','江州司马青衫泪・叫声','马致远','元','元曲','yuanqu','','[]','这都是一般儿的执象简戴乌纱，好着我眼花、眼花。',71,'元曲/yuanqu.json','["这都是一般儿的执象简戴乌纱，好着我眼花、眼花。", "只得偷睛抹，去向那文武班中试寻咱。", "(做见三人科，云)这是贾学士，这是孟学士，这是白侍郎。", "(唱)。"]'),
('yuanqu-653','江州司马青衫泪・剔银灯','马致远','元','元曲','yuanqu','','[]','旧主顾先生好么？新女婿郎君煞惊吓，那翰林学士行无多话。',57,'元曲/yuanqu.json','["旧主顾先生好么？新女婿郎君煞惊吓，那翰林学士行无多话。", "则这白侍郎正是我生死的冤家从头认，都不差，可怎行装聋作哑？。"]'),
('yuanqu-654','江州司马青衫泪・蔓菁菜','马致远','元','元曲','yuanqu','','[]','他怎敢面欺着当今驾？他当日为寻春色到儿家，便待强风情下榻。',54,'元曲/yuanqu.json','["他怎敢面欺着当今驾？他当日为寻春色到儿家，便待强风情下榻。", "俺只道他是个诗措大、酒游花，却原来也会治国平天下。"]'),
('yuanqu-655','江州司马青衫泪・随煞','马致远','元','元曲','yuanqu','','[]','恰才来万里天涯，早愁鬓萧萧生白发。',39,'元曲/yuanqu.json','["恰才来万里天涯，早愁鬓萧萧生白发。", "俺把那少年心撇罢，再不去趁春风攀折凤城花！。"]'),
('yuanqu-656','诸宫调风月紫云庭・幺','石君宝','元','元曲','yuanqu','','[]','西出阳关无故人，则见俺在这南国梁园依旧亲。',61,'元曲/yuanqu.json','["西出阳关无故人，则见俺在这南国梁园依旧亲。", "舍人呵，谁不知俺娘劣，恁爷狠？伯伯，两阵狂风是紧，也不到得教吹散楚城云。", "(下)。"]'),
('yuanqu-657','诸宫调风月紫云庭・仙吕/点绛唇','石君宝','元','元曲','yuanqu','','[]','怎想俺这月馆风亭，竹溪花径，变得这般嘿光景。',41,'元曲/yuanqu.json','["怎想俺这月馆风亭，竹溪花径，变得这般嘿光景。", "我每日撇嵌为生，俺娘向诸宫调里寻争竞。"]'),
('yuanqu-658','诸宫调风月紫云庭・油葫芦','石君宝','元','元曲','yuanqu','','[]','我但有些卧枕着床脑袋疼，他委实却也心内惊，他急荒的清医人诊了脉却笑容生，他道是喜的女孩儿感得些风寒症，惭愧呵谢天地不是相思病。',119,'元曲/yuanqu.json','["我但有些卧枕着床脑袋疼，他委实却也心内惊，他急荒的清医人诊了脉却笑容生，他道是喜的女孩儿感得些风寒症，惭愧呵谢天地不是相思病。", "(带云)你教俺尽世儿厮守着，娘呵，(唱)你这般毒害心，狠劣情。", "但见对锦鸳鸯他水上才交颈，你早则着棒打过蓼花汀！。"]'),
('yuanqu-659','诸宫调风月紫云庭・天下乐','石君宝','元','元曲','yuanqu','','[]','呵！你肯教双宿双飞过一生，便则我子弟每行依平。',67,'元曲/yuanqu.json','["呵！你肯教双宿双飞过一生，便则我子弟每行依平。", "休有情，教我打迭起那暖和出落着冷。", "满脸儿半指霜，通身儿一块冰。", "娘呵，我一处也画堂春自生。"]'),
('yuanqu-660','诸宫调风月紫云庭・醉中天','石君宝','元','元曲','yuanqu','','[]','我唱道那双渐临川令，他便脑袋不嫌听，提起那冯员外，便望空里助采声。',95,'元曲/yuanqu.json','["我唱道那双渐临川令，他便脑袋不嫌听，提起那冯员外，便望空里助采声。", "把个苏妈妈便是上古贤人般敬。", "我正唱到不肯上贩茶船的小卿，向那岸边厢刁蹬，(带云)俺这虔婆道，(唱)兀得不好拷末娘七代先灵！。"]'),
('yuanqu-661','诸宫调风月紫云庭・醉扶归','石君宝','元','元曲','yuanqu','','[]','这逗镘的是咱些权柄，呵，色就事便是你得人情。',98,'元曲/yuanqu.json','["这逗镘的是咱些权柄，呵，色就事便是你得人情。", "那厮每拿着二分钞便害疼。", "(带云)害疼，咱每就呵便二十锭三十锭呵，(唱)更磕着如今等。", "乾咽唾相思的后生，那个不害这般干使钞干嘿病？(正末云住)(正旦唱)。"]'),
('yuanqu-662','诸宫调风月紫云庭・金盏儿','石君宝','元','元曲','yuanqu','','[]','上俺门来的酒客每为我这妙唱若雏莺，引的他每豪饮似长鲸。',95,'元曲/yuanqu.json','["上俺门来的酒客每为我这妙唱若雏莺，引的他每豪饮似长鲸。", "我委实为甚停杯听曲教快成病，我安排桃花扇影，他每便破香枨。", "尚自着瓦磁为巨器，也则是陶泻庆新声。", "嗷！若还更酒斟金潋滟。", "大的好歌立玉娉婷！。"]'),
('yuanqu-663','诸宫调风月紫云庭・后庭花','石君宝','元','元曲','yuanqu','','[]','俺这老婆，肚皮里将六韬三略盛，面皮上把四时八节擎。',74,'元曲/yuanqu.json','["俺这老婆，肚皮里将六韬三略盛，面皮上把四时八节擎。", "未见钱罗，呀，冬雪严霜降；得了钞罗，春风和气生。", "俺这个狠精灵，他那生时节决定，犯着甚爱钱巴镘的星。"]'),
('yuanqu-664','诸宫调风月紫云庭・幺','石君宝','元','元曲','yuanqu','','[]','也难奈何俺那六臂那吒般狠柳青，我唱的那七国里庞涓也没这短命，则是个八怪洞里爱钱精。',61,'元曲/yuanqu.json','["也难奈何俺那六臂那吒般狠柳青，我唱的那七国里庞涓也没这短命，则是个八怪洞里爱钱精。", "我若还更九番家厮并，他比的十恶罪尚尤轻。"]'),
('yuanqu-665','诸宫调风月紫云庭・赚尾','石君宝','元','元曲','yuanqu','','[]','郎君每我行有十遍雨云期，除是害九伯风魔病。',124,'元曲/yuanqu.json','["郎君每我行有十遍雨云期，除是害九伯风魔病。", "俺家里八下里窝弓陷坑，你便有七步才无钱也不许行，六艺全便休卖聪明。", "哎！为甚恁这五陵人，把俺这等嘿交易难成？你便是四付马上驼来也索两平。", "俺这里别是个三街市井，另置下二连等秤，恰好的教恁一分银买一分情！(下)。"]'),
('yuanqu-666','诸宫调风月紫云庭・南吕/一枝花','石君宝','元','元曲','yuanqu','','[]','(残缺)。',5,'元曲/yuanqu.json','["(残缺)。"]'),
('yuanqu-667','诸宫调风月紫云庭・梁州第七','石君宝','元','元曲','yuanqu','','[]','(残缺)。',5,'元曲/yuanqu.json','["(残缺)。"]'),
('yuanqu-668','诸宫调风月紫云庭・感皇恩','石君宝','元','元曲','yuanqu','','[]','□□□□，□□□□。',59,'元曲/yuanqu.json','["□□□□，□□□□。", "□□□，□□□。", "只教我立化做一块望夫石。", "我便似病人冲太岁，他管也小鬼见钟馗腌材料，风短命，欠东西。"]'),
('yuanqu-669','诸宫调风月紫云庭・隔尾','石君宝','元','元曲','yuanqu','','[]','嗨，比俺娘那熬煎增十倍，恰才这些崎险艰难好做一回。',72,'元曲/yuanqu.json','["嗨，比俺娘那熬煎增十倍，恰才这些崎险艰难好做一回。", "哎，不做美的恩官干坏了他把戏。", "哎，唱话的小一，则好打恁兀那把门的老嘿，切不可放过这没钱雁看的。"]'),
('yuanqu-670','诸宫调风月紫云庭・红芍药','石君宝','元','元曲','yuanqu','','[]','兀的那般恶缘恶业镇相随，好教人难摘难离。',98,'元曲/yuanqu.json','["兀的那般恶缘恶业镇相随，好教人难摘难离。", "也是某年某月不曾离，无事无非。", "奶奶，你是老人家，(唱)须知些道理，有的事便捱不到家里？(卜儿云，住)(正旦唱)越道着越查声破嗓越骂得精细，前面他老相公听的。"]'),
('yuanqu-671','诸宫调风月紫云庭・二煞','石君宝','元','元曲','yuanqu','','[]','当日那梁公曾施行虎豹是真锋利，哎！包龙图呵，你这般拆散鸳鸯算甚正直？我也觑不得这光景掩不迭这泪。',100,'元曲/yuanqu.json','["当日那梁公曾施行虎豹是真锋利，哎！包龙图呵，你这般拆散鸳鸯算甚正直？我也觑不得这光景掩不迭这泪。", "我这壁道防送早催逼，他那壁带铁锁囚人监系，俺两处各心碎！是有遭间阻的也不似俺不吉利，兀的是甚末娘别离！。"]'),
('yuanqu-672','诸宫调风月紫云庭・收尾','石君宝','元','元曲','yuanqu','','[]','几曾见递流南浦人千里，怎饮这，配役阳关酒一杯！到如今说甚的，比别的记相识，你情知我心意，你知咱我知你。',150,'元曲/yuanqu.json','["几曾见递流南浦人千里，怎饮这，配役阳关酒一杯！到如今说甚的，比别的记相识，你情知我心意，你知咱我知你。", "歹处无好处记，休想我再出入。", "我寸肠中似刀刺，恁尊居。", "忒情理，合舍了怕甚的！哎，莲子花官人愿的你一千岁。", "嗨！怎直恁般下得？(卜儿云了)(正旦唱)咭！则是你了得，吡！都是你个吸人髓虔婆直攘到底！(下)。"]'),
('yuanqu-673','诸宫调风月紫云庭・中吕/粉蝶儿','石君宝','元','元曲','yuanqu','','[]','我本是个邪祟妖魔，他那俏魂灵倒将咱着末。',66,'元曲/yuanqu.json','["我本是个邪祟妖魔，他那俏魂灵倒将咱着末。", "呵，大冈来意气相合，今日把我情肠，他肺腑都混成一个。", "虽隔着千里关河，不曾有半个时辰意中捱过。"]'),
('yuanqu-674','诸宫调风月紫云庭・醉春风','石君宝','元','元曲','yuanqu','','[]','人害兀那魔病有时潜，则这相思无处躲。',74,'元曲/yuanqu.json','["人害兀那魔病有时潜，则这相思无处躲。", "直到再团圆被儿里得些温存，恁地后便可、可。", "我想世上这一点情缘，百般缠缴，有几人识破？(卜儿云，外住)(正旦唱)。"]'),
('yuanqu-675','诸宫调风月紫云庭・迎仙客','石君宝','元','元曲','yuanqu','','[]','姨姨，我为甚罢了雨云？却也是避些风波。',71,'元曲/yuanqu.json','["姨姨，我为甚罢了雨云？却也是避些风波。", "做这些淡生涯，且熬那穷过活。", "这些时调不上勤儿，却则是忙着俺老婆。", "都则为我不肯张罗，以此上闲放着盘千斤磨。"]'),
('yuanqu-676','诸宫调风月紫云庭・红绣鞋','石君宝','元','元曲','yuanqu','','[]','我则想别后云行地末，呵，叹人生会少离多。',73,'元曲/yuanqu.json','["我则想别后云行地末，呵，叹人生会少离多。", "(卜儿云，住)(正旦唱)呵，兀的是俺那心爱的庞儿旧哥哥。", "自从这人北渡，浑一似梦南柯。", "伯伯，间别来安乐末？。"]'),
('yuanqu-677','诸宫调风月紫云庭・石榴花','石君宝','元','元曲','yuanqu','','[]','常记得玉鞭骄马宴鸣珂，长安市少年他，似那邻舟一听惜蹉跎。',101,'元曲/yuanqu.json','["常记得玉鞭骄马宴鸣珂，长安市少年他，似那邻舟一听惜蹉跎。", "听一曲艳歌，细卷红罗。", "呵！我今日守空房也堕下千金货。", "(外末云)(正旦唱)却则是央及杀那象板银锣。", "况兼俺正厅儿虽是则些娘大，坐着俺那爱钞的的劣虔婆。"]'),
('yuanqu-678','诸宫调风月紫云庭・斗鹌鹑','石君宝','元','元曲','yuanqu','','[]','纵有些燕友莺朋，似望着龙楼凤阁。',100,'元曲/yuanqu.json','["纵有些燕友莺朋，似望着龙楼凤阁。", "(外末云)(正旦唱)咱若是驮汉呵由他，提着那觅钱后在我。", "(外末云了)(正旦唱)俺那老婆沙，直见阎王也没奈何。", "伯伯，你试想波，若是共别人并枕同床，他便不送得我披枷带锁！。"]'),
('yuanqu-679','诸宫调风月紫云庭・幺篇','石君宝','元','元曲','yuanqu','','[]','你道你少甚的，不剌，你却是召甚末？俺这外路打扮，其实没这异锦轻罗。',72,'元曲/yuanqu.json','["你道你少甚的，不剌，你却是召甚末？俺这外路打扮，其实没这异锦轻罗。", "(正末云住)(正旦唱)你若打死他，路上呵，你独自难过，却教谁牵你那虎皮驮驼？。"]'),
('yuanqu-680','诸宫调风月紫云庭・快活三','石君宝','元','元曲','yuanqu','','[]','无明火怎收撮，掴打会看如何？则教我烘地了半晌口难合，不觉我这身起是多来大。',37,'元曲/yuanqu.json','["无明火怎收撮，掴打会看如何？则教我烘地了半晌口难合，不觉我这身起是多来大。"]'),
('yuanqu-681','诸宫调风月紫云庭・哨遍','石君宝','元','元曲','yuanqu','','[]','送的人赤手空拳难过，都是俺舌尖上一点砂糖唾。',141,'元曲/yuanqu.json','["送的人赤手空拳难过，都是俺舌尖上一点砂糖唾。", "越精细的越着他，怎出俺这打多情地网天罗。", "且说俺这小哥哥，为俺耽惊受怕，波进流移，冷落了读书院，一就把功名懒堕。", "自尽教萱堂有梦并不想兰省登科。", "几时得两扶红日上青天，空望着一片白云隔黄河。", "则共我这般携手儿相将，举步儿同行，他想所事满心儿快活。"]'),
('yuanqu-682','诸宫调风月紫云庭・耍孩儿','石君宝','元','元曲','yuanqu','','[]','早是你不合将堂亡双亲躲，你却待改换你家门小可。',111,'元曲/yuanqu.json','["早是你不合将堂亡双亲躲，你却待改换你家门小可。", "这李亚仙苦劝你个郑元和，再休提那撒板鸣锣。", "若还俺娘知咱这暗私奔，到毒似那倒寨计，若还恁爷见你这诸宫调，更狠如那唱挽歌。", "你脖项上新开锁，俺娘难道那风云气少，恁爷却甚末儿女情多！。"]'),
('yuanqu-683','诸宫调风月紫云庭・三煞','石君宝','元','元曲','yuanqu','','[]','今后去了这驮汉子的小鬼头，看怎结末那吃勤儿的老业魔，再怎施展那个打鸳鸯抖擞的精神儿大。',86,'元曲/yuanqu.json','["今后去了这驮汉子的小鬼头，看怎结末那吃勤儿的老业魔，再怎施展那个打鸳鸯抖擞的精神儿大。", "则明日管舞旋旋空把个裙儿系，劳攘攘干将条柱杖儿拖。", "早则没着末，致仕了弟子，罢任波虔婆。"]'),
('yuanqu-684','诸宫调风月紫云庭・二煞','石君宝','元','元曲','yuanqu','','[]','这一件又得歇心，此一桩又得解脱，暂不见那官身祗候闲差拨。',75,'元曲/yuanqu.json','["这一件又得歇心，此一桩又得解脱，暂不见那官身祗候闲差拨。", "委实倦那月斜杨柳楼心舞，风软桃花扇底歌。", "欲将这把戏都参破，怎肯尽陶元阳真气，直变做了虚损沉疴。"]'),
('yuanqu-685','诸宫调风月紫云庭・收尾','石君宝','元','元曲','yuanqu','','[]','此行折末山村野店上藏，竹篱茅舍里躲。',47,'元曲/yuanqu.json','["此行折末山村野店上藏，竹篱茅舍里躲。", "能够得个桑榆景内安闲的过，也强如锣板声中断送了我。", "(下)。"]'),
('yuanqu-686','诸宫调风月紫云庭・双调/新水令','石君宝','元','元曲','yuanqu','','[]','当日个为多情一曲〔满庭芳〕，曾贬得苏东坡也趁波也趁波逐浪。',65,'元曲/yuanqu.json','["当日个为多情一曲〔满庭芳〕，曾贬得苏东坡也趁波也趁波逐浪。", "何况这莺花燕市客，更逢着云雨楚山娘。", "我凭那想像高唐，怎强如俺满意宿鸳鸯。"]'),
('yuanqu-687','诸宫调风月紫云庭・驻马听','石君宝','元','元曲','yuanqu','','[]','他为我堕落文章，生缠得携手同行不断肠。',80,'元曲/yuanqu.json','["他为我堕落文章，生缠得携手同行不断肠。", "直这般学成说唱，更则便受恩深处便为乡。", "则为这情缘千尺藕丝长，误尽禹门三月桃花浪。", "我若是不正当，枉了他那呆心肠一向在咱心上。"]'),
('yuanqu-688','诸宫调风月紫云庭・落梅风','石君宝','元','元曲','yuanqu','','[]','我恰猛可地向这厅堂中见，唬得我又待寻幔幕中藏。',73,'元曲/yuanqu.json','["我恰猛可地向这厅堂中见，唬得我又待寻幔幕中藏。", "哎！狠阿公间别来无恙！(做意了)可知我恰轻敲着他那边厢越分外的响。", "相公呵，这的是那打香印使来的锣棒。"]'),
('yuanqu-689','诸宫调风月紫云庭・水仙子','石君宝','元','元曲','yuanqu','','[]','相公那日正暴雷急雨怒在书房，几曾这般和气春风满画堂？(孤云)(正旦唱)舍人也没那五陵豪气三千丈，脖项上连铁索两托长！却虽是妾烦恼欢喜杀家堂，路岐人生死心难忘。',95,'元曲/yuanqu.json','["相公那日正暴雷急雨怒在书房，几曾这般和气春风满画堂？(孤云)(正旦唱)舍人也没那五陵豪气三千丈，脖项上连铁索两托长！却虽是妾烦恼欢喜杀家堂，路岐人生死心难忘。", "谢相公赍发觑当，直把俺牒配还乡。"]'),
('yuanqu-690','诸宫调风月紫云庭・雁儿落','石君宝','元','元曲','yuanqu','','[]','相公把孩儿呵腹内想，越教妾小鹿儿心头撞，我如今引来这园圃中，莫不是赚到这筵席上？。',41,'元曲/yuanqu.json','["相公把孩儿呵腹内想，越教妾小鹿儿心头撞，我如今引来这园圃中，莫不是赚到这筵席上？。"]'),
('yuanqu-691','诸宫调风月紫云庭・得胜令','石君宝','元','元曲','yuanqu','','[]','却又休金殿锁鸳鸯，一似书帏中拆鸾凰。',64,'元曲/yuanqu.json','["却又休金殿锁鸳鸯，一似书帏中拆鸾凰。", "恁那秀才凭学艺，他却也男儿当自强。", "他如今难当，日写在招儿上。", "相公试参详，这的唤功名纸半张！。"]'),
('yuanqu-692','诸宫调风月紫云庭・川拨棹','石君宝','元','元曲','yuanqu','','[]','不索你自夸扬，我可也知道你打了个好散场。',51,'元曲/yuanqu.json','["不索你自夸扬，我可也知道你打了个好散场。", "休得行唐，火速疾忙，见咱个旧日个恩官使长，与咱多多的准备重赏。"]'),
('yuanqu-693','诸宫调风月紫云庭・七弟兄','石君宝','元','元曲','yuanqu','','[]','他也大冈，你行也有些情肠，你那起初时敷演时曾听你唱、转街衢行至短垣墙，入花园尽步苍苔上。',44,'元曲/yuanqu.json','["他也大冈，你行也有些情肠，你那起初时敷演时曾听你唱、转街衢行至短垣墙，入花园尽步苍苔上。"]'),
('yuanqu-694','诸宫调风月紫云庭・收江南','石君宝','元','元曲','yuanqu','','[]','口应！老官人分付取小学郎。',91,'元曲/yuanqu.json','["口应！老官人分付取小学郎。", "(孤云了)(正旦唱)则教你住构栏，不教你坐监房。", "(正末云住)(正旦唱)在相公厅当日个你分开这沙上宿鸳鸯，怎生般对当，却教俺芰荷香里再成双。", "(卜儿云)(下)。"]'),
('yuanqu-695','诸宫调风月紫云庭・鹧鸪天','石君宝','元','元曲','yuanqu','','[]','玉软香矫意更真，花攒柳衬是消魂。',96,'元曲/yuanqu.json','["玉软香矫意更真，花攒柳衬是消魂。", "半生碌碌忘丹桂，千里驱驱觅彩云。", "鸾鉴破，凤钗分，世间多少断肠人。", "风流公案风流传，一度搬着一度新。", "象板银锣可意娘，玉鞭娇马画眉郎。", "两情迷到忘形处，落絮随风上下狂。"]'),
('yuanqu-696','朱太守风雪渔樵记・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','十载攻书，半生埋没，学千禄。',32,'元曲/yuanqu.json','["十载攻书，半生埋没，学千禄。", "误杀我者也之乎，打熬成这一付穷皮骨。"]'),
('yuanqu-697','朱太守风雪渔樵记・油葫芦','无名氏','元','元曲','yuanqu','','[]','说甚么年少今开万卷余，每日家长叹吁，想他这阴阳造化果非诬。',89,'元曲/yuanqu.json','["说甚么年少今开万卷余，每日家长叹吁，想他这阴阳造化果非诬。", "常言道是小富由人做，咱人这大富总是天之数。", "我空学成七步才，谩长就六尺躯。", "人都道书中自有千钟粟，怎生来偏着我风雪混樵渔？。"]'),
('yuanqu-698','朱太守风雪渔樵记・天下乐','无名氏','元','元曲','yuanqu','','[]','我一会家时复挑灯来看古书，我可便踌也波躇，那官职有也无，一会家受饥寒便似活地狱。',579,'元曲/yuanqu.json','["我一会家时复挑灯来看古书，我可便踌也波躇，那官职有也无，一会家受饥寒便似活地狱。", "则俺这朱买臣，虽不做真宰辅，(云)我虽然不做官，却也和那做官的一般。", "(杨孝先云)哥哥，可怎生与做官的一般？(正末唱)俺可也伴着他播清名一万古。", "(杨孝先云)哥哥说的是。", "(正末云)那江岸边不是哥哥的渔船？待我叫他一声。", "(做叫科，云)哥哥。", "(王安道云)俺两个兄弟来了也，快上船来！(做上船科)(王安道云)你两个兄弟请坐，老汉沽下一壶儿新酒，等你来荡寒，咱就此处闲攀话咱。", "(杨孝先云)雪下的紧，着哥哥久等也。", "(王安道做递酒科，云)兄弟满饮一杯。", "(正末云)哥哥先请。", "(王安道云)兄弟请。", "(正末做饮酒科)(王安道再递酒科，云)孝先兄弟，满饮一杯。", "(孝先做饮科)(王安道云)兄弟，咱闲口论闲话。", "我想来这会稽城中有钱的财主每，不知他怎生受用，兄弟细说一遍。", "我试听咱。", "(正末云)哥哥，便好道风雪酒家天。", "据着哥哥说呵，也有那等受苦的人；据着你兄弟说呵，也有那等受用的人。", "(王安道云)兄弟也，可是那一等人受用？(正末云)哥哥且休题别处，则说会稽城中有那等仕户财主每，遇着那太热的时节，他也不受热；遇着那太冷的时节，他也不受冷。", "哥哥不信时，听你兄弟说一遍咱。", "(王安道云)兄弟，你道那财主每，他冬月间不受冷，夏月间不受热，你说的差了也。", "可不道冷呵大家冷，热呵大家热，偏他怎生受用？你说，你说！(正末唱)。"]'),
('yuanqu-699','朱太守风雪渔樵记・村里迓鼓','无名氏','元','元曲','yuanqu','','[]','他道下着的是国家祥瑞，(带云)哥哥，这雪呵，(唱)则是与那富家每添助，(王安道云)那富贵的人家，怎生般受用快活？(正末唱)他向那红垆的这暖阁，一壁厢添上兽炭，他',346,'元曲/yuanqu.json','["他道下着的是国家祥瑞，(带云)哥哥，这雪呵，(唱)则是与那富家每添助，(王安道云)那富贵的人家，怎生般受用快活？(正末唱)他向那红垆的这暖阁，一壁厢添上兽炭，他把那羊羔来浅注。", "(王安道云)红垆暖阁，兽炭银瓶，饮着羊羔美酒，遇着这等大雪，果然是好受用也。", "(正末云)哥哥，他一来可也会受用，第二来又遇着这般好景致。", "(唱)门外又雪飘飘，耳边厢风飒飒，把那毡帘来低簌，(王安道云)看这等凛冽寒天，低簌毡帘，羊羔美酒正饮中间，还有甚么人扶侍他？(正末唱)一壁厢有各刺刺象板敲，听波韵悠悠佳人唱，醉了后还只待笑吟吟酒美沽，(王安道云)兄弟，这一会儿雪大风紧越冷了也！(正末唱)哎，哥也，他每端的便怎知俺这渔樵每受苦？(王安道云)兄弟，我想来你学成满腹文章，受如此穷暴，几时是你那发达的时节也？(正末唱)。"]'),
('yuanqu-700','朱太守风雪渔樵记・元和令','无名氏','元','元曲','yuanqu','','[]','总饶你似马相如赋《子虚》，怎比的他石崇家夸金谷。',142,'元曲/yuanqu.json','["总饶你似马相如赋《子虚》，怎比的他石崇家夸金谷。", "(王安道云)那有钱的怎如你这有学的好也？(正末唱)岂不闻冰炭不同垆，也似咱贤愚不并居。", "(王安道云)兄弟，我见这会稽城市中的人，有穿着那宽衫大袖的乔文假醋，诗云子曰，可不知他读书也不曾？(正末唱)他则待人前卖弄些好妆梳，扮一个峨冠士大大。"]'),
('yuanqu-701','朱太守风雪渔樵记・上马娇','无名氏','元','元曲','yuanqu','','[]','那一等本下愚，假扮做儒，他动不动一刻地谎喳呼。',77,'元曲/yuanqu.json','["那一等本下愚，假扮做儒，他动不动一刻地谎喳呼。", "见人呵闲言长语三十句，(王安道云)怕不的他外相儿好看，只是那腹中文章须假不得。", "(正末唱)他虚道是腹隐九经书。"]'),
('yuanqu-702','朱太守风雪渔樵记・胜葫芦','无名氏','元','元曲','yuanqu','','[]','可正是天降人皮包草躯，(王安道云)他也曾看书么？(正末唱)学料嘴不读书。',193,'元曲/yuanqu.json','["可正是天降人皮包草躯，(王安道云)他也曾看书么？(正末唱)学料嘴不读书。", "他每都道见贤思齐是说着谬语。", "那里也温良恭俭？(王安道云)那礼节上便不省的，倘遇着人说起诗词歌赋来，怎生答应？(正末唱)那里也诗词歌赋？端的个半星无。", "(王安道云)兄弟，我今日也捕不的鱼，两个兄弟也打不的柴，咱各自还家去罢。", "孝先兄弟，你家中借一担柴，与你哥哥将的家去，争奈媳妇儿有些不贤慧，免得他又要吵闹。", "(正末唱)。"]'),
('yuanqu-703','朱太守风雪渔樵记・寄生草','无名氏','元','元曲','yuanqu','','[]','见哥哥把那鱼船缆，冻的我手怎舒？(王安道云)兄弟，好大雪也。',120,'元曲/yuanqu.json','["见哥哥把那鱼船缆，冻的我手怎舒？(王安道云)兄弟，好大雪也。", "(正末唱)正值着扬风搅雪可便难停住。", "你待要收纶罢钓还家去，哎，哥也！只怕你披蓑顶笠迷归路。", "似这等战钦钦有口不能言，(带云)看了哥哥和兄弟这个模样呵，(唱)还说甚这晚来江上堪图处？。"]'),
('yuanqu-704','朱太守风雪渔樵记・后庭花','无名氏','元','元曲','yuanqu','','[]','想当日傅说曾板筑，(孤云)传说板筑，殷高宗建为太宰。',324,'元曲/yuanqu.json','["想当日傅说曾板筑，(孤云)传说板筑，殷高宗建为太宰。", "还再有谁？(正末唱)更有那倪宽可便曾抱锄。", "(孤云)倪宽是我武帝时御史大夫，还再有谁？(正末唱)有一个宁戚曾歌牛角，(孤云)宁戚叩角而歌，齐桓公举为上卿。", "还再有谁？(正末唱)有一个韩侯他也曾去钓鱼。", "(孤云)韩侯就是那三齐王韩信，果然曾钓鱼来。", "可再有谁？(正末唱)有一个秦白起是军卒，(孤云)那白起是秦将，起于卒伍之中。", "再呢？(正末唱)有一个冻苏秦田无半亩。", "(孤云)苏秦后来并相六国，可怎么冻的他死？再呢？(正末唱)有一个公孙弘曾牧猪，(孤云)那公孙弘也是我汉朝的宰相，曾牧猪于东海。", "再呢？(正末唱)有一个灌将军曾贩屦。", "(孤云)那灌婴我只知他贩缯，却不知他贩屦。", "(正末唱)朱买臣一略数，请相公听拜覆。"]'),
('yuanqu-705','朱太守风雪渔樵记・青哥儿','无名氏','元','元曲','yuanqu','','[]','哎，我这里叮咛、叮咛分诉，这都是始贫、始贫终富。',114,'元曲/yuanqu.json','["哎，我这里叮咛、叮咛分诉，这都是始贫、始贫终富。", "(带云)且休说别的，则这一个古人，堪做小生比喻。", "(孤云)可是那个古人？(正末唱)则说那姜子牙，正与区区可比如。", "他也曾朝歌市里为屠，蟠溪水上为渔，直捱到满头霜雪八旬余，才得把文王遇。"]'),
('yuanqu-706','朱太守风雪渔樵记・赚煞','无名氏','元','元曲','yuanqu','','[]','一转眼选场开，发了愿来年去，直至那长安帝都，(孤云)据凭贤士锦绣文章，何所不至！(正末唱)凭着我锦绣也似文章敢应举。',349,'元曲/yuanqu.json','["一转眼选场开，发了愿来年去，直至那长安帝都，(孤云)据凭贤士锦绣文章，何所不至！(正末唱)凭着我锦绣也似文章敢应举。", "(孤云)明年去，也是迟了。", "(正末云)大人，你道为何，这几年不进取功名来？(孤云)这可是为何？(正末唱)也是我不得时可便韫椟藏诸，我若是的鳌鱼，怕不就压倒群儒？(孤云)贤士，你若去进取功名，岂在他人之下。", "(正末唱)我着普天下文人每，那一个不拱手的伏！(孤云)请贤士收拾琴剑书箱，来年应举去也。", "(正末云)大人，别的书生用那琴剑书箱，小生则用着身边一般儿物件，夺取皇家富贵。", "(孤云)贤士，可那一般儿物件？(正末唱)凭着这砍黄桑的巨斧，端的便上青霄独步，(云)别的书生说道月中丹桂，若到的那里，折得一枝回来，足可了一生之愿。", "不是我朱买臣敢说大言也，(唱)落可便我把那月中仙桂剖根除。", "(下)。"]'),
('yuanqu-707','朱太守风雪渔樵记・滚绣球','无名氏','元','元曲','yuanqu','','[]','头直上乱纷纷雪似筛，耳边厢飒刺刺风又摆，(带云)可端的便这场冷也呵，(唱)哎哟，勿、勿、勿！畅好是冷的来奇怪，(带云)天那、天那！(唱)也则是单注着这穷汉每月值',197,'元曲/yuanqu.json','["头直上乱纷纷雪似筛，耳边厢飒刺刺风又摆，(带云)可端的便这场冷也呵，(唱)哎哟，勿、勿、勿！畅好是冷的来奇怪，(带云)天那、天那！(唱)也则是单注着这穷汉每月值年灾。", "(带云)似这雪呵，(唱)则俺那樵夫每怎打柴？便有那渔翁也索罢了钓台，(带云)似这雪呵，(唱)则问那映雪的书生安在，便是冻苏秦也怎生去搠笔巡街？则他这一方市户有那千家闭，抵多少十谒朱门九不开，(带云)似这雪呵，(唱)教我委实难捱。"]'),
('yuanqu-708','朱太守风雪渔樵记・快活三','无名氏','元','元曲','yuanqu','','[]','你怎不学贾氏妻，只为射雉如皋笑靥开？(旦儿云)我有甚么欢喜在那里，你着我笑？(正末云)你不笑，敢要哭，我就说一个哭的。',148,'元曲/yuanqu.json','["你怎不学贾氏妻，只为射雉如皋笑靥开？(旦儿云)我有甚么欢喜在那里，你着我笑？(正末云)你不笑，敢要哭，我就说一个哭的。", "(唱)你怎不学孟姜女，把长城哭倒也则一声哀？(旦儿云)朱买臣，穷叫化头！我也没工夫听这闲话。", "将休书来，休书来！(正末唱)你则管哩便胡言乱浯将我厮花白，你那些个将我似举案齐眉待？。"]'),
('yuanqu-709','朱太守风雪渔樵记・醉太平','无名氏','元','元曲','yuanqu','','[]','卓文君你将那书桌儿便快抬，(旦儿云)你可似谁？(正末唱)马相如，我看你怎的把他去支划，(旦儿云)纸笔在此，快写了罢。',309,'元曲/yuanqu.json','["卓文君你将那书桌儿便快抬，(旦儿云)你可似谁？(正末唱)马相如，我看你怎的把他去支划，(旦儿云)纸笔在此，快写了罢。", "(正末唱)你、你、你，把文房四宝快安排。", "(云)刘家女，我写则写，只是一件，人都算我明年得官，我若得了官呵，把个夫人的名号与了别人，你不干受了二十年的辛苦！(旦儿云)我辛苦也受的勾了，委实的捱不过。", "是我问你要来，不干你事。", "(正末云)请波，请波。", "(唱)你也索回头儿自揣，(旦儿云)我揣个甚么？是我问你要休书来，不干你事。", "(正末唱)非是我朱买臣不把你糟糠待，赤紧的玉天仙忍下的心肠歹。", "(带云)罢、罢、罢。", "(唱)这梁山伯也不恋你祝英台，(云)任从改嫁，并不争论。", "左手一个手模。", "将去！(唱)我早则写与你个贱才！。"]'),
('yuanqu-710','朱太守风雪渔樵记・二煞','无名氏','元','元曲','yuanqu','','[]','那知道岁寒然后知松柏，你看我似粪土之墙朽木材。',90,'元曲/yuanqu.json','["那知道岁寒然后知松柏，你看我似粪土之墙朽木材。", "断然是捱不彻饥寒，禁不过气恼，怎知我守定心肠，留下形骸。", "但有日官居八座，位列三台，日转千阶。", "头直上打一轮皂盖，那其间谁敢道我负薪来？。"]'),
('yuanqu-711','朱太守风雪渔樵记・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','十载诗书晓夜习，(杨孝先云)哥哥此去，必然为官也。',122,'元曲/yuanqu.json','["十载诗书晓夜习，(杨孝先云)哥哥此去，必然为官也。", "(正末唱)一举成名天下知，(王安道云)兄弟，你哥哥专听喜信哩！(正末唱)你是必耳打听好消息。", "(做拜别科)(王安道云)兄弟，你小心在意者。", "(正末唱)休嘱付小心在意，我可敢包夺的一个锦衣归。", "(下)。"]'),
('yuanqu-712','朱太守风雪渔樵记・醉春风','无名氏','元','元曲','yuanqu','','[]','你看我抖搜着老精神，我与你便花白么娘那小贱人。',72,'元曲/yuanqu.json','["你看我抖搜着老精神，我与你便花白么娘那小贱人。", "想着你二十载夫妻怎下的索休离，这妮子你畅好是狠，狠。", "道不的个一夫一妇，一家一计，你可甚么一亲一近。"]'),
('yuanqu-713','朱太守风雪渔樵记・迎仙客','无名氏','元','元曲','yuanqu','','[]','我则见那公吏一字儿摆，那父老每两边分。',389,'元曲/yuanqu.json','["我则见那公吏一字儿摆，那父老每两边分。", "(云)无一时则见那西门骨刺刺的开了，我则见那骨朵衙仗，水罐银盆，茶褐罗伞，那五明马上坐着的呵，(刘二公云)可是谁那？(张云)我买卖忙，不曾看，我忘了也。", "(刘二公云)我央及你波，那做官的可是谁？(张云)等我想，哦，我想起来了也。", "(唱)是你那前年索了休离的唤做朱买臣！(刘二公云)惭愧，俺家女婿做了官也！(张云)老弟子孩儿！你道不要便宜，去年时节不说是你家女婿，今日得了官，便说是你家女婿，一个好相公也！(唱)他可不托大不嫌贫，(云)他不看见我，万事都休；一投得见了我，便认的俺是本村里张伯伯，连忙滚鞍下马，按我在那银交椅上，纳头的拜了两拜。", "(唱)他先下拜险些儿可便惊杀那众人。", "施礼罢复叙寒温，(云)那相公问道：王安道哥哥好么？杨孝先兄弟好么？那四村上下、姑姑姨姨、婶子伯娘、兄弟妹子，都好么？我道：都好，都好。", "(唱)他把那旧伴等可便从头儿问。"]'),
('yuanqu-714','朱太守风雪渔樵记・喜春儿','无名氏','元','元曲','yuanqu','','[]','刚只是半星儿道着呵，(张做嘴脸科)(旦儿云)老的，你怎么做这嘴脸？(张唱)他把你十分恨，(旦儿云)他恨我些甚么那？(张唱)他无非想着你一夜夫妻有那百夜恩。',156,'元曲/yuanqu.json','["刚只是半星儿道着呵，(张做嘴脸科)(旦儿云)老的，你怎么做这嘴脸？(张唱)他把你十分恨，(旦儿云)他恨我些甚么那？(张唱)他无非想着你一夜夫妻有那百夜恩。", "(旦儿云)他还说甚么？(张唱)他道汉相如伸意你个卓文君，(旦儿云)伸个甚的意思？(张云)他道你把车驾的稳，(旦儿云)他敢是要来取我么？(张唱)没着便嫁他人？。"]'),
('yuanqu-715','朱太守风雪渔樵记・上小楼','无名氏','元','元曲','yuanqu','','[]','你道他忘人大恩，又道他记人小恨。',153,'元曲/yuanqu.json','["你道他忘人大恩，又道他记人小恨。", "谁着你生勒开他，生则同衾，死则同坟。", "(旦儿云)他每日家偎妻靠妇，四十九岁，全不把功名为念。", "我生逼的他求官去，我是歹意来？(张唱)你道他过四旬，还不肯把那功名求进，(云)老的也，你记的俺庄东头王学究说的那一句书儿么？(刘二公云)是那一句书？(张唱)他则是个君子，可便固守本分。"]'),
('yuanqu-716','朱太守风雪渔樵记・幺篇','无名氏','元','元曲','yuanqu','','[]','那妮子强勒他休，这老子又绝了他亲。',225,'元曲/yuanqu.json','["那妮子强勒他休，这老子又绝了他亲。", "眼见的身上无衣，肚里无食，(带云)大雪里赶出他来，(唱)可着他便进退无门。", "(刘二公云)我孩儿又不曾别嫁了人，是斗他耍，怎么这等认真，就说嘴说舌，背槽抛粪？(张唱)你道他才出身，便认真，和咱评论，(云)他在你家做了二十年女婿，只是打柴做活，不曾受了一些好处，临了着个妮子大风大雪里勒了休书，赶他出去，你则说波，(唱)这个是谁做的来背槽抛粪？(刘二公云)哎，他如今做了官，便不认的俺家里，眼见的是忘恩背义了也！(张唱)。"]'),
('yuanqu-717','朱太守风雪渔樵记・满庭芳','无名氏','元','元曲','yuanqu','','[]','这的是知恩哎报恩，(旦儿云)他再说些甚么来？(张唱)他着你便别招女婿，再嫁取个郎君。',207,'元曲/yuanqu.json','["这的是知恩哎报恩，(旦儿云)他再说些甚么来？(张唱)他着你便别招女婿，再嫁取个郎君。", "(旦儿云)他再说些甚么来？(张唱)他道你枉则有蛾眉螓首堆鸦鬓，可怎生少喜多嗔。", "道你是个木乳饼钱亲也那口紧，道你是个铁扫帚扫坏他家门。", "(旦儿云)他再说些甚么来？(张唱)他道你便无些儿淹润，又道你不和那六亲，端的是雌太岁，母凶神！(云)误了我买卖也，(摇鼓做走科)(旦儿云)老的，还有甚说话，一发说了罢。", "(张云)他说来，说来！(唱)。"]'),
('yuanqu-718','朱太守风雪渔樵记・耍孩儿','无名氏','元','元曲','yuanqu','','[]','他肩将那柴担担，口不住把书赋温，每日家穿林过涧谁瞅问？他和那青松翠柏为交友，野草闲花作近邻。',114,'元曲/yuanqu.json','["他肩将那柴担担，口不住把书赋温，每日家穿林过涧谁瞅问？他和那青松翠柏为交友，野草闲花作近邻。", "但行处有八个宇相随趁，(刘二公云)是那八个宇？(张唱)是那斧镰绳担、琴剑书文。", "(旦儿云)他如今做了官，比那旧时模样，可是如何？(张唱)。"]'),
('yuanqu-719','朱太守风雪渔樵记・一煞','无名氏','元','元曲','yuanqu','','[]','他如今得了本处官，端的是别换了一个人，那的是貌随福转你可也急难认。',153,'元曲/yuanqu.json','["他如今得了本处官，端的是别换了一个人，那的是貌随福转你可也急难认。", "他往常黄干黑瘦衣衫破，(带云)你觑去波，(唱)到如今白马红缨彩色新。", "一弄儿多豪俊，摆列着骨朵衙仗，水罐银盆。", "(刘二公云)这话不是他说的，都是你说的。", "(旦儿云)说了这一日，都是你这老苘麻嘴，没空生有，说谎吊皮，片口张舌，口困出来的！(张唱)。"]'),
('yuanqu-720','朱太守风雪渔樵记・煞尾','无名氏','元','元曲','yuanqu','','[]','这的是他道来，他道来，可着我转伸，我转伸。',137,'元曲/yuanqu.json','["这的是他道来，他道来，可着我转伸，我转伸。", "(刘二公云)他做了官呵，便把我怎的？(张云)他敢怎的你？(唱)他将你扌朋扒吊栲施呈尽！(旦儿云)呸！我是他的夫人，他敢怎么的我？(张云)误了我买卖！(摇鼓叫科，云)笊篱马杓，破缺也换那！(唱)直将你那索休离的冤仇他待证了本！(下)。"]'),
('yuanqu-721','朱太守风雪渔樵记・川拨棹','无名氏','元','元曲','yuanqu','','[]','我则待打张干，(云)且问那吃打的是谁？(杨孝先云)哥哥，是你兄弟杨孝先。',329,'元曲/yuanqu.json','["我则待打张干，(云)且问那吃打的是谁？(杨孝先云)哥哥，是你兄弟杨孝先。", "(正末唱)原来是同道人杨孝先。", "(孝先做拜、踞倒酒瓶科)(正末回科，云)兄弟免礼！(杨孝先云)哥哥喜得美除！(王安遭云)兄弟你也来了？(正末云)兄弟好么？(杨孝先云)哥哥，您兄弟好。", "(正末唱)俺也曾合火分钱，共起同眠，间别来隔岁经年。", "(云)兄弟也，你如今做甚么营生买卖？(杨孝先云)哥哥，你兄弟依旧打柴哩。", "(正末唱)还靠着打柴薪为过遣，怎这般时命蹇？(刘二公同旦儿上，云)孩儿，俺和你同见朱买臣去来。", "(旦儿云)父亲，我先过去。", "(刘二公云)孩儿你先过去，看他认也不认。", "(旦儿见跪科，云)相公喜得美除，我道你不是个受贫的么！(正末云)俺这朋友饮酒处，张千，谁着你放他这妇人来？打起去！(唱)。"]'),
('yuanqu-722','朱太守风雪渔樵记・七弟兄','无名氏','元','元曲','yuanqu','','[]','这是那一家宅眷？稳便。',73,'元曲/yuanqu.json','["这是那一家宅眷？稳便。", "(王安道云)夫人也，来了也。", "(正末做见、怒科，唱)请起波玉天仙！去年时为甚耽疾怨？觑绝时不由我便怒冲天，今日家咱两个重相见。"]'),
('yuanqu-723','朱太守风雪渔樵记・梅花酒','无名氏','元','元曲','yuanqu','','[]','呀，做多少假腼腆，咱须是夙世姻缘，今世缠绵，可怎生就待不到来年？(旦儿云)相公，旧话休题。',144,'元曲/yuanqu.json','["呀，做多少假腼腆，咱须是夙世姻缘，今世缠绵，可怎生就待不到来年？(旦儿云)相公，旧话休题。", "(正末唱)当初你要休离我便休离，你今日呵要团圆我不团圆。", "(云)刘家女，你不道来那。", "(旦儿云)我道甚么来？(正末唱)你道你正青春正少年，你道你好描条好眉面，善裁剪善针线，无儿女厮牵连，别嫁取个大官员。"]'),
('yuanqu-724','朱太守风雪渔樵记・雁儿落','无名氏','元','元曲','yuanqu','','[]','你这卓王孙呵，怎生便不重贤？(王安道云)他是刘二公，怎做的那卓王孙？(正末云)他既不是卓王孙，(唱)索怎生则搬调的个文君女嫌贫贱？我则问你，逼相如索了休，你当初',138,'元曲/yuanqu.json','["你这卓王孙呵，怎生便不重贤？(王安道云)他是刘二公，怎做的那卓王孙？(正末云)他既不是卓王孙，(唱)索怎生则搬调的个文君女嫌贫贱？我则问你，逼相如索了休，你当初可也对苍天曾罚愿？(云)今日座上的众人，你可认得么？(旦儿云)认的。", "这个是王安道伯伯，这个是杨孝先叔叔。", "(正末唱)。"]'),
('yuanqu-725','朱太守风雪渔樵记・甜水令','无名氏','元','元曲','yuanqu','','[]','折莫你便奔井投河，自推自跌，自埋自怨！(旦儿云)王伯伯，你劝一劝儿波！(正末唱)便央及煞俺也不相怜！折莫便一来一往，一上一下，将咱解劝，总盖不过你这前愆。',77,'元曲/yuanqu.json','["折莫你便奔井投河，自推自跌，自埋自怨！(旦儿云)王伯伯，你劝一劝儿波！(正末唱)便央及煞俺也不相怜！折莫便一来一往，一上一下，将咱解劝，总盖不过你这前愆。"]'),
('yuanqu-726','朱太守风雪渔樵记・折桂令','无名氏','元','元曲','yuanqu','','[]','从来你这打渔人顺水推船，想着那凛冽寒风，大雪漫天。',185,'元曲/yuanqu.json','["从来你这打渔人顺水推船，想着那凛冽寒风，大雪漫天。", "想着我那身上无衣，肚里无食，怀内无钱。", "(云)刘家女，你不道来？(旦儿云)我道甚么来？(正末唱)你怕甚舍不得我那南庄北园，撇不了我那东阁西轩？我如今旱地上也无田，水路里也无船。", "只除这紫绶金章，可不的依还是赤手空拳？(云)刘家女，你欲要我认你也，你将一盆永来。", "(张千云)水在此。", "(王安道云)相公，你只认了夫人罢！(正末唱)。"]'),
('yuanqu-727','朱太守风雪渔樵记・沽美酒','无名氏','元','元曲','yuanqu','','[]','我只道你泼无徒心太偏，元来是姜太公使机变，不钓鱼儿只钓贤。',45,'元曲/yuanqu.json','["我只道你泼无徒心太偏，元来是姜太公使机变，不钓鱼儿只钓贤。", "你可便施恩在我前，暗赍发与盘缠。"]'),
('yuanqu-728','朱太守风雪渔樵记・太平令','无名氏','元','元曲','yuanqu','','[]','从来个打渔人言如钩线，道的我羞答答闭口无言。',73,'元曲/yuanqu.json','["从来个打渔人言如钩线，道的我羞答答闭口无言。", "明明的这关节有何难见，险些把一家儿恩多成怨。", "我如今意转，性转，也是他的运转，呀，不独是为尊兄做些颜面。"]'),
('yuanqu-729','朱太守风雪渔樵记・鸳鸯煞尾','无名氏','元','元曲','yuanqu','','[]','方知是皇明日月光非遍，天恩雨露沾还浅。',223,'元曲/yuanqu.json','["方知是皇明日月光非遍，天恩雨露沾还浅。", "道我禄薄官卑，岁加二千，昔日穷交，都皆赐田。", "便是妻子何缘，早遂了团圆愿。", "倒与他后世流传，道这风雪渔樵也只落的做一场故事儿演。", "(刘二公云)天下喜事，无过夫妇团圆。", "今日既是认了，便当杀羊造酒，做一个庆贺的筵席！(词云)玉天仙容貌多娇媚，恋恩情进取偏无意。", "假乖张故逼写休书，到长安果得登高第。", "除太守即在会稽城，显威风谁不惊回避。", "怀旧恨夫妇两参商，覆盆水险做傍州例。", "若不是严司徒赍敕再重来，怎结末朱买臣风雪渔樵记？。"]'),
('yuanqu-730','越调・斗鹌鹑开筵','童童学士','元','元曲','yuanqu','','[]','鹤背乘风，朝真半空。',48,'元曲/yuanqu.json','["鹤背乘风，朝真半空。", "龟枕生寒，游仙梦中。", "瑞日融和，祥云峙耸。", "赴天阙，游月宫。", "歌舞吹弹，前后簇拥。"]'),
('yuanqu-731','小桃红・筵前谈笑尽喧哄，一派笙箫动。媚景良辰自情重，拚却醉颜红，','童童学士','元','元曲','yuanqu','','[]','一杯未尽笙歌送。',27,'元曲/yuanqu.json','["一杯未尽笙歌送。", "金樽莫侧，玉山低趄，直吃的凉月转梧桐。"]'),
('yuanqu-732','天净沙・碧天边桂魄飞腾，银河外斗柄回东，畅好是更长漏水。梅花三弄，','童童学士','元','元曲','yuanqu','','[]','访危楼十二帘笼。',8,'元曲/yuanqu.json','["访危楼十二帘笼。"]'),
('yuanqu-733','调笑令・玉容，露春葱，翠袖殷勤捧玉钟。绛纱笼烛影摇红，艳歌起韵梁','童童学士','元','元曲','yuanqu','','[]','尘动。',22,'元曲/yuanqu.json','["尘动。", "都吃的开襟堕巾筵宴中，绮罗丛醉眼朦胧。"]'),
('yuanqu-735','双调・新水令念远','童童学士','元','元曲','yuanqu','','[]','烧痕回绿遍天涯，忆王孙去时残腊。',39,'元曲/yuanqu.json','["烧痕回绿遍天涯，忆王孙去时残腊。", "愁垂檐外雨，忧损镜中花。", "掘土抟沙，感事自惊讶。"]');
